const searchBiasCatalog = (query) => {
  if (!query || !query.trim()) return [];
  const q = query.toLowerCase().trim();
  return KPOP_BIAS_CATALOG.filter(e =>
    e.displayName.toLowerCase().includes(q) ||
    e.searchTerms.some(t => t.includes(q))
  ).slice(0, 12);
};

