// ─── AUTH SCREEN ──────────────────────────────────────────────────────────────
// Handles: login, sign-up, and 3-step profile setup after first registration.
// Falls back to mock mode when Supabase is not configured.
function Onboarding({ onDone }) {
  const pendingProfile = normalizeProfile(ls.get("backstage_session")?.user);
  const needsProfileRecovery = Boolean(pendingProfile && !canEnterApp(pendingProfile));
  // Only skip to profile step if user is actually authenticated (session exists).
  // Stale backstage_pending_uid from a previous session must not bypass the welcome screen.
  const hasSession = Boolean(ls.get("backstage_session")?.user?.id);
  const [mode, setMode]     = useState(()=>hasSession && (needsProfileRecovery || ls.get("backstage_pending_uid")) ? "profile" : "landing");    // landing | login | signup | profile | tour
  const [step, setStep]     = useState(1);
  const [email, setEmail]   = useState(pendingProfile?.email || "");
  const [pass, setPass]     = useState("");
  const [data, setData]     = useState({ name:pendingProfile?.handle || "", groups:pendingProfile?.fandoms || [], bias:pendingProfile?.bias || "", biasWrecker:"", ult:"", fanDNA:[], concertCount:"", discoveryPrefs:[], city:pendingProfile?.city || "", cityMeta:null, skippedRequiredProfile:false });
  const [onbCitySuggestions, setOnbCitySuggestions] = useState([]);
  const [search, setSearch] = useState("");
  const [err, setErr]       = useState("");
  const [loading, setLoading] = useState(false);
  const [cooldown, setCooldown] = useState(0); // seconds remaining after rate-limit
  const [unconfirmed, setUnconfirmed] = useState(false); // true when sign-in blocked by unconfirmed email
  const [resendCooldown, setResendCooldown] = useState(0); // seconds remaining after resend attempt
  const [resendSuccess, setResendSuccess] = useState(""); // success message after resend
  const [savedProfile, setSavedProfile] = useState(null);
  const [tourStep, setTourStep] = useState(0);

  // Detect if user came from /capsule QR link — swap to capsule-first copy
  const fromCapsule = !!(ls.get("backstage_capsule_context"));

  const filtered = search
    ? ALL_GROUPS.filter(g => g.toLowerCase().includes(search.toLowerCase()))
    : ALL_GROUPS.slice(0, 16);
  const toggle = g => setData(d => ({ ...d, groups: d.groups.includes(g) ? d.groups.filter(x=>x!==g) : [...d.groups, g] }));

  useEffect(() => {
    if (cooldown <= 0) return;
    const t = setTimeout(() => setCooldown(c => c - 1), 1000);
    return () => clearTimeout(t);
  }, [cooldown]);

  useEffect(() => {
    if (resendCooldown <= 0) return;
    const t = setTimeout(() => setResendCooldown(c => c - 1), 1000);
    return () => clearTimeout(t);
  }, [resendCooldown]);

  // ── SIGN IN ──
  const handleSignIn = async () => {
    if (loading) return;
    if (!email.trim() || !pass) return;
    setLoading(true); setErr(""); setUnconfirmed(false); setResendSuccess("");
    if (MOCK_AUTH) {
      const mockUser = ls.get('backstage_mock_user');
      if (mockUser) { onDone(mockUser); setLoading(false); return; }
      // New mock user
      setMode("profile"); setLoading(false); return;
    }
    try {
      const { data: d, error } = await _supabase.auth.signInWithPassword({ email, password: pass });
      if (error) {
        const msg = error.message || '';
        if (error.status === 429 || msg.toLowerCase().includes('security purposes') || msg.toLowerCase().includes('rate limit') || msg.toLowerCase().includes('too many')) {
          setCooldown(60);
          setErr("Backstage is cooling down sign-in emails. Wait 60 seconds and try once.");
        } else if (msg.toLowerCase().includes('email not confirmed') || msg.toLowerCase().includes('email_not_confirmed')) {
          setUnconfirmed(true);
          setErr("Your email still needs to be confirmed.");
        } else {
          setErr(msg);
        }
        setLoading(false); return;
      }
      // Set token immediately so api.get('/api/users/me') below is authenticated.
      // AuthProvider.onAuthStateChange will also set it, but fires asynchronously.
      if (d.session?.access_token) api._setToken(d.session.access_token);
      // Replay any pending onboarding PATCH — happens when email confirmation was
      // required at signup and the PATCH got 401'd (no session token yet).
      const pendingPatch = ls.get(`backstage_pending_patch_${d.user.id}`);
      if (pendingPatch && d.session?.access_token) {
        try {
          const pr = await fetch(`${API_URL}/api/users/me`, {
            method:'PATCH',
            headers:{ 'Content-Type':'application/json', 'Authorization':`Bearer ${d.session.access_token}` },
            body: JSON.stringify(pendingPatch),
          });
          if (pr.ok) { ls.del(`backstage_pending_patch_${d.user.id}`); console.log('[SignIn] pending onboarding patch replayed'); }
        } catch(e) { console.warn('[SignIn] pending patch replay failed:', e?.message); }
      }
      const profile = await api.get('/api/users/me');
      const fallback = { id:d.user.id, email:d.user.email, username:email.split('@')[0], fandoms:[], bias:'', is_vip:false };
      const u = mergeStoredProfile(ls.get(`backstage_profile_${d.user.id}`), profile?.id ? normalizeProfile({...fallback,...profile}) : null, fallback);
      ls.set('backstage_session', { user: u });
      if (u.id) ls.set(`backstage_profile_${u.id}`, u);
      if (!canEnterApp(u)) {
        ls.set('backstage_pending_uid', d.user.id);
        setData(prev=>({ ...prev, name:u.handle || email.split('@')[0], groups:u.fandoms || [], bias:u.bias || "" }));
        setMode("profile");
        setLoading(false);
        return;
      }
      onDone(u);
    } catch(e) { setErr('Connection error. Try again.'); }
    setLoading(false);
  };

  // ── SIGN UP ──
  const handleSignUp = async () => {
    if (loading) return;
    if (!email.trim() || pass.length < 6) { setErr("Password must be at least 6 characters."); return; }
    setLoading(true); setErr("");
    if (MOCK_AUTH) { setMode("profile"); setLoading(false); return; }
    try {
      const { data: d, error } = await _supabase.auth.signUp({ email, password: pass });
      if (error) {
        const msg = error.message || '';
        if (error.status === 429 || msg.toLowerCase().includes('security purposes') || msg.toLowerCase().includes('rate limit') || msg.toLowerCase().includes('too many')) {
          setCooldown(60);
          setErr("Backstage is cooling down signup emails. Wait 60 seconds and try once.");
        } else {
          setErr(msg);
        }
        setLoading(false);
        return;
      }
      if (d.user) { ls.set('backstage_pending_uid', d.user.id); setMode("profile"); }
    } catch(e) { setErr('Connection error. Try again.'); }
    setLoading(false);
  };

  // ── FORGOT PASSWORD ──
  const handleForgotPassword = async () => {
    if (loading) return;
    if (!email.trim()) { setErr("Enter your email address."); return; }
    setLoading(true); setErr("");
    if (MOCK_AUTH) { setLoading(false); setMode("resetpw_sent"); return; }
    try {
      const { error } = await _supabase.auth.resetPasswordForEmail(email.trim(), {
        redirectTo: window.location.origin,
      });
      if (error) { setErr(error.message); } else { setMode("resetpw_sent"); }
    } catch(e) { setErr('Connection error. Try again.'); }
    setLoading(false);
  };

  // ── RESEND VERIFICATION (for unconfirmed users on sign-in screen) ──
  const handleResendFromSignIn = async () => {
    if (resendCooldown > 0) return;
    setResendSuccess("");
    if (MOCK_AUTH) {
      setErr("");
      setResendSuccess("Confirmation email sent. Check your inbox and spam folder.");
      setResendCooldown(60);
      return;
    }
    try {
      const { error } = await _supabase.auth.resend({ type: 'signup', email: email.trim() });
      if (error) {
        const m = error.message?.toLowerCase() || '';
        if (error.status === 429 || m.includes('too many') || m.includes('rate limit') || m.includes('security purposes')) {
          setErr('Too many attempts. Wait 1 minute and try again.');
          setResendCooldown(60);
        } else {
          setErr(error.message);
        }
      } else {
        setErr("");
        setResendSuccess("Confirmation email sent. Check your inbox and spam folder.");
        setResendCooldown(60);
      }
    } catch(e) { setErr('Connection error. Try again.'); }
  };

  // ── CLEAR STALE SESSION ──
  const clearSession = async () => {
    try { if (_supabase) await _supabase.auth.signOut(); } catch(e) {}
    clearAuthStorage();
    setErr('');
    setEmail('');
    setPass('');
    setMode('landing');
  };

  // ── COMPLETE PROFILE ──
  const handleProfileDone = async () => {
    if (!data.name.trim() || (!data.groups.length && !data.skippedRequiredProfile)) return;
    setLoading(true);
    const uid  = ls.get('backstage_pending_uid') || pendingProfile?.id || `mock_${Date.now()}`;
    // fandoms = canonical selected-groups field. data.groups comes from the
    // fandom picker (step 2 of onboarding). Stored as user.fandoms everywhere.
    // PHASE 2: user.fandoms will personalize GET /api/events (Ticketmaster-backed).
    const locationFields = {};
    if (data.cityMeta) {
      const e = data.cityMeta;
      Object.assign(locationFields, {
        city_display: makeCityFull(e),
        city_key:     makeCityKey(e),
        region:       e.region,
        region_code:  e.region_code,
        country:      e.country,
        country_code: e.country_code,
        continent:    e.continent,
        city_lat:     e.lat,
        city_lng:     e.lng,
        timezone:     e.timezone,
      });
    }

    const profile = normalizeProfile({
      id:uid,
      email,
      username:data.name,
      handle:data.name,
      backstage_name:data.name,
      display_name:data.name,
      fandoms:data.groups,
      favorite_groups:data.groups,
      bias:data.bias,
      bias_wrecker:data.bias_wrecker || "",
      city:data.city,
      ...locationFields,
      show_city:true,
      showCity:true,
      is_vip:false,
      onboarding_skipped:data.skippedRequiredProfile === true,
      onboarding_complete:true,
      profile_complete:true,
    });

    if (!MOCK_AUTH && _supabase) {
      const patchBody = { username:data.name, handle:data.name, backstage_name:data.name, display_name:data.name, fandoms:data.groups, favorite_groups:data.groups, bias:data.bias, bias_wrecker:data.bias_wrecker || "", city:data.city, ...locationFields, show_city:true, onboarding_complete:true, profile_complete:true };
      try {
        const session = await _supabase.auth.getSession();
        const token = session?.data?.session?.access_token;
        const res = await fetch(`${API_URL}/api/users/me`, {
          method:'PATCH',
          headers:{ 'Content-Type':'application/json', 'Authorization':`Bearer ${token||''}` },
          body: JSON.stringify(patchBody),
        });
        if (!res.ok) {
          // No valid session yet (email confirmation pending) — 401 silently discarded
          // by fetch(). Store for replay on the next successful sign-in.
          ls.set(`backstage_pending_patch_${uid}`, patchBody);
          console.warn('[Onboarding] profile PATCH', res.status, '— stored for replay on sign-in');
        } else {
          ls.del(`backstage_pending_patch_${uid}`);
        }
      } catch(e) {
        // Network error — store for replay
        ls.set(`backstage_pending_patch_${uid}`, patchBody);
        console.warn('[Onboarding] profile PATCH skipped (API unavailable):', e?.message);
      }
    }

    try {
      ls.set('backstage_mock_user', profile);
      ls.set('backstage_session', { user: profile });
      if (profile.id) ls.set(`backstage_profile_${profile.id}`, profile);
      markOnboardingComplete(profile);
      ls.del('backstage_pending_uid');
      // Seed rich fan identity from onboarding data
      try {
        ls.set("backstage_fan_identity", { name:data.name, ult:data.ult||"", bias:data.bias, biasWrecker:data.biasWrecker||"", fanDNA:data.fanDNA||[], fandoms:data.groups, concertCount:data.concertCount||"", city:data.city, seededAt:Date.now() });
        if (data.discoveryPrefs?.length) ls.set("backstage_discovery_preferences", data.discoveryPrefs);
        if (data.concertCount && data.concertCount !== "") {
          // concertCount is already stored in backstage_fan_identity above.
          // Ensure concert_resume is initialized as an array (not object) for future show entries.
          const cResume = ls.get("backstage_concert_resume", null);
          if (cResume === null || !Array.isArray(cResume)) ls.set("backstage_concert_resume", []);
        }
      } catch(e) { console.warn("[Onboarding] fan identity seed failed:", e?.message); }
    } catch(e) {
      console.warn('[Onboarding] localStorage write failed:', e?.message);
    }

    setLoading(false);
    setSavedProfile(profile);
    if (ls.get('backstage_tour_shown')) { onDone(profile); return; }
    setTourStep(0);
    setMode("tour");
  };

  // ── LANDING ──
  if (mode === "landing") return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", justifyContent:"center", padding:"32px 24px", background:C.bg, overflowY:"auto" }}>
      <div style={{ animation:"up .45s ease", textAlign:"center" }}>
        {/* Glow backdrop */}
        <div style={{ position:"absolute",top:"20%",left:"50%",transform:"translateX(-50%)",width:280,height:200,borderRadius:"50%",background:`radial-gradient(ellipse,${C.accent}12,transparent 70%)`,pointerEvents:"none" }} />
        {/* Backstage logo */}
        <img
          src="/fanverse-logo.png"
          alt="Backstage"
          style={{ width:120, height:120, objectFit:"contain", marginBottom:16 }}
        />
        <p style={{ fontSize:10, letterSpacing:"0.2em", textTransform:"uppercase", color:C.textMid, marginBottom:12 }}>Fanverse · K-pop Fandom App</p>
        <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:22, letterSpacing:"-0.02em", marginBottom:8, lineHeight:1.2 }}>Welcome to Backstage</p>
        <p style={{ color:C.textMid, fontSize:12.5, lineHeight:1.65, maxWidth:270, margin:"0 auto 6px" }}>Your fandom. Your people. Your memories.</p>
        <p style={{ color:C.textDim, fontSize:12, lineHeight:1.6, maxWidth:260, margin:"0 auto 32px" }}>
          {fromCapsule
            ? <>Your Concert Capsule is waiting.<br/>Join Backstage to save your moment.</>
            : <>Build My Stage, find your circle,<br/>and keep every concert era.</>}
        </p>
        <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
          <Btn onClick={()=>setMode("signup")}>Get started →</Btn>
          <Btn ghost color={C.textMid} onClick={()=>setMode("login")}>I already have an account</Btn>
        </div>
        <p style={{ fontSize:10, color:C.textDim, textAlign:"center", marginTop:14, lineHeight:1.5 }}>Start free. Go VIP when you're ready to unlock your full fan era.</p>
        {MOCK_AUTH && (
          <div style={{ marginTop:18, background:`${C.gold}0a`, border:`1px solid ${C.gold}28`, borderRadius:12, padding:"9px 14px" }}>
            <p style={{ fontSize:10.5, color:C.gold, lineHeight:1.5 }}>✦ No account needed — jump straight in.</p>
            <button onClick={()=>{ setEmail("demo@backstage.app"); setMode("profile"); }} style={{ marginTop:8, background:C.gold, border:"none", borderRadius:8, padding:"6px 14px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11, cursor:"pointer" }}>Enter as Demo Fan →</button>
          </div>
        )}
      </div>
    </div>
  );

  // ── LOGIN / SIGNUP ──
  if (mode === "login" || mode === "signup") return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", justifyContent:"center", padding:"32px 24px", background:C.bg, overflowY:"auto" }}>
      <div style={{ animation:"up .35s ease" }}>
        <button onClick={()=>setMode("landing")} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer",marginBottom:24 }}>←</button>
        <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:28, letterSpacing:"-0.025em", marginBottom:6 }}>
          {mode==="login" ? "Welcome back ✦" : "Create your account"}
        </p>
        <p style={{ color:C.textMid, fontSize:13, marginBottom:28 }}>
          {mode==="login"
            ? "Sign in to your Backstage account."
            : fromCapsule
              ? "Create your profile to add your moment to tonight's capsule."
              : "Join Backstage. Build your fan world."}
        </p>
        {err && <div style={{ background:`${C.rose}12`, border:`1px solid ${C.rose}40`, borderRadius:11, padding:"10px 13px", marginBottom:unconfirmed?6:14, fontSize:12, color:C.rose }}>{err}</div>}
        {mode==="login"&&unconfirmed&&(
          <div style={{ marginBottom:14 }}>
            <button onClick={handleResendFromSignIn} disabled={resendCooldown>0} style={{ background:"none",border:"none",color:C.accent,fontSize:12,cursor:resendCooldown>0?"default":"pointer",textDecoration:"underline",padding:0,opacity:resendCooldown>0?0.5:1 }}>
              {resendCooldown>0?`Resend available in ${resendCooldown}s…`:"Resend confirmation email →"}
            </button>
          </div>
        )}
        {mode==="login"&&resendSuccess&&(
          <div style={{ background:`${C.accent}15`,border:`1px solid ${C.accent}40`,borderRadius:11,padding:"10px 13px",marginBottom:14,fontSize:12,color:C.accent }}>
            {resendSuccess}
          </div>
        )}
        <Input label="Email" value={email} onChange={e=>{setEmail(e.target.value);setErr("");setUnconfirmed(false);setResendSuccess("");}} placeholder="you@example.com" type="email" style={{ marginBottom:12 }} />
        <Input label="Password" value={pass} onChange={e=>{setPass(e.target.value);setErr("");}} placeholder={mode==="signup"?"At least 6 characters":"Your password"} type="password" style={{ marginBottom:mode==="login"?8:20 }} />
        {mode==="login"&&<div style={{ textAlign:"right",marginBottom:14 }}><button onClick={()=>{setErr("");setMode("forgot");}} style={{ background:"none",border:"none",color:C.accent,fontSize:11.5,cursor:"pointer",textDecoration:"underline",padding:0 }}>Forgot password?</button></div>}
        <Btn onClick={mode==="login"?handleSignIn:handleSignUp} disabled={loading||cooldown>0||!email.trim()||!pass}>
          {cooldown>0?`Wait ${cooldown}s…`:loading?"Working...":mode==="login"?"Sign In":"Create Account →"}
        </Btn>
        <div style={{ height:14 }} />
        <Btn ghost color={C.textMid} onClick={()=>{setMode(mode==="login"?"signup":"login");setUnconfirmed(false);setResendSuccess("");}} small>
          {mode==="login"?"Don't have an account? Sign up":"Already have an account? Sign in"}
        </Btn>
        <div style={{ height:20 }} />
        <button onClick={clearSession} style={{ background:"none",border:"none",color:C.textMid,fontSize:11,cursor:"pointer",opacity:0.55,textDecoration:"underline",display:"block",margin:"0 auto" }}>
          Having trouble? Clear session and try again
        </button>
      </div>
    </div>
  );

  // ── FORGOT PASSWORD ──
  if (mode === "forgot") return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",padding:"32px 24px",background:C.bg,overflowY:"auto" }}>
      <div style={{ animation:"up .35s ease" }}>
        <button onClick={()=>{setMode("login");setErr("");}} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer",marginBottom:24 }}>←</button>
        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:28,letterSpacing:"-0.025em",marginBottom:6 }}>Forgot password?</p>
        <p style={{ color:C.textMid,fontSize:13,marginBottom:28 }}>Enter your email and we'll send a reset link.</p>
        {err&&<div style={{ background:`${C.rose}12`,border:`1px solid ${C.rose}40`,borderRadius:11,padding:"10px 13px",marginBottom:14,fontSize:12,color:C.rose }}>{err}</div>}
        <Input label="Email" value={email} onChange={e=>{setEmail(e.target.value);setErr("");}} placeholder="you@example.com" type="email" style={{ marginBottom:20 }} />
        <Btn onClick={handleForgotPassword} disabled={loading||!email.trim()}>
          {loading?"Sending…":"Send Reset Link"}
        </Btn>
      </div>
    </div>
  );

  if (mode === "resetpw_sent") return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",padding:"32px 24px",background:C.bg }}>
      <div style={{ animation:"up .35s ease",textAlign:"center" }}>
        <p style={{ fontSize:40,marginBottom:16 }}>✉️</p>
        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:24,marginBottom:8 }}>Check your email</p>
        <p style={{ color:C.textMid,fontSize:13,lineHeight:1.6,maxWidth:280,margin:"0 auto 28px" }}>
          We sent a password reset link to <strong style={{ color:C.text }}>{email}</strong>. Tap the link to set a new password.
        </p>
        <Btn ghost color={C.textMid} onClick={()=>{setMode("login");setErr("");}}>Back to Sign In</Btn>
      </div>
    </div>
  );

  // ── FEATURE TOUR (4 slides, shown once after profile setup) ──
  if(mode === "tour") {
    const TOUR = [
      {
        emoji:null,
        logo:true,
        title:"The Fanverse",
        body:"Your live fandom community. See what fans worldwide are posting, find fan buddies near your concert, and drop a Backstage Pass.",
        accent: C.accent,
        tag:"Community",
        hint:"Fanverse tab → Feed, Hubs, Nearby",
        sparks:["#d2","#f2","#a8"],
      },
      {
        emoji:"📸",
        title:"Concert Capsule",
        body:"Every fan's view of the same night — one shared archive per show. Fit checks, seat views, freebies, setlist moments.",
        accent: C.lavender,
        tag:"Concerts",
        hint:"Concert Day Mode → Concert Capsule ✦",
        sparks:["#b5","#c8","#9a"],
      },
      {
        emoji:"🎟️",
        title:"Backstage Passes",
        body:"Quick disappearing moments from your fan era. Gone in 24 hours. Not a post — just a Pass. Raw, real, right now.",
        accent: C.pink,
        tag:"Fanverse",
        hint:"Fanverse tab → Backstage Passes",
        sparks:["#e8","#d2","#f0"],
      },
      {
        emoji:"🌙",
        title:"Afterglow",
        body:"The night isn't over when the show ends. Log your concert memory, rate the setlist, and save it forever in your Scrapbook.",
        accent: C.gold,
        tag:"Memory",
        hint:"Home → Afterglow · Library → Scrapbook",
        sparks:["#cc","#aa","#ee"],
      },
    ];
    const slide = TOUR[tourStep];
    const isLast = tourStep === TOUR.length - 1;

    const SPARK_POSITIONS = [
      [{top:"8%",left:"12%",size:14},{top:"14%",left:"78%",size:10},{top:"72%",left:"88%",size:12},{top:"82%",left:"8%",size:9}],
      [{top:"6%",left:"82%",size:12},{top:"78%",left:"14%",size:10},{top:"18%",left:"8%",size:9},{top:"70%",left:"80%",size:14}],
      [{top:"10%",left:"18%",size:11},{top:"76%",left:"76%",size:13},{top:"20%",left:"84%",size:8},{top:"80%",left:"18%",size:11}],
      [{top:"7%",left:"72%",size:13},{top:"75%",left:"10%",size:11},{top:"15%",left:"15%",size:10},{top:"78%",left:"82%",size:9}],
    ];

    return (
      <div style={{ height:"100%",display:"flex",flexDirection:"column",justifyContent:"center",padding:"32px 24px",background:`linear-gradient(160deg,${C.cosmic} 0%,${C.bg} 50%,#0c0820 100%)`,overflowY:"auto",textAlign:"center",position:"relative",overflow:"hidden" }}>

        {/* Ambient radial glow */}
        <div style={{ position:"absolute",top:"18%",left:"50%",transform:"translateX(-50%)",width:340,height:340,borderRadius:"50%",background:`radial-gradient(ellipse,${slide.accent}1c,transparent 68%)`,pointerEvents:"none",transition:"background .6s" }} />
        {/* Bottom glow */}
        <div style={{ position:"absolute",bottom:"-10%",left:"50%",transform:"translateX(-50%)",width:280,height:180,borderRadius:"50%",background:`radial-gradient(ellipse,${slide.accent}10,transparent 70%)`,pointerEvents:"none" }} />

        {/* Floating star sparks */}
        {SPARK_POSITIONS[tourStep].map((sp,i)=>(
          <div key={i} style={{ position:"absolute",top:sp.top,left:sp.left,fontSize:sp.size,color:slide.accent,opacity:0.45,animation:`sparkleFloat ${2.8+i*0.5}s ease-in-out infinite`,animationDelay:`${i*0.4}s`,pointerEvents:"none",transition:"color .6s" }}>✦</div>
        ))}

        <div style={{ animation:"up .4s ease",position:"relative" }}>
          {/* Step counter */}
          <p style={{ fontSize:9,fontFamily:"'Epilogue',sans-serif",fontWeight:700,letterSpacing:"0.18em",color:slide.accent,textTransform:"uppercase",marginBottom:24,opacity:0.8 }}>
            {tourStep+1} of {TOUR.length} — {slide.tag}
          </p>

          {/* Progress dots */}
          <div style={{ display:"flex",gap:7,justifyContent:"center",marginBottom:32 }}>
            {TOUR.map((_,i)=>(
              <div key={i} style={{ height:5,borderRadius:99,width:i===tourStep?28:5,background:i<=tourStep?slide.accent:`${C.border}88`,transition:"all .35s",boxShadow:i===tourStep?`0 0 8px ${slide.accent}66`:"none" }} />
            ))}
          </div>

          {/* Icon with glow ring */}
          <div style={{ position:"relative",display:"inline-block",marginBottom:26 }}>
            <div style={{ position:"absolute",inset:-14,borderRadius:"50%",background:`radial-gradient(circle,${slide.accent}20,transparent 70%)`,pointerEvents:"none" }} />
            <div style={{ width:92,height:92,borderRadius:28,background:slide.logo?"transparent":`linear-gradient(145deg,${slide.accent}22,${slide.accent}0c)`,border:`1.5px solid ${slide.accent}50`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:42,boxShadow:`0 0 48px ${slide.accent}30,0 0 0 1px ${slide.accent}18`,transition:"all .5s",position:"relative",overflow:"hidden" }}>
              {slide.logo
                ? <img src="/fanverse-logo.png" alt="Backstage" style={{ width:"100%",height:"100%",objectFit:"cover",display:"block" }} />
                : slide.emoji}
            </div>
          </div>

          {/* Title */}
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:28,letterSpacing:"-0.03em",marginBottom:13,lineHeight:1.15,background:`linear-gradient(135deg,${C.text} 40%,${slide.accent} 100%)`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",transition:"background .5s" }}>
            {slide.title}
          </p>

          {/* Body */}
          <p style={{ color:C.textMid,fontSize:14,lineHeight:1.8,maxWidth:290,margin:"0 auto 20px",letterSpacing:"0.01em" }}>
            {slide.body}
          </p>

          {/* Where to find it */}
          <div style={{ background:`${slide.accent}0e`,border:`1px solid ${slide.accent}30`,borderRadius:12,padding:"8px 18px",display:"inline-block",marginBottom:38 }}>
            <p style={{ fontSize:10.5,color:slide.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,letterSpacing:"0.02em" }}>📍 {slide.hint}</p>
          </div>

          {/* Buttons */}
          <div style={{ display:"flex",flexDirection:"column",gap:10 }}>
            <button
              onClick={()=>{
                if(isLast){
                  ls.set('backstage_tour_shown', true);
                  setMode("firstaction");
                } else {
                  setTourStep(t=>t+1);
                }
              }}
              className="tap"
              style={{ width:"100%",padding:"15px",borderRadius:16,background:isLast?`linear-gradient(140deg,${C.gold},#d4a820,${C.accent})`:`linear-gradient(140deg,${slide.accent}dd,${slide.accent}88)`,backgroundSize:"200%",border:"none",color:isLast?"#0a0a14":C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:15,cursor:"pointer",letterSpacing:"0.01em",boxShadow:`0 6px 28px ${slide.accent}30`,transition:"box-shadow .3s",animation:isLast?"vipShimmer 3s linear infinite":"none" }}
            >
              {isLast ? "Enter Backstage ✦" : "Next →"}
            </button>
            {!isLast && (
              <button onClick={()=>{ ls.set('backstage_tour_shown', true); setMode("firstaction"); }} style={{ background:"none",border:"none",color:C.textDim,fontSize:12,cursor:"pointer",padding:"8px",fontFamily:"'Instrument Sans',sans-serif" }}>
                Skip intro
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  // ── FIRST ACTION ──
  if (mode === "firstaction") {
    const FA_ACTIONS = [
      { emoji:"🎭", label:"Customize My Stage",  sub:"Make your fan identity shine",           dest:"studio",    color:C.lavender },
      { emoji:"💜", label:"Find my people",       sub:"Meet fans near your next show",          dest:"community", color:C.accent   },
      { emoji:"⭕", label:"Join a Fan Circle",    sub:"Groups for your specific fandom era",    dest:"community", color:C.pink     },
      { emoji:"🏛️", label:"Open My World",       sub:"Collections, capsules and memories",     dest:"collect",   color:C.mint     },
      { emoji:"🎤", label:"Add a concert",        sub:"Log your shows and fan eras",            dest:"myshows",   color:C.gold     },
      { emoji:"📸", label:"Concert Capsule",      sub:"Save tonight's moments forever",         dest:"capsule",   color:C.rose     },
    ];
    const handleFirstAction = (dest) => {
      if (dest === "studio") ls.set("backstage_open_studio", true);
      ls.set("backstage_first_action_done", true);
      onDone(savedProfile || ls.get("backstage_mock_user") || ls.get("backstage_session")?.user);
    };
    const firstName = (data.name || "").split(/[_\-\.]/)[0] || data.name || "fan";
    return (
      <div style={{ height:"100%", display:"flex", flexDirection:"column", background:`linear-gradient(160deg,${C.cosmic} 0%,${C.bg} 55%)`, overflowY:"auto", padding:"32px 24px 28px", position:"relative" }}>
        {/* Ambient glow */}
        <div style={{ position:"absolute",top:0,left:"50%",transform:"translateX(-50%)",width:340,height:240,borderRadius:"50%",background:`radial-gradient(ellipse,${C.accent}12,transparent 65%)`,pointerEvents:"none" }} />
        <div style={{ animation:"up .4s ease", position:"relative" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:25, letterSpacing:"-0.025em", marginBottom:5, lineHeight:1.2 }}>
            You're in{firstName ? `, ${firstName}` : ""}. ✦
          </p>
          <p style={{ color:C.textMid, fontSize:13, lineHeight:1.65, marginBottom:22 }}>
            Where do you want to start?
          </p>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:22 }}>
            {FA_ACTIONS.map((a,i)=>(
              <div key={i} onClick={()=>handleFirstAction(a.dest)} className="tap"
                style={{ background:`${a.color}0c`, border:`1.5px solid ${a.color}28`, borderRadius:16, padding:"14px 12px", cursor:"pointer" }}>
                <div style={{ fontSize:22, marginBottom:7 }}>{a.emoji}</div>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:12, color:a.color, lineHeight:1.25, marginBottom:3 }}>{a.label}</p>
                <p style={{ fontSize:10, color:C.textDim, lineHeight:1.4 }}>{a.sub}</p>
              </div>
            ))}
          </div>
          <button onClick={()=>{ ls.set("backstage_first_action_done",true); onDone(savedProfile || ls.get("backstage_mock_user") || ls.get("backstage_session")?.user); }}
            style={{ background:"none", border:"none", color:C.textDim, fontSize:12, cursor:"pointer", display:"block", margin:"0 auto 14px", fontFamily:"'Instrument Sans',sans-serif", padding:"8px" }}>
            Take me to the home feed →
          </button>
          <p style={{ fontSize:10, color:C.textDim, textAlign:"center", lineHeight:1.55 }}>
            Start free. Go VIP when you're ready to unlock your full fan era.
          </p>
        </div>
      </div>
    );
  }

  // ── PROFILE SETUP (6-step) ──
  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", justifyContent:"center", padding:"32px 24px", background:C.bg, overflowY:"auto" }}>
      <div style={{ display:"flex", gap:5, justifyContent:"center", marginBottom:28 }}>
        {[1,2,3,4,5,6].map(i=>(
          <div key={i} style={{ height:3, borderRadius:99, width:i===step?24:i<step?16:5, background:i<=step?C.accent:C.border, transition:"all .3s" }} />
        ))}
      </div>
      {step===1 && (
        <div style={{ animation:"up .35s ease" }}>
          {fromCapsule && (
            <div style={{ background:`${C.berry}14`,border:`1px solid ${C.berry}30`,borderRadius:12,padding:"9px 13px",marginBottom:18,display:"flex",alignItems:"center",gap:8 }}>
              <span style={{ fontSize:14 }}>📸</span>
              <p style={{ fontSize:11.5,color:C.lavender,lineHeight:1.5 }}>Almost there — your name will appear on your capsule moment.</p>
            </div>
          )}
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, marginBottom:6 }}>What's your stan name?</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:22 }}>{fromCapsule?"This is how you'll show up in the capsule.":"Your identity in the fanverse. Make it iconic."}</p>
          <Input value={data.name} onChange={e=>setData({...data,name:e.target.value})} placeholder="e.g. stayforever_mia" autoFocus style={{ marginBottom:isReservedUsername(data.name)?8:20 }} />
          {isReservedUsername(data.name) && (
            <p style={{ fontSize:11.5,color:C.rose,marginBottom:18,lineHeight:1.55 }}>
              That name is reserved for official use. Try adding your own twist, like a number, era, or fan tag.
            </p>
          )}
          <Btn onClick={()=>data.name.trim()&&!isReservedUsername(data.name)&&setStep(2)} disabled={!data.name.trim()||isReservedUsername(data.name)}>Continue →</Btn>
        </div>
      )}
      {step===2 && (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, marginBottom:6 }}>Which fandoms are you in?</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:16 }}>Select all that apply. No judgment for multi-fans.</p>
          <Input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search group..." style={{ marginBottom:14 }} />
          <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginBottom:16, maxHeight:220, overflowY:"auto" }}>
            {filtered.map(g=>(
              <span key={g} onClick={()=>toggle(g)} className="tap" style={{ padding:"7px 14px", borderRadius:99, fontSize:12, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer", background:data.groups.includes(g)?C.accent:C.surfaceHi, color:data.groups.includes(g)?C.bg:C.text, border:`1.5px solid ${data.groups.includes(g)?C.accent:C.border}`, transition:"all .18s" }}>{g}</span>
            ))}
          </div>
          {data.groups.length>0&&(
            <>
              <p style={{ fontSize:11, color:C.accentDim, marginBottom:10 }}>{data.groups.length} selected</p>
              <p style={{ fontSize:11.5, color:C.textMid, marginBottom:8 }}>Your ULT group <span style={{ color:C.textDim }}>— optional</span></p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:7, marginBottom:14 }}>
                {data.groups.map(g=>(
                  <span key={g} onClick={()=>setData(d=>({...d, ult:d.ult===g?"":g}))} className="tap"
                    style={{ padding:"6px 12px", borderRadius:99, fontSize:11.5, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer",
                      background:data.ult===g?C.gold:`${C.gold}12`, color:data.ult===g?C.bg:C.gold,
                      border:`1.5px solid ${data.ult===g?C.gold:`${C.gold}30`}`, transition:"all .18s" }}>
                    {data.ult===g?"★ ":""}{g}
                  </span>
                ))}
              </div>
            </>
          )}
          <Btn onClick={()=>data.groups.length&&setStep(3)} disabled={!data.groups.length}>Continue →</Btn>
          <div style={{ height:10 }} />
          <Btn ghost color={C.textMid} onClick={()=>{ setData(d=>({...d, skippedRequiredProfile:true})); setStep(3); }} small>Skip for now</Btn>
        </div>
      )}
      {step===3 && (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, marginBottom:6 }}>Who's your bias?</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:22 }}>Just one. We know how hard that is.</p>
          <Input value={data.bias} onChange={e=>setData({...data,bias:e.target.value})} placeholder="e.g. Felix, Jimin, Karina..." autoFocus style={{ marginBottom:16 }} />
          <p style={{ fontSize:11.5, color:C.textMid, marginBottom:8 }}>Bias wrecker <span style={{ color:C.textDim }}>— optional</span></p>
          <Input value={data.biasWrecker} onChange={e=>setData({...data,biasWrecker:e.target.value})} placeholder="The one who keeps threatening your bias..." style={{ marginBottom:22 }} />
          <Btn onClick={()=>setStep(4)}>Continue →</Btn>
          <div style={{ height:10 }} />
          <Btn ghost color={C.textMid} onClick={()=>setStep(4)} small>Skip</Btn>
        </div>
      )}
      {step===4 && (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, marginBottom:6 }}>Your Fan DNA</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:18 }}>Pick what vibes with you. This shapes your Fanverse experience.</p>
          <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginBottom:16, maxHeight:200, overflowY:"auto" }}>
            {["Concert goer 🎤","Merch collector 🃏","Photo fan 📸","Setlist nerd 📋","Multi-fandom 💫","ULT stan 💜","Fan art lover 🎨","Cosplay / fits 🎭","Solo stan 🌟","Fandom OG 📅","Stream warrior 🎵","Light stick army 💡","Concert buddies 👯","K-drama fan 📺"].map(dna=>(
              <span key={dna} onClick={()=>setData(d=>({ ...d, fanDNA:d.fanDNA.includes(dna)?d.fanDNA.filter(x=>x!==dna):[...d.fanDNA,dna] }))}
                className="tap"
                style={{ padding:"7px 13px", borderRadius:99, fontSize:11.5, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer",
                  background:data.fanDNA.includes(dna)?C.pink:`${C.pink}10`,
                  color:data.fanDNA.includes(dna)?C.bg:C.text,
                  border:`1.5px solid ${data.fanDNA.includes(dna)?C.pink:C.border}`, transition:"all .18s" }}>
                {dna}
              </span>
            ))}
          </div>
          {data.fanDNA.length>0&&<p style={{ fontSize:11, color:C.pink, marginBottom:10 }}>{data.fanDNA.length} picked</p>}
          <Btn onClick={()=>setStep(5)}>Continue →</Btn>
          <div style={{ height:10 }} />
          <Btn ghost color={C.textMid} onClick={()=>setStep(5)} small>Skip</Btn>
        </div>
      )}
      {step===5 && (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, marginBottom:6 }}>Your concert life</p>
          <p style={{ color:C.textMid, fontSize:13, marginBottom:20 }}>How many K-pop concerts have you been to?</p>
          <div style={{ display:"flex", flexWrap:"wrap", gap:8, marginBottom:22 }}>
            {[["0","First one coming 🌱"],["1-3","Just getting started ✦"],["4-10","Era regular 🎤"],["11-20","Concert veteran 🎟️"],["20+","Hall of fame 💜"]].map(([val,label])=>(
              <div key={val} onClick={()=>setData(d=>({...d,concertCount:val}))}
                className="tap"
                style={{ flex:"1 1 calc(50% - 4px)", background:data.concertCount===val?C.accent:`${C.accent}0c`,
                  border:`1.5px solid ${data.concertCount===val?C.accent:`${C.accent}28`}`,
                  borderRadius:13, padding:"12px 14px", cursor:"pointer", transition:"all .18s" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:12, color:data.concertCount===val?C.bg:C.accent, lineHeight:1.3 }}>{label}</p>
                <p style={{ fontSize:10, color:data.concertCount===val?"rgba(10,10,20,0.65)":C.textDim, marginTop:3 }}>{val} concerts</p>
              </div>
            ))}
          </div>
          <Btn onClick={()=>setStep(6)}>Continue →</Btn>
          <div style={{ height:10 }} />
          <Btn ghost color={C.textMid} onClick={()=>setStep(6)} small>Skip</Btn>
        </div>
      )}
      {step===6 && (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:23, marginBottom:5 }}>Your region + vibe</p>
          <p style={{ fontSize:10.5, color:C.textDim, marginBottom:14, lineHeight:1.55 }}>Approx city/region helps fans find their people. You can hide it anytime.</p>
          <div style={{ position:"relative", marginBottom:16 }}>
            <input
              value={data.city}
              onChange={e=>{ const v=e.target.value; setData(d=>({...d,city:v,cityMeta:null})); if(v.length>=2){const q=v.toLowerCase();setOnbCitySuggestions(CITY_LIST.filter(c=>c.city.toLowerCase().includes(q)||makeCityDisplay(c).toLowerCase().includes(q)||c.country.toLowerCase().includes(q)).slice(0,6));}else{setOnbCitySuggestions([]);} }}
              onKeyDown={e=>{ if(e.key==="Escape"||e.key==="Enter") setOnbCitySuggestions([]); }}
              placeholder="e.g. Dallas, TX — approximate is fine"
              style={{ width:"100%", padding:"11px 14px", borderRadius:11, background:C.surfaceHi, border:`1.5px solid ${C.border}`, color:C.text, fontSize:13, boxSizing:"border-box" }}
            />
            {onbCitySuggestions.length > 0 && (
              <div style={{ position:"absolute",top:"100%",left:0,right:0,background:C.surface,border:`1px solid ${C.border}`,borderRadius:10,zIndex:200,overflow:"hidden",marginTop:3 }}>
                {onbCitySuggestions.map((c,i)=>(
                  <div key={i} onMouseDown={()=>{ const display=makeCityDisplay(c); setData(d=>({...d,city:display,cityMeta:c})); setOnbCitySuggestions([]); }}
                    style={{ padding:"9px 14px",cursor:"pointer",fontSize:13,display:"flex",justifyContent:"space-between",alignItems:"center",borderBottom:i<onbCitySuggestions.length-1?`1px solid ${C.border}`:"none" }}
                    onMouseEnter={e=>e.currentTarget.style.background=C.surfaceMid}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <span style={{ color:C.text,fontWeight:600 }}>{c.city}</span>
                    <span style={{ color:C.textDim,fontSize:11 }}>{c.region_code?`${c.region_code} · ${c.country}`:c.country}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
          <p style={{ fontSize:11.5, color:C.textMid, marginBottom:10 }}>What are you looking for? <span style={{ color:C.textDim }}>— pick any</span></p>
          <div style={{ display:"flex", flexWrap:"wrap", gap:7, marginBottom:22 }}>
            {["Concert buddies 🎤","Local fans 📍","Fan Circles 💜","Trades 🃏","Freebies 🎁","Travel buddies ✈️","Outfit inspo 🎭","Capsule memories 📸"].map(pref=>(
              <span key={pref} onClick={()=>setData(d=>({ ...d, discoveryPrefs:d.discoveryPrefs.includes(pref)?d.discoveryPrefs.filter(x=>x!==pref):[...d.discoveryPrefs,pref] }))}
                className="tap"
                style={{ padding:"6px 12px", borderRadius:99, fontSize:11, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer",
                  background:data.discoveryPrefs.includes(pref)?C.lavender:`${C.lavender}10`,
                  color:data.discoveryPrefs.includes(pref)?C.bg:C.text,
                  border:`1.5px solid ${data.discoveryPrefs.includes(pref)?C.lavender:C.border}`, transition:"all .18s" }}>
                {pref}
              </span>
            ))}
          </div>
          <Btn onClick={handleProfileDone} disabled={loading}>
            {loading?"Setting up…":"Enter Backstage ✦"}
          </Btn>
        </div>
      )}
    </div>
  );

}


// ─── SET NEW PASSWORD (password reset callback) ────────────────────────────────
function SetNewPasswordScreen() {
  const { setPasswordRecovery } = useAuth();
  const [newPass, setNewPass]         = useState("");
  const [confirm, setConfirm]         = useState("");
  const [loading, setLoading]         = useState(false);
  const [err, setErr]                 = useState("");
  const [done, setDone]               = useState(false);

  const handleSubmit = async () => {
    if (loading) return;
    if (newPass.length < 6) { setErr("Password must be at least 6 characters."); return; }
    if (newPass !== confirm) { setErr("Passwords don't match."); return; }
    setLoading(true); setErr("");
    if (MOCK_AUTH) { setDone(true); setLoading(false); return; }
    try {
      const { error } = await _supabase.auth.updateUser({ password: newPass });
      if (error) { setErr(error.message); setLoading(false); }
      else { setDone(true); setLoading(false); }
    } catch(e) { setErr("Connection error. Try again."); setLoading(false); }
  };

  return (
    <div style={{ position:"fixed",inset:0,zIndex:9999,background:`linear-gradient(160deg,${C.cosmic},${C.bg})`,display:"flex",flexDirection:"column",justifyContent:"center",padding:"32px 24px" }}>
      {!done ? (
        <div style={{ animation:"up .35s ease" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:28,letterSpacing:"-0.025em",marginBottom:6 }}>Set new password</p>
          <p style={{ color:C.textMid,fontSize:13,marginBottom:28 }}>Choose a strong password for your Backstage account.</p>
          {err&&<div style={{ background:`${C.rose}12`,border:`1px solid ${C.rose}40`,borderRadius:11,padding:"10px 13px",marginBottom:14,fontSize:12,color:C.rose }}>{err}</div>}
          <Input label="New Password" value={newPass} onChange={e=>{setNewPass(e.target.value);setErr("");}} placeholder="At least 6 characters" type="password" style={{ marginBottom:12 }} />
          <Input label="Confirm Password" value={confirm} onChange={e=>{setConfirm(e.target.value);setErr("");}} placeholder="Repeat password" type="password" style={{ marginBottom:20 }} />
          <Btn onClick={handleSubmit} disabled={loading||!newPass||!confirm}>
            {loading?"Saving…":"Save New Password"}
          </Btn>
        </div>
      ) : (
        <div style={{ animation:"up .35s ease",textAlign:"center" }}>
          <p style={{ fontSize:40,marginBottom:16 }}>✓</p>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:24,marginBottom:8 }}>Password updated!</p>
          <p style={{ color:C.textMid,fontSize:13,lineHeight:1.6,maxWidth:280,margin:"0 auto 28px" }}>Your new password is set. You're good to go.</p>
          <Btn onClick={()=>setPasswordRecovery(false)}>Continue to Backstage →</Btn>
        </div>
      )}
    </div>
  );
}

// ─── CONCERTS ─────────────────────────────────────────────────────────────────
function ConcertsPage({ go, isVip, onUpgrade, user }) {
  const [view, setView] = useState(()=>{ const v=ls.get("backstage_concerts_view","shows"); ls.del("backstage_concerts_view"); return v; });
  const [going, setGoing] = useState(()=>ls.get("backstage_going",{}));
  const [selected, setSelected] = useState(null);
  const [rsvped, setRsvped] = useState(()=>ls.get("backstage_rsvped",{}));
  const setGoingPersisted   = (fn) => setGoing(prev=>{ const next=typeof fn==="function"?fn(prev):fn; ls.set("backstage_going",next); return next; });
  const setRsvpedPersisted  = (fn) => setRsvped(prev=>{ const next=typeof fn==="function"?fn(prev):fn; ls.set("backstage_rsvped",next); return next; });

  // Live events from backend — useEvents handles mock flag + data state labeling
  const userGroups = user?.fandoms || user?.favorite_groups || [];
  const { events: liveEvents, dataState: eventsState } = useEvents({ groups: userGroups });

  // Normalize API events to MOCK_CONCERTS shape, skip IDs already in MOCK_CONCERTS
  const existingIds   = new Set(MOCK_CONCERTS.map(c => c.id));
  const apiConcerts   = liveEvents
    .filter(e => !existingIds.has(e.id))
    .map(e => ({
      id:                 e.id,
      name:               e.name || e.title,
      city:               e.city,
      date:               e.date,
      venue:              e.venue,
      group:              e.group_name || e.group,
      color:              C.accent,
      attendees:          e.going || null,
      ticket_url:         e.ticket_url || e.url || null,
      image_url:          e.image_url   || null,
      verificationStatus: e.verificationStatus || (eventsState === 'real' ? 'confirmed' : 'preview'),
      sourceType:         e.source || 'ticketmaster',
      sourceName:         e.source === 'ticketmaster' ? 'Ticketmaster' : 'Backstage',
      sourceUrl:          e.ticket_url || e.url || null,
    }));

  if (selected) return <ShowDetail concert={selected} onBack={()=>setSelected(null)} going={going} setGoing={setGoingPersisted} go={go} isVip={isVip} onUpgrade={onUpgrade} rsvped={rsvped} setRsvped={setRsvpedPersisted} />;

  const views = [["shows","Shows"],["meetups","Meetups"],["parties","After Parties"],["fans","Find Fans"]];

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      {/* ── HEADER — title + disclaimer + tabs ── */}
      <div style={{ padding:"16px 20px 0", flexShrink:0, background:`linear-gradient(180deg,${C.bg} 85%,transparent)` }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:6 }}>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:22, letterSpacing:"-0.02em" }}>Concerts</h2>
          {/* Data state badge — honest about source */}
          {eventsState === 'real'    && <span style={{ fontSize:8, color:C.mint, fontFamily:"'Epilogue',sans-serif", fontWeight:700, letterSpacing:"0.1em" }}>● SYNCED</span>}
          {eventsState === 'preview' && <StatusChip label="PREVIEW" style={{ fontSize:8 }} />}
          {eventsState === 'loading' && <span style={{ fontSize:8, color:C.textDim }}>Loading…</span>}
        </div>
        <p style={{ fontSize:10, color:C.textMid, marginBottom:14, lineHeight:1.55 }}>
          {eventsState === 'real'
            ? 'Live events from official ticketing sources.'
            : eventsState === 'empty'
              ? 'No upcoming shows found for your groups yet.'
              : <>Confirmed events are from official sources.{" "}<span style={{ color:C.textDim }}>Preview cards are sample data.</span></>
          }
        </p>
        {/* Tab row — paddingRight so last tab doesn't clip at edge */}
        <div style={{ display:"flex", gap:7, overflowX:"auto", paddingBottom:12, paddingRight:20, scrollbarWidth:"none", WebkitOverflowScrolling:"touch" }}>
          {views.map(([id,label])=>(
            <span key={id} onClick={()=>setView(id)} className="tap" style={{ flexShrink:0, padding:"8px 16px", borderRadius:99, fontSize:11, fontFamily:"'Epilogue',sans-serif", fontWeight:700, cursor:"pointer", background:view===id?`linear-gradient(140deg,${C.accent}cc,${C.accentDim})`:C.surfaceHi, color:view===id?C.bg:C.textMid, border:`1px solid ${view===id?C.accent:C.border}`, boxShadow:view===id?`0 4px 14px ${C.accent}28`:"none" }}>{label}</span>
          ))}
        </div>
      </div>

      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {view==="shows" && (
          <div style={{ display:"flex", flexDirection:"column", gap:14, paddingTop:4 }}>
            {[...MOCK_CONCERTS, ...apiConcerts].map((c,idx)=>{
              const isConfirmed = c.verificationStatus === "confirmed" || c.verificationStatus === "official";
              const isPreview   = c.verificationStatus === "preview";
              const daysLeft    = computeDaysLeft(c.dates ? c.dates[0]+', 2026' : c.date);
              const chipLabel   = isConfirmed ? "CONFIRMED" : "PREVIEW";
              const hasStats    = c.attendees != null;
              const ticketUrl   = c.sourceUrl || `https://seatgeek.com/search?q=${encodeURIComponent(c.name)}#filters`;
              return (
              <div key={c.id} onClick={()=>setSelected(c)} className="tap card-lift" style={{
                ...VS.glowCard(c.color),
                padding:"18px 16px",
                cursor:"pointer",
                opacity: isPreview ? 0.88 : 1,  // preview cards slightly dimmed
                boxShadow: isConfirmed
                  ? `0 12px 44px ${c.color}28, 0 0 0 1px ${c.color}30`
                  : `0 4px 18px ${c.color}0a`,
                border: isConfirmed
                  ? `1.5px solid ${c.color}55`
                  : `1px solid ${c.color}22`,
              }}>
                <div style={VS.shimmerLine(isConfirmed ? c.color : C.border)} />
                <div style={{ position:"absolute",top:-20,right:-20,width:130,height:130,borderRadius:"50%",background:`radial-gradient(circle,${c.color}${isConfirmed?"22":"12"},transparent 65%)`,pointerEvents:"none" }} />
                <div style={{ position:"relative" }}>

                  {/* ── Top badge row ── */}
                  <div style={{ display:"flex",alignItems:"center",gap:6,marginBottom:10,flexWrap:"wrap" }}>
                    <Pill color={c.color} active small>{c.group}</Pill>
                    <StatusChip label={chipLabel} />
                    {/* Source attribution — readable, not hidden */}
                    {isConfirmed && c.sourceName && (
                      <span style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>via {c.sourceName}</span>
                    )}
                    {/* Featured badge pushed to the right for confirmed top card */}
                    {isConfirmed && idx===0 && (
                      <div style={{ marginLeft:"auto",display:"inline-flex",alignItems:"center",gap:5,background:`${c.color}18`,border:`1px solid ${c.color}40`,borderRadius:99,padding:"3px 10px" }}>
                        <div style={{ width:5,height:5,borderRadius:"50%",background:c.color,animation:"pulse 1.3s ease infinite" }} />
                        <p style={{ fontSize:9,color:c.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em" }}>Featured</p>
                      </div>
                    )}
                  </div>

                  {/* ── Name / venue / date + day counter ── */}
                  <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12 }}>
                    <div style={{ flex:1,minWidth:0,paddingRight:10 }}>
                      <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:isConfirmed?18:16, marginBottom:4, letterSpacing:"-0.01em", lineHeight:1.2 }}>{c.name}</p>
                      <p style={{ fontSize:11, color:C.textMid, marginBottom:2 }}>📍 {c.city} · {c.venue}</p>
                      <p style={{ fontSize:11, color:C.textMid }}>{isConfirmed?"🗓️":"📅"} {c.date}</p>
                    </div>

                    {/* Day counter — confirmed: real number | preview: "SAMPLE" badge */}
                    {isConfirmed ? (
                      <div style={{ textAlign:"center",background:`${c.color}14`,border:`1.5px solid ${c.color}33`,borderRadius:14,padding:"10px 14px",flexShrink:0,minWidth:56 }}>
                        {daysLeft != null ? (<>
                          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:24,color:c.color,lineHeight:1 }}>{daysLeft}</p>
                          <p style={{ fontSize:8.5,color:C.textMid,marginTop:2 }}>days</p>
                        </>) : (
                          <p style={{ fontSize:8.5,color:C.textMid,fontStyle:"italic" }}>TBD</p>
                        )}
                        {going[c.id]&&<Pill color={C.mint} active xs style={{ marginTop:6 }}>✓ Going</Pill>}
                      </div>
                    ) : (
                      /* Preview cards: no days counter — show SAMPLE label instead */
                      <div style={{ textAlign:"center",background:C.surfaceHi,border:`1px solid ${C.border}`,borderRadius:14,padding:"8px 12px",flexShrink:0 }}>
                        <p style={{ fontSize:8,color:C.textDim,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.06em" }}>SAMPLE</p>
                      </div>
                    )}
                  </div>

                  {/* ── Stats / call-to-join row ── */}
                  {isConfirmed ? (
                    /* Confirmed: no fake stats — show Circle CTA */
                    <div style={{ padding:"10px 0",borderTop:`1px solid ${c.color}18`,borderBottom:`1px solid ${c.color}18`,marginBottom:14 }}>
                      <p style={{ fontSize:10.5,color:C.textMid }}>💜 Find your Circle — connect with fans going to this show</p>
                    </div>
                  ) : hasStats ? (
                    /* Preview: stats labelled as sample */
                    <div style={{ borderTop:`1px solid ${C.border}`,borderBottom:`1px solid ${C.border}`,marginBottom:14,paddingTop:10,paddingBottom:8 }}>
                      <p style={{ fontSize:8.5,color:C.textDim,fontStyle:"italic",marginBottom:8 }}>Sample stats shown for layout preview</p>
                      <div style={{ display:"flex",gap:14 }}>
                        {[["👥",c.attendees,"going"],["🤝",c.buddies,"buddy"],["✈️",c.traveling,"traveling"]].map(([icon,count,label])=>(
                          <div key={label} style={{ textAlign:"center",flex:1 }}>
                            <p style={{ fontSize:14,marginBottom:2 }}>{icon}</p>
                            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:14,color:C.textMid }}>{count}</p>
                            <p style={{ fontSize:9,color:C.textDim }}>{label}</p>
                          </div>
                        ))}
                      </div>
                    </div>
                  ) : null}

                  {/* ── CTAs ── confirmed: I'm Going | preview: View Sample */}
                  {isConfirmed ? (
                    <div style={{ display:"flex",gap:8 }}>
                      <button onClick={e=>{e.stopPropagation();setGoing(g=>({...g,[c.id]:!g[c.id]}));}} className="tap" style={{ flex:1,padding:"11px",borderRadius:14,background:going[c.id]?`${C.mint}18`:`linear-gradient(140deg,${c.color}ee,${c.color}88)`,border:going[c.id]?`1.5px solid ${C.mint}`:"none",color:going[c.id]?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:12,cursor:"pointer",boxShadow:going[c.id]?"none":`0 4px 14px ${c.color}30` }}>
                        {going[c.id]?"✓ I'm Going!":"I'm Going"}
                      </button>
                      <button onClick={e=>{e.stopPropagation();setSelected(c);}} className="tap" style={{ flex:1,padding:"11px",borderRadius:14,background:"transparent",border:`1.5px solid ${c.color}44`,color:c.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}>Details →</button>
                      <button onClick={e=>{e.stopPropagation();window.open(ticketUrl,"_blank");}} className="tap" style={{ padding:"11px 12px",borderRadius:14,background:"transparent",border:`1.5px solid ${C.gold}44`,color:C.gold,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}>🎟️</button>
                    </div>
                  ) : (
                    /* Preview: single ghost CTA — no "I'm Going" to avoid false commitment */
                    <div style={{ display:"flex",gap:8 }}>
                      <button onClick={e=>{e.stopPropagation();setSelected(c);}} className="tap" style={{ flex:1,padding:"11px",borderRadius:14,background:"transparent",border:`1px solid ${C.border}`,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12,cursor:"pointer" }}>View Sample →</button>
                    </div>
                  )}
                </div>
              </div>
              );
            })}
          </div>
        )}
        {view==="meetups" && (
          <div style={{ paddingTop:4 }}>
            {/* My RSVPs — only shown when user has confirmed RSVPs */}
            {Object.keys(rsvped).filter(id=>rsvped[id]).length > 0 && (
              <div style={{ marginBottom:18 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:13, marginBottom:10, color:C.accent }}>✓ My RSVPs</p>
                {MOCK_MEETUPS.filter(m=>rsvped[m.id]).map(m=>(
                  <div key={m.id} style={{ background:`${m.color}10`, border:`1.5px solid ${m.color}55`, borderRadius:14, padding:12, marginBottom:8, display:"flex", gap:10, alignItems:"center" }}>
                    <span style={{ fontSize:20 }}>{m.type==="cupsleeve"?"🧋":m.type==="freebie"?"🎁":m.type==="trade"?"🃏":m.type==="afterparty"?"🎉":"📍"}</span>
                    <div style={{ flex:1 }}>
                      <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:12.5 }}>{m.title}</p>
                      <p style={{ fontSize:10, color:C.textMid }}>{m.date} · {m.time} · {m.place}</p>
                    </div>
                    <button onClick={()=>setRsvpedPersisted(r=>({...r,[m.id]:false}))} style={{ background:"none", border:`1px solid ${C.border}`, borderRadius:8, padding:"4px 10px", color:C.textMid, fontSize:10, cursor:"pointer" }}>Cancel</button>
                  </div>
                ))}
              </div>
            )}

            {/* Host CTA */}
            <Card style={{ background:`${C.accent}0a`, border:`1px solid ${C.accent}22`, marginBottom:14 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13, marginBottom:4 }}>Host a meetup</p>
              <p style={{ fontSize:11.5, color:C.textMid, marginBottom:12 }}>Create a pre-show meetup, cup sleeve event, trading session, or after party.</p>
              <Btn small>+ Create Meetup</Btn>
            </Card>

            {/* Upcoming fan events */}
            <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:13, marginBottom:10, color:C.text }}>Upcoming Fan Events</p>
            {MOCK_MEETUPS.filter(m=>m.type!=="afterparty").map(m=>(
              <div key={m.id} style={{ background:C.surface, border:`1.5px solid ${rsvped[m.id]?m.color:C.border}`, borderRadius:18, padding:14, marginBottom:10 }}>
                <div style={{ display:"flex", gap:10, alignItems:"center" }}>
                  <span style={{ fontSize:24 }}>{m.type==="cupsleeve"?"🧋":m.type==="freebie"?"🎁":m.type==="trade"?"🃏":"📍"}</span>
                  <div style={{ flex:1 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13.5 }}>{m.title}</p>
                    <p style={{ fontSize:10.5, color:C.textMid }}>{m.date} · {m.time} · {m.place}</p>
                    {m.city&&<p style={{ fontSize:10, color:C.textDim, marginTop:2 }}>📍 {m.city}</p>}
                  </div>
                  <Pill color={m.color} small style={{ cursor:"pointer" }} onClick={()=>setRsvpedPersisted(r=>({...r,[m.id]:!r[m.id]}))}>
                    {rsvped[m.id]?"✓ Going":"RSVP"}
                  </Pill>
                </div>
                {m.organizer&&<p style={{ fontSize:10, color:C.textDim, marginTop:6, paddingLeft:34 }}>👤 {m.organizer} · {m.rsvps} going</p>}
              </div>
            ))}
          </div>
        )}
        {view==="parties" && (
          <div style={{ paddingTop:4 }}>
            <p style={{ fontSize:12, color:C.textMid, marginBottom:14 }}>K-pop after parties near upcoming shows. Age restrictions enforced by venues.</p>
            {MOCK_MEETUPS.filter(m=>m.type==="afterparty").map(m=>(
              <div key={m.id} style={{ background:`linear-gradient(140deg,${m.color}18,${m.color}06)`, border:`2px solid ${m.color}44`, borderRadius:20, padding:18, marginBottom:14 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12 }}>
                  <div><Pill color={m.color} active small>🎉 After Party</Pill>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:17, marginTop:8 }}>{m.title}</p>
                    <p style={{ fontSize:11, color:C.textMid }}>{m.date} · {m.time} · {m.place}</p>
                  </div>
                  {m.rsvps>50&&<div style={{ background:`${C.gold}18`, border:`1px solid ${C.gold}44`, borderRadius:12, padding:"8px 12px", textAlign:"center" }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:18, color:C.gold }}>{m.rsvps}</p>
                    <p style={{ fontSize:8, color:C.textMid }}>going</p>
                  </div>}
                </div>
                <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:14 }}>
                  {m.vibe&&<Pill color={C.silver} small>Vibe: {m.vibe}</Pill>}
                  {m.ageLimit&&<Pill color={C.gold} small>{m.ageLimit}</Pill>}
                  {m.entry&&<Pill color={C.mint} small>Entry: {m.entry}</Pill>}
                  {m.music&&<Pill color={m.color} small>{m.music}</Pill>}
                </div>
                <Btn color={m.color} small onClick={()=>setRsvpedPersisted(r=>({...r,[m.id]:!r[m.id]}))}>
                  {rsvped[m.id]?"✓ You're Going!":"RSVP →"}
                </Btn>
              </div>
            ))}
          </div>
        )}
        {view==="fans" && <FanBuddyMatcher go={go} />}
      </Screen>
    </div>
  );
}

function AiItinerary({ concert }) {
  const parseHour = (timeStr) => {
    if (!timeStr) return 19.5;
    const [time, period] = timeStr.split(" ");
    let [h, m] = time.split(":").map(Number);
    if (period === "PM" && h !== 12) h += 12;
    if (period === "AM" && h === 12) h = 0;
    return h + (m || 0) / 60;
  };

  const showHour = parseHour(concert.showTime);
  const doorsHour = parseHour(concert.doorsOpen);
  const fmt = (h) => {
    const period = h >= 12 ? "PM" : "AM";
    const hour = Math.floor(h % 12) || 12;
    const min = Math.round((h % 1) * 60);
    return `${hour}:${min.toString().padStart(2,"0")} ${period}`;
  };

  const steps = [
    { time: fmt(showHour - 8),   emoji:"☕", label:"Morning fuel",         detail:`Coffee + light breakfast. You'll be on your feet all day.`, color:C.gold },
    { time: fmt(showHour - 6),   emoji:"🛍️", label:"Merch run (early)",    detail:`Beat the line — ${concert.venue} merch opens ${fmt(doorsHour - 2)}. Go now.`, color:C.mint },
    { time: fmt(showHour - 5),   emoji:"🍜", label:"Pre-show meal",        detail:`Korean BBQ or a sit-down near the venue. Eat properly.`, color:C.rose },
    { time: fmt(showHour - 3.5), emoji:"✨", label:"Outfit check & photos", detail:`Find the fan zone outside the venue for fit pics before it gets crowded.`, color:C.pink },
    { time: fmt(doorsHour - 0.5),emoji:"🚶", label:"Head to venue",        detail:`Leave 30 min before doors. ${concert.parkingTip || "Factor in parking."}`, color:C.accent },
    { time: fmt(doorsHour),      emoji:"🎟️", label:"Doors open",           detail:`${concert.gateInfo || "Enter and find your section early."}`, color:concert.color },
    { time: fmt(doorsHour + 0.5),emoji:"🃏", label:"Find your people",     detail:`Check Backstage for nearby fan buddies and meetup spots inside.`, color:C.lavender },
    { time: fmt(showHour - 0.5), emoji:"🎤", label:"Artist warm-up vibes", detail:`Opening acts. Learn the fanchants — ${concert.group} will hear you.`, color:concert.color },
    { time: fmt(showHour),       emoji:"💜", label:"Show starts",           detail:`You're here. Every rehearsal, every save, worth it.`, color:C.pink },
    { time: fmt(showHour + 2.5), emoji:"📸", label:"Afterglow & capsule",  detail:`Add your memory to the Concert Capsule before you leave the venue.`, color:C.accent },
    { time: fmt(showHour + 3),   emoji:"🍕", label:"Late night food",      detail:`You earned it. Something near the venue — keep the night going.`, color:C.gold },
    { time: fmt(showHour + 4),   emoji:"🌙", label:"Post-concert debrief", detail:`Swap stories, share fits, drop a Backstage Pass while it's fresh.`, color:C.lavender },
  ];

  return (
    <div style={{ background:C.surface,border:`1.5px solid ${C.accent}30`,borderRadius:18,overflow:"hidden",animation:"up .3s ease" }}>
      {/* Header */}
      <div style={{ padding:"14px 16px",background:`linear-gradient(140deg,${C.accent}12,${C.pink}06)`,borderBottom:`1px solid ${C.border}` }}>
        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,color:C.text,marginBottom:2 }}>🗓️ Your Day at {concert.name}</p>
        <p style={{ fontSize:10.5,color:C.textMid }}>Show time {concert.showTime} · Doors {concert.doorsOpen} · {concert.venue}</p>
      </div>

      {/* Timeline */}
      <div style={{ padding:"14px 16px",display:"flex",flexDirection:"column",gap:0 }}>
        {steps.map((s,i)=>(
          <div key={i} style={{ display:"flex",gap:12,position:"relative" }}>
            {/* Connector line */}
            {i < steps.length - 1 && (
              <div style={{ position:"absolute",left:19,top:36,bottom:-4,width:1.5,background:`${s.color}30` }} />
            )}
            {/* Icon bubble */}
            <div style={{ width:38,height:38,borderRadius:12,background:`${s.color}18`,border:`1px solid ${s.color}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,flexShrink:0,zIndex:1 }}>{s.emoji}</div>
            {/* Content */}
            <div style={{ paddingBottom:16,flex:1 }}>
              <div style={{ display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:2 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5,color:C.text }}>{s.label}</p>
                <span style={{ fontSize:9.5,color:s.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,flexShrink:0,marginLeft:8 }}>{s.time}</span>
              </div>
              <p style={{ fontSize:11,color:C.textMid,lineHeight:1.55 }}>{s.detail}</p>
            </div>
          </div>
        ))}
      </div>

      {/* Save CTA */}
      <div style={{ padding:"0 16px 16px" }}>
        <p style={{ fontSize:9.5,color:C.textDim,textAlign:"center",fontStyle:"italic" }}>✦ Personalized for {concert.group} at {concert.city}</p>
      </div>
    </div>
  );
}

function ShowDetail({ concert, onBack, going, setGoing, go, isVip, onUpgrade, rsvped, setRsvped }) {
  const [chatOpen, setChatOpen] = useState(false);
  const [chatMsg, setChatMsg] = useState("");
  const [messages, setMessages] = useState(["Anyone doing the merch line early? 👀","outfit reveal at 6pm meet me at gate 3 ✨","Freebies station at Gate 5 after 3pm 🎁"]);
  const [itineraryOpen, setItineraryOpen] = useState(false);
  const [selectedMeetup, setSelectedMeetup] = useState(null);
  const isArirangEvent = concert?.id === "bts-lv-2026" || concert?.id === "bts-lv-1" || /ARIRANG/i.test(concert?.name || "");
  const capsuleBannerKey = `backstage_arirang_capsule_banner_dismissed_${concert?.id || "event"}`;
  const [showCapsuleBanner, setShowCapsuleBanner] = useState(() => isArirangEvent && !ls.get(capsuleBannerKey, false));
  const myMeetups = MOCK_MEETUPS.filter(m=>m.concertId===concert.id);

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"16px 20px", display:"flex", gap:10, alignItems:"center", flexShrink:0 }}>
        <button onClick={onBack} style={{ background:"none", border:"none", color:C.textMid, fontSize:22, cursor:"pointer" }}>←</button>
        <div style={{ flex:1,minWidth:0 }}>
          <div style={{ display:"flex",alignItems:"center",gap:7,marginBottom:4 }}>
            <Pill color={concert.color} active small>{concert.group}</Pill>
            <StatusChip label={concert.verificationStatus==="confirmed"?"CONFIRMED":concert.verificationStatus==="official"?"OFFICIAL":"PREVIEW"} />
          </div>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:17, letterSpacing:"-0.01em" }}>{concert.name}</h2>
          {concert.verificationStatus==="confirmed"&&concert.sourceName&&(
            <p style={{ fontSize:9,color:C.textDim,fontStyle:"italic",marginTop:2 }}>✦ {concert.sourceName}</p>
          )}
          {concert.verificationStatus==="preview"&&(
            <p style={{ fontSize:9,color:C.textDim,fontStyle:"italic",marginTop:2 }}>Sample concert card · not verified data</p>
          )}
        </div>
      </div>
      <Screen>
        <div style={{ background:`linear-gradient(140deg,${concert.color}22,${concert.color}08)`, border:`1.5px solid ${concert.color}40`, borderRadius:20, padding:18, marginBottom:16 }}>
          <p style={{ fontSize:12, color:C.text }}>📅 {concert.date}</p>
          <p style={{ fontSize:12, color:C.text, marginBottom:14 }}>📍 {concert.venue}, {concert.city}</p>
          {concert.attendees != null ? (
            <div style={{ display:"flex", gap:20, marginBottom:14 }}>
              {[["👥",concert.attendees,"going"],["🤝",concert.buddies,"buddy"],["✈️",concert.traveling,"traveling"]].map(([icon,count,label])=>(
                <div key={label} style={{ textAlign:"center", flex:1 }}>
                  <p style={{ fontSize:20 }}>{icon}</p>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:20, color:concert.color }}>{count}</p>
                  <p style={{ fontSize:9.5, color:C.textMid }}>{label}</p>
                </div>
              ))}
            </div>
          ) : (
            <div style={{ marginBottom:14,padding:"10px 12px",background:`${concert.color}08`,borderRadius:12,border:`1px solid ${concert.color}20` }}>
              <p style={{ fontSize:11,color:C.textMid }}>💜 Find fans going — add this show and connect with your Circle.</p>
            </div>
          )}
          <Btn color={concert.color} onClick={()=>setGoing(g=>({...g,[concert.id]:!g[concert.id]}))}>
            {going[concert.id]?"✓ I'm Going!":"Mark I'm Going"}
          </Btn>
          <button onClick={async()=>{
            const ics=`BEGIN:VCALENDAR\nVERSION:2.0\nBEGIN:VEVENT\nSUMMARY:${concert.name}\nDTSTART:20260430T193000Z\nDTEND:20260430T233000Z\nLOCATION:${concert.venue}, ${concert.city}\nDESCRIPTION:K-pop concert tracked on Backstage · ${concert.attendees} fans going\nEND:VEVENT\nEND:VCALENDAR`;
            // Use Web Share API when available (iOS Safari, Android Chrome) — native calendar dialog
            if(navigator.share && navigator.canShare) {
              try {
                const file = new File([ics], `${concert.name.replace(/\s+/g,"-")}.ics`, {type:"text/calendar"});
                if(navigator.canShare({files:[file]})) { await navigator.share({files:[file],title:concert.name,text:`${concert.name} · ${concert.city}`}); return; }
              } catch(e) { /* fallback to download */ }
            }
            // Fallback: .ics download
            const blob=new Blob([ics],{type:"text/calendar"});
            const url=URL.createObjectURL(blob);
            const a=document.createElement("a");
            a.href=url; a.download=`${concert.name.replace(/\s+/g,"-")}.ics`; a.click();
            URL.revokeObjectURL(url);
          }} style={{ width:"100%",marginTop:9,padding:"9px",borderRadius:13,background:`${concert.color}10`,border:`1.5px solid ${concert.color}33`,color:concert.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11.5,cursor:"pointer" }}>📅 Add to Calendar</button>
        </div>
        {showCapsuleBanner && (
          <div style={{ background:`linear-gradient(140deg,${C.accent}18,${C.pink}0c)`, border:`1.5px solid ${C.accent}38`, borderRadius:16, padding:14, marginBottom:16 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:13.5, color:C.lavender, marginBottom:5 }}>✨ Add your ARIRANG memories to the Concert Capsule</p>
            <p style={{ fontSize:11.5, color:C.textMid, lineHeight:1.55, marginBottom:12 }}>Share your photos, freebies, banners, outfits, and favorite Vegas moments with ARMY.</p>
            <div style={{ display:"flex", gap:8 }}>
              <button onClick={()=>go("capsule")} style={{ flex:1, padding:"9px 12px", borderRadius:11, background:C.accent, border:"none", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:11.5, cursor:"pointer" }}>Open Capsule</button>
              <button onClick={()=>{ ls.set(capsuleBannerKey, true); setShowCapsuleBanner(false); }} style={{ padding:"9px 12px", borderRadius:11, background:"transparent", border:`1px solid ${C.border}`, color:C.textMid, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11.5, cursor:"pointer" }}>Maybe later</button>
            </div>
          </div>
        )}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:18 }}>
          {[["💬 Show Chat",()=>setChatOpen(!chatOpen)],["✈️ Trip Planner",()=>go("trip")],["📋 Prep Checklist",()=>go("concertprep")],["✨ Outfit Generator",()=>go("outfits")],["🎵 Fan Chants",()=>go("explore")],["📸 My Shows",()=>go("myshows")]].map(([label,action])=>(
            <button key={label} onClick={action} className="tap" style={{ padding:14, borderRadius:14, background:C.surfaceHi, border:`1.5px solid ${C.border}`, color:C.text, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11.5, cursor:"pointer", textAlign:"center" }}>{label}</button>
          ))}
        </div>
        {/* ── AI CONCERT DAY ITINERARY (VIP) ── */}
        <div style={{ marginBottom:20 }}>
          {/* Header row */}
          <div style={{ display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12 }}>
            <div style={{ display:"flex",gap:8,alignItems:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:C.text }}>✨ AI Concert Day Itinerary</p>
              <span style={{ fontSize:8,padding:"2px 7px",borderRadius:99,background:`${C.gold}18`,border:`1px solid ${C.gold}33`,color:C.gold,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>VIP</span>
            </div>
            {isVip&&<button onClick={()=>setItineraryOpen(o=>!o)} style={{ background:"none",border:"none",color:C.accent,fontSize:11.5,cursor:"pointer",fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>{itineraryOpen?"Hide ↑":"Generate ↓"}</button>}
          </div>

          {!isVip ? (
            <VipGate isVip={false} onUpgrade={onUpgrade} feature="AI Concert Day Itinerary">
              <div style={{ height:120 }} />
            </VipGate>
          ) : itineraryOpen ? (
            <AiItinerary concert={concert} />
          ) : (
            <div onClick={()=>setItineraryOpen(true)} className="tap" style={{ background:`linear-gradient(140deg,${C.accent}10,${C.pink}06)`,border:`1.5px dashed ${C.accent}44`,borderRadius:16,padding:"16px 18px",cursor:"pointer",textAlign:"center" }}>
              <p style={{ fontSize:28,marginBottom:8 }}>🗓️</p>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,color:C.accent,marginBottom:4 }}>Build Your Full Day</p>
              <p style={{ fontSize:11.5,color:C.textMid,lineHeight:1.55 }}>Arrival window · Merch timing · Dinner · Afterglow — all planned around your show time.</p>
            </div>
          )}
        </div>

        <SectionHeader title="Meetups & Events" />
        <div style={{ marginBottom:18 }}>
          {myMeetups.length === 0 && (
            <div style={{ background:C.surface, border:`1px solid ${C.border}`, borderRadius:14, padding:16, textAlign:"center" }}>
              <p style={{ fontSize:12, color:C.textMid }}>No meetups listed yet for this show.</p>
              <p style={{ fontSize:11, color:C.textDim, marginTop:4 }}>Check Backstage closer to the date.</p>
            </div>
          )}
          {myMeetups.map(m=>{
            const icon = m.type==="afterparty"?"🎉":m.type==="cupsleeve"?"🧋":m.type==="trade"?"🃏":m.type==="freebie"?"🎁":"📍";
            const isExpanded = selectedMeetup===m.id;
            const userRsvped = rsvped?.[m.id];
            return (
              <div key={m.id} onClick={()=>setSelectedMeetup(isExpanded?null:m.id)} className="tap" style={{ background:m.type==="afterparty"?`${m.color}12`:C.surface, border:`1.5px solid ${userRsvped?m.color:m.type==="afterparty"?m.color:C.border}`, borderRadius:16, padding:14, marginBottom:10, cursor:"pointer" }}>
                <div style={{ display:"flex", gap:10, alignItems:"center" }}>
                  <span style={{ fontSize:22 }}>{icon}</span>
                  <div style={{ flex:1 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13 }}>{m.title}</p>
                    <p style={{ fontSize:10.5, color:C.textMid }}>{m.time} · {m.place}</p>
                    {m.rsvps>0&&<p style={{ fontSize:10, color:m.color, marginTop:2 }}>{m.rsvps} going</p>}
                  </div>
                  <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:6 }}>
                    {m.ageLimit&&<span style={{ fontSize:9, padding:"2px 6px", borderRadius:99, background:`${C.gold}18`, color:C.gold, fontFamily:"'Epilogue',sans-serif", fontWeight:700 }}>{m.ageLimit}</span>}
                    <span style={{ fontSize:9, color:C.textDim }}>tap for details</span>
                  </div>
                </div>
                {isExpanded&&(
                  <div style={{ marginTop:12, borderTop:`1px solid ${C.border}`, paddingTop:12, animation:"up .2s ease" }} onClick={e=>e.stopPropagation()}>
                    {m.description&&<p style={{ fontSize:11.5, color:C.textMid, lineHeight:1.6, marginBottom:10 }}>{m.description}</p>}
                    <div style={{ display:"flex", flexWrap:"wrap", gap:6, marginBottom:12 }}>
                      {m.organizer&&<span style={{ fontSize:10, padding:"3px 8px", borderRadius:99, background:C.surfaceHi, color:C.textMid }}>👤 {m.organizer}</span>}
                      {m.capacity&&<span style={{ fontSize:10, padding:"3px 8px", borderRadius:99, background:C.surfaceHi, color:C.textMid }}>👥 Capacity: {m.capacity}</span>}
                      {m.entry&&<span style={{ fontSize:10, padding:"3px 8px", borderRadius:99, background:C.surfaceHi, color:C.textMid }}>🎟 {m.entry}</span>}
                    </div>
                    {m.safety&&(
                      <div style={{ background:`${C.mint}0e`, border:`1px solid ${C.mint}30`, borderRadius:10, padding:"8px 11px", marginBottom:12 }}>
                        <p style={{ fontSize:10.5, color:C.mint }}>🛡 {m.safety}</p>
                      </div>
                    )}
                    <Btn color={m.color} small onClick={()=>{
                      const next = {...(rsvped||{}), [m.id]:!(rsvped?.[m.id])};
                      setRsvped&&setRsvped(next);
                    }}>
                      {userRsvped?"✓ You're Going! (tap to cancel)":"RSVP →"}
                    </Btn>
                  </div>
                )}
              </div>
            );
          })}
        </div>
        {chatOpen && (
          <div style={{ background:C.surfaceHi, border:`1.5px solid ${concert.color}44`, borderRadius:18, padding:16, marginBottom:18, animation:"up .25s ease" }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13.5 }}>💬 {concert.group} Show Chat</p>
              <button onClick={()=>setChatOpen(false)} style={{ background:"none", border:"none", color:C.textMid, cursor:"pointer" }}>✕</button>
            </div>
            <div style={{ display:"flex", flexDirection:"column", gap:8, marginBottom:12 }}>
              {messages.map((msg,i)=>(
                <div key={i} style={{ background:C.surface, borderRadius:11, padding:"8px 12px" }}>
                  <p style={{ fontSize:12 }}>{msg}</p>
                </div>
              ))}
            </div>
            <div style={{ display:"flex", gap:8 }}>
              <input value={chatMsg} onChange={e=>setChatMsg(e.target.value)} placeholder="Say something..." style={{ flex:1, padding:"10px 12px", borderRadius:11, background:C.surface, border:`1.5px solid ${C.border}`, color:C.text, fontSize:12.5 }} onKeyDown={e=>{ if(e.key==="Enter"&&chatMsg.trim()){ setMessages([...messages,chatMsg]); setChatMsg(""); } }} />
              <button onClick={()=>{ if(chatMsg.trim()){setMessages([...messages,chatMsg]);setChatMsg("");} }} style={{ background:concert.color, border:"none", borderRadius:11, padding:"0 16px", color:C.bg, fontWeight:800, cursor:"pointer", fontSize:16 }}>→</button>
            </div>
          </div>
        )}
      </Screen>
    </div>
  );
}

// ─── COLLECT ──────────────────────────────────────────────────────────────────
// ─── LIBRARY TAB — rich collection shell ─────────────────────────────────────
// ─── PHOTOCARD GRID — visual, photo-upload, AI-identify placeholder ───────────
function PhotocardGrid({ cards, groups, groupFilter, setGroupFilter, go, rarityColors, rarityGlow, rarityBg, rarityBadge }) {
  const CONDITION_TO_RAR = { mint:'UR', near_mint:'SR', good:'R', played:'N' };
  const [cardPhotos, setCardPhotos] = useState(()=>ls.get("backstage_card_photos",{}));
  const [aiResult, setAiResult]     = useState(null);
  const [aiLoading, setAiLoading]   = useState(null);
  const [expanded, setExpanded]     = useState(null);
  const [uploading, setUploading]   = useState(null);
  const fileRefs = useRef({});

  const savePhoto = (cardId, url) => {
    const next = {...cardPhotos, [cardId]: url};
    setCardPhotos(next);
    ls.set("backstage_card_photos", next);
  };

  const handleFileChange = async (e, card) => {
    const f = e.target.files[0]; if(!f) return;
    const r = new FileReader();
    r.onload = ev => savePhoto(card.id, ev.target.result);
    r.readAsDataURL(f);
    // Upload to Supabase for real DB cards (UUID string ids)
    if (typeof card.id === 'string') {
      setUploading(card.id);
      try {
        const urlRes = await api.post('/api/cards/upload-url', { filename: f.name, content_type: f.type });
        if (urlRes?.signed_url) {
          await fetch(urlRes.signed_url, { method:'PUT', body:f, headers:{'Content-Type':f.type} });
          await api.patch(`/api/cards/${card.id}`, { image_url: urlRes.public_url });
          savePhoto(card.id, urlRes.public_url);
        }
      } catch { /* keep localStorage preview as fallback */ }
      setUploading(null);
    }
  };

  const handleAiIdentify = async (cardId) => {
    setAiLoading(cardId);
    await new Promise(r=>setTimeout(r,1200));
    // TODO: POST /api/ai/identify-card with image data — not called without proxy
    setAiResult({ cardId, name:"Felix", group:"Stray Kids", era:"MAXIDENT", rarity:"UR", confidence:"92%", note:"AI-estimated. Verify against official fansites." });
    setAiLoading(null);
  };

  return (
    <div>
      {/* Group filter chips */}
      <div style={{ display:"flex", gap:6, marginBottom:14, overflowX:"auto", scrollbarWidth:"none" }}>
        {groups.map(g=>(
          <span key={g} onClick={()=>setGroupFilter(g)} className="tap" style={{ flexShrink:0, padding:"5px 12px", borderRadius:99, fontSize:10, fontFamily:"'Epilogue',sans-serif", fontWeight:700, cursor:"pointer", background:groupFilter===g?C.pink:`${C.pink}12`, color:groupFilter===g?C.bg:C.textMid, border:`1px solid ${groupFilter===g?C.pink:C.border}` }}>{g==="all"?"All Groups":g}</span>
        ))}
      </div>

      {/* AI identify result banner */}
      {aiResult && (
        <div style={{ ...VS.glowCard(C.mint),padding:"12px 14px",marginBottom:14,animation:"notifDrop .25s ease" }}>
          <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.mint}55,transparent)` }} />
          <div style={{ position:"relative",display:"flex",gap:10,alignItems:"flex-start" }}>
            <span style={{ fontSize:20 }}>🤖</span>
            <div style={{ flex:1 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5,color:C.mint,marginBottom:2 }}>AI Card Identified — {aiResult.confidence} confidence</p>
              <p style={{ fontSize:11.5,color:C.text,marginBottom:3 }}>{aiResult.name} · {aiResult.group} · {aiResult.era} · {aiResult.rarity}</p>
              <p style={{ fontSize:10,color:C.textDim,fontStyle:"italic" }}>{aiResult.note}</p>
            </div>
            <button onClick={()=>setAiResult(null)} style={{ background:"none",border:"none",color:C.textMid,cursor:"pointer",fontSize:16 }}>✕</button>
          </div>
        </div>
      )}

      {/* Photocard grid */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:9 }}>
        {cards.map(c=>{
          const cardName  = c.member || c.name;
          const cardGroup = c.group_name || c.group;
          const isDupe    = c.status==='duplicate' || c.dupe;
          const isForTrade= c.status==='for_trade'  || c.tradeable;
          const rar  = c.rarity || CONDITION_TO_RAR[c.condition] || 'R';
          const rc   = (rarityColors||{})[rar]||C.accent;
          const photo = c.image_url || cardPhotos[c.id];
          const isExpanded  = expanded===c.id;
          const isUploading = uploading===c.id;
          return (
            <div key={c.id} style={{ position:"relative" }}>
              {/* Status badges */}
              <div style={{ position:"absolute",top:4,left:4,zIndex:3,display:"flex",flexDirection:"column",gap:2 }}>
                {isDupe&&<div style={{ background:C.gold,borderRadius:4,padding:"1px 5px",fontSize:7,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:C.bg }}>DUPE</div>}
                {isForTrade&&<div style={{ background:C.rose,borderRadius:4,padding:"1px 5px",fontSize:7,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:C.bg }}>TRADE</div>}
              </div>
              {/* Rarity/condition badge */}
              <div style={{ position:"absolute",top:5,right:5,zIndex:3 }}>
                <div style={{ background:rar==="UR"?`linear-gradient(135deg,${C.gold}ee,${C.coral}cc)`:rar==="SR"?`${C.berry}dd`:`${rc}cc`,borderRadius:4,padding:"2px 6px",fontSize:6.5,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:rar==="UR"?C.bg:C.white,letterSpacing:"0.04em" }}>{(rarityBadge||{})[rar]||rar}</div>
              </div>
              {/* Card body — collectible style */}
              <div onClick={()=>setExpanded(isExpanded?null:c.id)} className="tap card-lift" style={{ borderRadius:14,aspectRatio:"2/3",background:(rarityBg||{})[rar]||(photo?"transparent":`linear-gradient(160deg,${rc}44,${rc}18)`),border:`1.5px solid ${rc}55`,display:"flex",flexDirection:"column",justifyContent:"flex-end",padding:"6px 5px",overflow:"hidden",boxShadow:((rarityGlow||{})[rar]||"none")+", 0 4px 16px rgba(0,0,0,0.5)",position:"relative",cursor:"pointer" }}>
                {/* Holo shimmer overlay for UR */}
                {rar==="UR"&&!photo&&<div style={{ position:"absolute",inset:0,background:"linear-gradient(135deg,transparent 0%,rgba(255,255,255,0.04) 40%,rgba(255,255,255,0.08) 50%,rgba(255,255,255,0.04) 60%,transparent 100%)",backgroundSize:"200% 200%",animation:"holoShift 4s ease infinite",borderRadius:12,zIndex:1,pointerEvents:"none" }} />}
                {photo ? (
                  <img src={photo} alt={cardName} style={{ position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",borderRadius:12 }} />
                ) : (
                  <div style={{ position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,opacity:0.15 }}>
                    <span style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:36,color:rc,opacity:0.25 }}>{cardName?.[0]||"K"}</span>
                  </div>
                )}
                {/* Inner glow border effect */}
                <div style={{ position:"absolute",inset:0,borderRadius:12,boxShadow:`inset 0 0 16px ${rc}22`,pointerEvents:"none" }} />
                <div style={{ position:"relative",zIndex:2,background:photo?"rgba(6,6,15,0.7)":"transparent",borderRadius:"0 0 10px 10px",padding:"4px 5px" }}>
                  <p style={{ fontSize:7.5,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:C.white,lineHeight:1.2 }}>{cardName}</p>
                  <p style={{ fontSize:6.5,color:rc }}>{cardGroup||c.era}</p>
                </div>
              </div>
              {/* Expanded actions */}
              {isExpanded && (
                <div style={{ position:"absolute",bottom:-82,left:0,right:0,zIndex:10,background:C.surfaceHi,border:`1.5px solid ${rc}44`,borderRadius:12,padding:8,animation:"up .15s ease",display:"flex",flexDirection:"column",gap:5 }}>
                  <button onClick={()=>fileRefs.current[c.id]?.click()} disabled={isUploading} style={{ padding:"6px 8px",borderRadius:8,background:`${rc}18`,border:`1px solid ${rc}33`,color:rc,fontSize:9.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer" }}>{isUploading?"⏳ Uploading...":(photo?"📷 Replace Photo":"📷 Add Photo")}</button>
                  <button onClick={()=>handleAiIdentify(c.id)} disabled={!!aiLoading} style={{ padding:"6px 8px",borderRadius:8,background:`${C.mint}18`,border:`1px solid ${C.mint}33`,color:C.mint,fontSize:9.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer" }}>{aiLoading===c.id?"🤖 Scanning...":"🤖 AI Identify"}</button>
                  <input ref={el=>fileRefs.current[c.id]=el} type="file" accept="image/*" onChange={e=>handleFileChange(e,c)} style={{ display:"none" }} />
                </div>
              )}
            </div>
          );
        })}
        {/* Add card slot */}
        <div onClick={()=>go?.("collect")} className="tap" style={{ borderRadius:12,aspectRatio:"2/3",border:`2px dashed ${C.border}`,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:3,cursor:"pointer" }}>
          <p style={{ fontSize:18,color:C.accent }}>+</p>
          <p style={{ fontSize:7,color:C.textDim,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textAlign:"center",lineHeight:1.3 }}>Add Card</p>
        </div>
      </div>
      <p style={{ fontSize:9.5,color:C.textDim,marginTop:12,textAlign:"center",lineHeight:1.5 }}>Tap a card to add a photo · AI identify estimates only</p>
    </div>
  );
}

function LibraryTab({ cards, setCards, isVip, onUpgrade, go, user, weather }) {
  const [section, setSection] = useState("museum");
  const [groupFilter, setGroupFilter] = useState("all");
  const [myWorldTheme, setMyWorldTheme] = useState(()=>ls.get("backstage_my_world_theme","Purple Galaxy"));
  const [featuredShelf, setFeaturedShelf] = useState(()=>ls.get("backstage_featured_shelf",{photocard:null,concert:null,capsule:null,outfit:null,biasMoment:null}));
  const [showDecorate, setShowDecorate] = useState(false);
  const [editingShelfKey, setEditingShelfKey] = useState(null);
  const [shelfDraft, setShelfDraft] = useState("");
  const saveTheme = (t)=>{ setMyWorldTheme(t); ls.set("backstage_my_world_theme",t); };
  const saveFeatured = (key,val)=>{ const next={...featuredShelf,[key]:val}; setFeaturedShelf(next); ls.set("backstage_featured_shelf",next); };
  const WORLD_THEMES = [
    {id:"Purple Galaxy",  emoji:"🌌", color:C.lavender},
    {id:"Pink Lightstick",emoji:"🩷", color:C.pink    },
    {id:"Golden Founder", emoji:"✦",  color:C.gold    },
    {id:"Holo Binder",    emoji:"🌈", color:C.mint    },
    {id:"Soft MySpace",   emoji:"💜", color:C.berry   },
    {id:"Midnight Arena", emoji:"🎤", color:"#6699dd" },
  ];
  const THEME_BG = {
    "Purple Galaxy":  `radial-gradient(ellipse at 65% 0%,${C.lavender}22,transparent 55%),radial-gradient(ellipse at 20% 88%,${C.accent}10,transparent 50%)`,
    "Pink Lightstick":`radial-gradient(ellipse at 70% 0%,${C.pink}20,transparent 55%),radial-gradient(ellipse at 25% 85%,${C.rose}10,transparent 50%)`,
    "Golden Founder": `radial-gradient(ellipse at 60% 0%,${C.gold}18,transparent 55%),radial-gradient(ellipse at 15% 88%,${C.gold}08,transparent 50%)`,
    "Holo Binder":    `radial-gradient(ellipse at 70% 5%,${C.mint}18,transparent 55%),radial-gradient(ellipse at 25% 80%,${C.sky}10,transparent 50%)`,
    "Soft MySpace":   `radial-gradient(ellipse at 60% 0%,${C.berry}20,transparent 55%),radial-gradient(ellipse at 20% 88%,${C.blush}10,transparent 50%)`,
    "Midnight Arena": `radial-gradient(ellipse at 65% 5%,#6699dd22,transparent 55%),radial-gradient(ellipse at 15% 80%,#44668820,transparent 50%)`,
  };

  const { binders } = useBinders();
  const [isoCards, setIsoCards] = useState([]);
  useEffect(()=>{ api.get('/api/cards?status=iso').then(d=>{ if(d?.cards) setIsoCards(d.cards); }).catch(()=>{}); },[]);
  const wishlist  = isoCards;
  const allCards  = cards || MOCK_CARDS;
  const dupes     = allCards.filter(c=>c.status==='duplicate'||c.dupe);
  const tradeable = allCards.filter(c=>c.status==='for_trade'||c.tradeable);
  const totalOwned = allCards.length;
  const completion = Math.round((totalOwned / Math.max(totalOwned + wishlist.length, 1)) * 100);

  const GROUPS = ["all", ...new Set(allCards.map(c=>c.group_name||c.group).filter(Boolean))].slice(0,6);

  const filteredCards = groupFilter==="all" ? allCards : allCards.filter(c=>(c.group_name||c.group)===groupFilter);

  const RARITY_COLORS  = { UR:C.gold, SR:C.berry, R:C.lavender, N:C.silver };
  const RARITY_GLOW    = { UR:`0 0 18px ${C.gold}66, 0 0 36px ${C.gold}22`, SR:`0 0 14px ${C.berry}55`, R:`0 0 10px ${C.lavender}44`, N:"none" };
  const RARITY_BADGE   = { UR:"HOLO", SR:"RARE", R:"1/1", N:"STD" };
  const RARITY_BG      = {
    UR:`linear-gradient(135deg,#1a1000,#2d1a00,#3d2400)`,
    SR:`linear-gradient(135deg,#1a0018,#2d0028,#3d0038)`,
    R: `linear-gradient(135deg,#0a0020,#160038,#1e0050)`,
    N: `linear-gradient(135deg,#0e0e22,#181830,#1e1e3c)`,
  };

  const _concertResume = ls.get("backstage_concert_resume",[]);
  const _fanIdentity   = ls.get("backstage_fan_identity",null);
  const MUSEUM_TILES = [
    {id:"albums",       emoji:"📁", label:"Albums",       stat:binders.length,          unit:"binders",  color:C.accent  },
    {id:"pcs",          emoji:"🃏", label:"Photocards",   stat:allCards.length,          unit:"cards",    color:C.pink    },
    {id:"memories",     emoji:"📸", label:"Memories",     stat:4,                        unit:"moments",  color:C.sky     },
    {id:"concerts",     emoji:"🎤", label:"Concerts",     stat:_concertResume.length||6, unit:"shows",    color:C.berry   },
    {id:"capsules",     emoji:"💊", label:"Capsules",     stat:ls.get("backstage_capsules_count",2), unit:"saved", color:C.mint },
    {id:"scrapbook",    emoji:"🗂️", label:"Scrapbooks",  stat:1,                        unit:"book",     color:C.lavender},
    {id:"achievements", emoji:"🏅", label:"Achievements", stat:7,                        unit:"unlocked", color:C.gold    },
    {id:"shrine",       emoji:"💜", label:"Bias Shrine",  stat:_fanIdentity?.bias?1:0,   unit:"set",      color:C.rose    },
  ];
  const FEATURED_OPTIONS = [
    {key:"photocard",  label:"Favorite Photocard",    emoji:"🃏", placeholder:"Felix — MANIAC era",        color:C.pink    },
    {key:"concert",    label:"Favorite Concert",       emoji:"🎤", placeholder:"ATEEZ Dallas 2025",         color:C.berry   },
    {key:"capsule",    label:"Favorite Capsule",       emoji:"💊", placeholder:"BTS Vegas Night 2 ✦",      color:C.mint    },
    {key:"outfit",     label:"Favorite Outfit",        emoji:"✨", placeholder:"MANIAC era silver fit",     color:C.lavender},
    {key:"biasMoment", label:"Favorite Bias Moment",   emoji:"💜", placeholder:"Karina eye contact fancam", color:C.rose    },
  ];

  const SECTIONS = [
    { id:"museum",     label:"Museum",     icon:"🏛️" },
    { id:"photocards", label:"Photocards", icon:"🃏" },
    { id:"albums",     label:"Albums",     icon:"📁" },
    { id:"scrapbook",  label:"Scrapbook",  icon:"📸" },
    { id:"wishlist",   label:"Wishlist",   icon:"⭐" },
  ];

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      {/* Atmospheric bg */}
      <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at 80% 10%,${C.pink}06,transparent 45%),radial-gradient(ellipse at 10% 85%,${C.accent}05,transparent 50%)`,pointerEvents:"none",zIndex:0 }} />
      {/* Theme overlay — changes with Decorate selection */}
      <div style={{ position:"absolute",inset:0,background:THEME_BG[myWorldTheme]||THEME_BG["Purple Galaxy"],pointerEvents:"none",zIndex:0,transition:"background .5s ease" }} />

      {/* Slim fixed header — only title + sub-nav */}
      <div style={{ padding:"18px 20px 0", flexShrink:0, position:"relative", zIndex:1 }}>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
          <div>
            <div>
              <p style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:1 }}>My World</p>
              <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontStyle:"italic",fontWeight:700,fontSize:20,background:`linear-gradient(135deg,${C.lavender},${C.blush})`,WebkitBackgroundClip:"text",WebkitTextFillColor:"transparent",lineHeight:1.1 }}>My Universe ✦</h2>
              <p style={{ fontSize:9.5,color:C.textDim,marginTop:2 }}>Collections, capsules, memories, and scrapbooks.</p>
              <p style={{ fontSize:9.5,color:C.textMid,marginTop:1 }}>{totalOwned} owned · {wishlist.length} wanted · {tradeable.length} tradeable</p>
            </div>
          </div>
          <div style={{ display:"flex", gap:8, alignItems:"center" }}>
            {isVip&&<VipBadge />}
            <button onClick={()=>go("collect")} style={{ background:`linear-gradient(140deg,${C.accent}cc,${C.accentDim})`, border:"none", borderRadius:11, padding:"8px 13px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10.5, cursor:"pointer" }}>+ Add</button>
          </div>
        </div>
        {/* Sub-nav */}
        <div style={{ display:"flex", gap:6, overflowX:"auto", paddingBottom:12, scrollbarWidth:"none" }}>
          {SECTIONS.map(s=>(
            <button key={s.id} onClick={()=>setSection(s.id)} className="tap" style={{ flexShrink:0, padding:"7px 14px", borderRadius:99, fontSize:11, fontFamily:"'Epilogue',sans-serif", fontWeight:700, background:section===s.id?`linear-gradient(140deg,${C.accent}cc,${C.accentDim})`:C.surfaceHi, color:section===s.id?C.bg:C.textMid, border:section===s.id?"none":`1px solid ${C.border}`, cursor:"pointer", boxShadow:section===s.id?`0 4px 12px ${C.accent}28`:"none", display:"flex", gap:5, alignItems:"center" }}>
              <span>{s.icon}</span><span>{s.label}</span>
            </button>
          ))}
        </div>
      </div>

      {/* CONTENT — all cards/stats scroll here */}
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))", position:"relative", zIndex:1 }}>

        {/* Collection Overview card */}
        <div style={{ background:`linear-gradient(140deg,${C.surfaceMid},${C.surfaceHi})`, border:`1.5px solid ${C.borderHi}`, borderRadius:18, padding:"14px 16px", marginBottom:12, position:"relative", overflow:"hidden" }}>
          <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.accent}44,transparent)` }} />
          <p style={{ fontSize:9, color:C.textMid, fontFamily:"'Epilogue',sans-serif", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.1em", marginBottom:10 }}>Collection Overview</p>
          <div style={{ display:"flex", gap:0 }}>
            {[
              { val:totalOwned, label:"Total", color:C.text },
              { val:allCards.filter(c=>c.status?c.status==='owned':!c.dupe&&!c.tradeable).length, label:"Photocards", color:C.pink },
              { val:binders.length, label:"Albums", color:C.accent },
            ].map((s,i)=>(
              <div key={s.label} style={{ flex:1, textAlign:"center", borderRight:i<2?`1px solid ${C.border}`:"none" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:22, color:s.color, lineHeight:1 }}>{s.val}</p>
                <p style={{ fontSize:9, color:C.textMid, marginTop:3 }}>{s.label}</p>
              </div>
            ))}
          </div>
          <div style={{ height:1, background:C.border, margin:"12px 0" }} />
          <div style={{ display:"flex", gap:0 }}>
            {[
              { val:wishlist.length, label:"Wishlist", color:C.gold },
              { val:tradeable.length, label:"Tradeable", color:C.rose },
              { val:`${completion}%`, label:"Complete", color:C.mint },
            ].map((s,i)=>(
              <div key={s.label} style={{ flex:1, textAlign:"center", borderRight:i<2?`1px solid ${C.border}`:"none" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:22, color:s.color, lineHeight:1 }}>{s.val}</p>
                <p style={{ fontSize:9, color:C.textMid, marginTop:3 }}>{s.label}</p>
              </div>
            ))}
          </div>
          <div style={{ marginTop:12 }}>
            <ProgressBar value={completion} color={C.mint} />
            <div style={{ display:"flex", justifyContent:"space-between", marginTop:5 }}>
              <p style={{ fontSize:9, color:C.mint, fontFamily:"'Epilogue',sans-serif", fontWeight:700 }}>{completion}% overall completion</p>
              {completion>=75&&<p style={{ fontSize:9, color:C.mint, fontFamily:"'Epilogue',sans-serif", fontWeight:700 }}>✦ Almost there!</p>}
            </div>
          </div>
        </div>

        {/* Smart nudge */}
        {wishlist.length > 0 && (
          <div style={{ background:`linear-gradient(140deg,${C.rose}18,${C.rose}06)`, border:`1.5px solid ${C.rose}38`, borderRadius:14, padding:"10px 14px", marginBottom:12, display:"flex", gap:10, alignItems:"center" }}>
            <span style={{ fontSize:18 }}>🔥</span>
            <div style={{ flex:1 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:12, color:C.text }}>So close! <span style={{ color:C.rose }}>{wishlist.length} card{wishlist.length>1?"s":""}</span> away</p>
              <p style={{ fontSize:10, color:C.textMid }}>Finish your collection — check Trade Hub</p>
            </div>
            <button onClick={()=>go("collect")} style={{ background:C.rose, border:"none", borderRadius:9, padding:"6px 11px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10, cursor:"pointer" }}>Trade →</button>
          </div>
        )}

        {/* VIP upsell */}
        {!isVip && (
          <div onClick={onUpgrade} className="tap" style={{ background:`linear-gradient(140deg,${C.gold}1c,${C.gold}08)`, border:`1.5px solid ${C.gold}44`, borderRadius:14, padding:"10px 14px", marginBottom:14, display:"flex", gap:10, alignItems:"center", cursor:"pointer" }}>
            <span style={{ fontSize:18 }}>✦</span>
            <div style={{ flex:1 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11.5, color:C.gold }}>Unlock Backstage VIP</p>
              <p style={{ fontSize:10, color:C.textMid }}>Unlimited binders · Trade analytics · Priority matches</p>
            </div>
            <div style={{ ...VS.activePill(C.gold), fontSize:9 }}>Upgrade →</div>
          </div>
        )}

        {/* ── MY WORLD MUSEUM ─────────────────────────────────────────────── */}
        {section==="museum" && (
          <div>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:12 }}>
              <div>
                <p style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.12em",marginBottom:2 }}>Fan Archive</p>
                <h3 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16,color:C.text,lineHeight:1.1 }}>Your Fan Museum ✦</h3>
              </div>
              <button onClick={()=>setShowDecorate(d=>!d)} style={{ background:showDecorate?`${C.lavender}28`:`${C.lavender}12`, border:`1.5px solid ${showDecorate?C.lavender:C.lavender+"33"}`, borderRadius:10, padding:"7px 13px", color:C.lavender, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10.5, cursor:"pointer", transition:"all .2s" }}>🎨 Decorate</button>
            </div>
            {showDecorate && (
              <div style={{ ...VS.glowCard(C.lavender), padding:"14px 16px", marginBottom:14 }}>
                <div style={VS.shimmerLine(C.lavender)} />
                <p style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.1em",marginBottom:10 }}>World Theme</p>
                <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr 1fr", gap:8 }}>
                  {WORLD_THEMES.map(t=>(
                    <div key={t.id} onClick={()=>saveTheme(t.id)} className="tap" style={{ borderRadius:12, padding:"10px 8px", textAlign:"center", cursor:"pointer", background:myWorldTheme===t.id?`${t.color}28`:`${t.color}0a`, border:`1.5px solid ${myWorldTheme===t.id?t.color:t.color+"33"}`, transition:"all .2s" }}>
                      <div style={{ fontSize:18, marginBottom:3 }}>{t.emoji}</div>
                      <p style={{ fontSize:8.5, fontFamily:"'Epilogue',sans-serif", fontWeight:700, color:myWorldTheme===t.id?t.color:C.textMid, lineHeight:1.3 }}>{t.id}</p>
                      {myWorldTheme===t.id && <div style={{ width:5,height:5,borderRadius:"50%",background:t.color,margin:"4px auto 0" }} />}
                    </div>
                  ))}
                </div>
              </div>
            )}
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
              {MUSEUM_TILES.map(tile=>(
                <div key={tile.id} onClick={({albums:()=>setSection("albums"),pcs:()=>setSection("photocards"),memories:()=>go("scrapbook"),concerts:()=>go("myshows"),capsules:()=>go("capsule"),scrapbook:()=>setSection("scrapbook")})[tile.id]} className="tap" style={{ borderRadius:16, padding:"14px 14px", background:`${tile.color}0d`, border:`1.5px solid ${tile.color}30`, cursor:"pointer", position:"relative", overflow:"hidden" }}>
                  <div style={{ position:"absolute",top:-10,right:-10,width:44,height:44,borderRadius:"50%",background:`${tile.color}10`,pointerEvents:"none" }} />
                  <div style={{ fontSize:22, marginBottom:5 }}>{tile.emoji}</div>
                  <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:24,color:tile.color,lineHeight:1 }}>{tile.stat}</p>
                  <p style={{ fontSize:9,color:C.textMid,marginTop:1 }}>{tile.unit}</p>
                  <p style={{ fontSize:11.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:C.text,marginTop:5 }}>{tile.label}</p>
                </div>
              ))}
            </div>
            <p style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.12em",marginBottom:8 }}>✦ Featured Shelf</p>
            <div style={{ display:"flex", flexDirection:"column", gap:9, marginBottom:4 }}>
              {FEATURED_OPTIONS.map(opt=>{
                const val = featuredShelf[opt.key];
                const isEditing = editingShelfKey===opt.key;
                return (
                  <div key={opt.key} style={{ ...VS.glowCard(opt.color), padding:"11px 14px" }}>
                    <div style={VS.shimmerLine(opt.color)} />
                    <div style={{ position:"relative", display:"flex", gap:10, alignItems:"center" }}>
                      <div style={{ fontSize:18, flexShrink:0 }}>{opt.emoji}</div>
                      <div style={{ flex:1, minWidth:0 }}>
                        <p style={{ fontSize:8.5,color:opt.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:2 }}>{opt.label}</p>
                        {isEditing ? (
                          <div style={{ display:"flex", gap:6, alignItems:"center" }}>
                            <input value={shelfDraft} onChange={e=>setShelfDraft(e.target.value)} placeholder={opt.placeholder} style={{ flex:1, padding:"5px 8px", borderRadius:8, background:C.surfaceHi, border:`1.5px solid ${opt.color}44`, color:C.text, fontSize:11, fontFamily:"'Instrument Sans',sans-serif", outline:"none" }} autoFocus />
                            <button onClick={()=>{ saveFeatured(opt.key,shelfDraft||null); setEditingShelfKey(null); }} style={{ background:opt.color, border:"none", borderRadius:8, padding:"5px 10px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10, cursor:"pointer" }}>✓</button>
                            <button onClick={()=>setEditingShelfKey(null)} style={{ background:`${opt.color}18`, border:`1px solid ${opt.color}33`, borderRadius:8, padding:"5px 8px", color:opt.color, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10, cursor:"pointer" }}>✕</button>
                          </div>
                        ) : (
                          <p style={{ fontSize:12,color:val?C.text:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:val?600:400,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{val||opt.placeholder}</p>
                        )}
                      </div>
                      {!isEditing && (
                        <button onClick={()=>{ setEditingShelfKey(opt.key); setShelfDraft(val||""); }} style={{ flexShrink:0,background:`${opt.color}18`,border:`1.5px solid ${opt.color}44`,borderRadius:9,padding:"5px 11px",color:opt.color,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:10,cursor:"pointer" }}>{val?"Edit":"Set"}</button>
                      )}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {section==="photocards" && <PhotocardGrid cards={filteredCards} groups={GROUPS} groupFilter={groupFilter} setGroupFilter={setGroupFilter} go={go} rarityColors={RARITY_COLORS} rarityGlow={RARITY_GLOW} rarityBg={RARITY_BG} rarityBadge={RARITY_BADGE} />}

        {section==="albums" && (
          <div style={{ paddingTop:4 }}>
            {/* Albums hero banner */}
            <div style={{ background:`linear-gradient(140deg,${C.plum},${C.cosmic})`,border:`1.5px solid ${C.accent}28`,borderRadius:20,padding:"16px 18px",marginBottom:16,position:"relative",overflow:"hidden" }}>
              <div style={{ position:"absolute",inset:0,background:`radial-gradient(ellipse at 80% 20%,${C.lavender}12,transparent 55%)`,pointerEvents:"none" }} />
              <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.accent}44,transparent)` }} />
              <div style={{ position:"relative" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:C.text,marginBottom:3 }}>📁 My Binders</p>
                <p style={{ fontSize:11,color:C.textMid,lineHeight:1.55,marginBottom:12 }}>Track your complete photocard sets, era by era.</p>
                {!isVip&&(
                  <div onClick={onUpgrade} className="tap" style={{ background:`${C.gold}14`,border:`1px solid ${C.gold}33`,borderRadius:10,padding:"8px 12px",cursor:"pointer",display:"inline-flex",gap:8,alignItems:"center" }}>
                    <span style={{ fontSize:14 }}>✦</span>
                    <div>
                      <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,color:C.gold }}>Unlock your fan era</p>
                      <p style={{ fontSize:9.5,color:C.textMid }}>Unlimited binders · Trade analytics from $4.99/mo</p>
                    </div>
                  </div>
                )}
              </div>
            </div>
            <CollectTab cards={cards} setCards={setCards} isVip={isVip} onUpgrade={onUpgrade} user={user} />
          </div>
        )}

        {section==="scrapbook" && <ScrapbookTab isVip={isVip} onUpgrade={onUpgrade} />}

        {section==="wishlist" && (
          <div style={{ paddingTop:4 }}>
            {wishlist.length===0 ? (
              <div style={{ textAlign:"center",padding:"32px 16px",background:`${C.gold}08`,border:`1.5px dashed ${C.gold}33`,borderRadius:20,marginBottom:14 }}>
                <p style={{ fontSize:30,marginBottom:10 }}>♡</p>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14,marginBottom:5 }}>No wishlist cards yet</p>
                <p style={{ fontSize:12,color:C.textMid,lineHeight:1.6 }}>Open a binder and set cards to ISO to track what you're looking for.</p>
              </div>
            ) : wishlist.map((w,i)=>(
              <div key={w.id||i} className="tap" style={{ ...VS.glowCard(C.gold), padding:14, marginBottom:10, cursor:"pointer", display:"flex", gap:12, alignItems:"center" }}>
                <div style={{ width:48,height:64,borderRadius:10,background:`linear-gradient(160deg,${C.gold}44,${C.gold}18)`,border:`1.5px solid ${C.gold}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0,boxShadow:`0 0 12px ${C.gold}33`,overflow:"hidden" }}>
                  {w.image_url ? <img src={w.image_url} alt="" style={{ width:"100%",height:"100%",objectFit:"cover" }} /> : "🃏"}
                </div>
                <div style={{ flex:1 }}>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:14, color:C.text, marginBottom:3 }}>{w.member||w.name}</p>
                  <p style={{ fontSize:11, color:C.textMid, marginBottom:6 }}>{w.group_name||w.group}{(w.album||w.era)&&` · ${w.album||w.era}`}</p>
                  <div style={{ ...VS.activePill(C.gold), fontSize:8.5 }}>♡ ISO</div>
                </div>
                <button onClick={()=>go("collect")} style={{ background:`${C.gold}18`, border:`1.5px solid ${C.gold}44`, borderRadius:10, padding:"7px 12px", color:C.gold, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10, cursor:"pointer" }}>Find →</button>
              </div>
            ))}
            <button onClick={onUpgrade} style={{ width:"100%", marginTop:8, padding:14, borderRadius:14, background:`${C.gold}08`, border:`1.5px dashed ${C.gold}33`, color:C.gold, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:12, cursor:"pointer" }}>✦ VIP: Unlimited Wishlist + Smart Matching</button>
          </div>
        )}
      </Screen>
    </div>
  );
}

const BINDER_STATUS_TO_DB = { missing:"missing", owned:"owned", wishlist:"iso", dupe:"duplicate", tradeable:"for_trade" };

function BinderCreate({ onBack, onCustom, onCreatedBinder }) {
  const [step, setStep] = useState("search"); // search | preview | slots
  const [groupSearch, setGroupSearch] = useState("");
  const [selectedTemplate, setSelectedTemplate] = useState(null);   // DB template
  const [selectedMock, setSelectedMock] = useState(null);           // mock template (legacy slots flow)
  const [slots, setSlots] = useState([]);
  const [saved, setSaved] = useState(false);
  const [saving, setSaving] = useState(false);
  const [dbTemplates, setDbTemplates] = useState([]);
  const [dbLoading, setDbLoading] = useState(true);
  const [dbError, setDbError] = useState(false);
  const [duplicateErr, setDuplicateErr] = useState(null);

  // Fetch DB templates on mount; fall back to MOCK if unavailable
  useEffect(() => {
    api.get('/api/card-templates')
      .then(d => {
        if (d?.templates?.length) { setDbTemplates(d.templates); }
        else setDbError(true);
        setDbLoading(false);
      })
      .catch(() => { setDbError(true); setDbLoading(false); });
  }, []);

  // Which templates to show: DB if available, otherwise mock-shaped fallback
  const showingDb = !dbError && dbTemplates.length > 0;
  const q = groupSearch.toLowerCase();
  const filteredDb = showingDb
    ? dbTemplates.filter(t => !q || t.group_name.toLowerCase().includes(q) || t.album_name.toLowerCase().includes(q) || (t.era||'').toLowerCase().includes(q))
    : [];
  const filteredMock = !showingDb
    ? MOCK_COLLECTION_TEMPLATES.filter(t => !q || t.group.toLowerCase().includes(q) || t.album.toLowerCase().includes(q))
    : [];

  const openDbTemplate = (t) => { setSelectedTemplate(t); setSelectedMock(null); setDuplicateErr(null); setStep("preview"); };
  const openMockTemplate = (t) => { setSelectedMock(t); setSelectedTemplate(null); const initSlots = t.cards.map((name,i)=>({id:i,name,status:"missing"})); setSlots(initSlots); setStep("slots"); };

  const cycleStatus = (id) => {
    const order = ["missing", "owned", "wishlist", "dupe", "tradeable"];
    setSlots(s => s.map(slot => slot.id === id ? { ...slot, status: order[(order.indexOf(slot.status) + 1) % order.length] } : slot));
  };

  // Legacy: save mock-template binder (slots flow)
  const saveBinder = async () => {
    if (saving || !selectedMock) return;
    setSaving(true);
    const d = await api.post('/api/binders', {
      name: `${selectedMock.group} — ${selectedMock.album}`,
      group_name: selectedMock.group,
      cover_color: selectedMock.color,
      emoji: selectedMock.emoji,
    });
    if (d?.binder?.id) {
      const binderId = d.binder.id;
      await Promise.all(slots.map(slot =>
        api.post('/api/cards', {
          binder_id: binderId,
          group_name: selectedMock.group,
          album: selectedMock.album,
          era: selectedMock.era,
          member: slot.name,
          status: BINDER_STATUS_TO_DB[slot.status] || 'missing',
        })
      ));
      ls.set('backstage_has_binder', true);
      if (onCreatedBinder) onCreatedBinder(d.binder);
      else { setSaved(true); setTimeout(() => onBack(), 1200); }
    } else {
      setSaving(false);
    }
  };

  // DB template path: create binder from template via API
  const createFromTemplate = async () => {
    if (saving || !selectedTemplate) return;
    setSaving(true); setDuplicateErr(null);
    const d = await api.post('/api/binders/from-template', { template_id: selectedTemplate.id });
    if (d?.binder) {
      ls.set('backstage_has_binder', true);
      if (onCreatedBinder) onCreatedBinder(d.binder);
      else { setSaved(true); setTimeout(() => onBack(), 1200); }
    } else if (d?.existing_binder_id) {
      setDuplicateErr(`You already have a binder for ${selectedTemplate.group_name} — ${selectedTemplate.album_name}.`);
      setSaving(false);
    } else {
      setSaving(false);
    }
  };

  const STATUS_COLORS = { missing: C.textDim, owned: C.mint, wishlist: C.accent, dupe: C.gold, tradeable: C.rose };
  const STATUS_LABELS = { missing: "—", owned: "✓", wishlist: "♡", dupe: "×2", tradeable: "⇄" };

  if (saved) return (
    <div style={{ flex:1, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", padding:40, textAlign:"center" }}>
      <div style={{ fontSize:52, marginBottom:16, animation:"burst .4s ease" }}>🎉</div>
      <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:22, marginBottom:8 }}>Binder Created!</p>
      <p style={{ fontSize:13, color:C.textMid }}>Your {(selectedMock||selectedTemplate)?.group_name||(selectedMock?.group)} collection is ready to track.</p>
    </div>
  );

  // DB template preview step
  if (step === "preview" && selectedTemplate) {
    const STATUS_CHIP_META = { backstage:'Backstage Template', fan_submitted:'Fan-Submitted · Needs review', verified:'Verified Template', in_progress:'In Progress' };
    const COMPLETENESS_CHIP = { complete:{ label:'Complete', color:C.mint }, may_include_gaps:{ label:'May include gaps', color:C.gold }, partial:{ label:'Partial', color:C.gold }, unknown:{ label:'Unknown', color:C.textMid } };
    const cComp = COMPLETENESS_CHIP[selectedTemplate.completeness] || COMPLETENESS_CHIP.unknown;
    return (
      <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
        <div style={{ padding:"16px 20px 14px", flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
          <button onClick={()=>setStep("search")} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:18 }}>Template Preview</h2>
        </div>
        <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>
          {/* Hero */}
          <div style={{ background:`linear-gradient(140deg,${selectedTemplate.cover_color||C.accent}18,${selectedTemplate.cover_color||C.accent}06)`, border:`1.5px solid ${selectedTemplate.cover_color||C.accent}33`, borderRadius:22, padding:20, marginBottom:16, position:"relative", overflow:"hidden" }}>
            <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${selectedTemplate.cover_color||C.accent}44,transparent)` }} />
            <div style={{ display:"flex", gap:14, alignItems:"center", marginBottom:14 }}>
              <div style={{ width:60,height:60,borderRadius:18,background:`${selectedTemplate.cover_color||C.accent}22`,border:`1.5px solid ${selectedTemplate.cover_color||C.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,flexShrink:0 }}>{selectedTemplate.cover_emoji||"🃏"}</div>
              <div style={{ flex:1,minWidth:0 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:C.text,lineHeight:1.2,marginBottom:3 }}>{selectedTemplate.album_name}</p>
                <p style={{ fontSize:12,color:C.textMid }}>{selectedTemplate.group_name}{selectedTemplate.era&&selectedTemplate.era!==selectedTemplate.album_name?` · ${selectedTemplate.era}`:""}{selectedTemplate.release_year?` · ${selectedTemplate.release_year}`:""}</p>
              </div>
            </div>
            <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:10 }}>
              <div style={{ ...VS.activePill(selectedTemplate.cover_color||C.accent), fontSize:9 }}>{STATUS_CHIP_META[selectedTemplate.status]||selectedTemplate.status}</div>
              <div style={{ ...VS.activePill(cComp.color), fontSize:9 }}>⚠ {cComp.label}</div>
              <div style={{ ...VS.activePill(C.silver), fontSize:9 }}>🃏 {selectedTemplate.card_count} cards</div>
            </div>
            {/* Stats row */}
            <div style={{ display:"flex", gap:0, background:`${C.bg}55`, borderRadius:14, overflow:"hidden" }}>
              {[{val:selectedTemplate.card_count,label:"Cards"},{val:selectedTemplate.release_year||"—",label:"Year"},{val:selectedTemplate.last_updated_fmt||"—",label:"Updated"}].map((s,i)=>(
                <div key={s.label} style={{ flex:1,textAlign:"center",padding:"10px 4px",borderRight:i<2?`1px solid ${C.border}`:"none" }}>
                  <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16,color:selectedTemplate.cover_color||C.accent,lineHeight:1 }}>{s.val}</p>
                  <p style={{ fontSize:9,color:C.textMid,marginTop:2 }}>{s.label}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Honesty note */}
          <div style={{ background:`${C.gold}0a`, border:`1px solid ${C.gold}28`, borderRadius:14, padding:"10px 14px", marginBottom:16, display:"flex", gap:8, alignItems:"flex-start" }}>
            <span style={{ fontSize:14, flexShrink:0 }}>⚠</span>
            <div>
              <p style={{ fontSize:10.5, color:C.gold, fontFamily:"'Epilogue',sans-serif", fontWeight:700, marginBottom:2 }}>May include gaps</p>
              <p style={{ fontSize:10.5, color:C.textMid, lineHeight:1.55 }}>{selectedTemplate.notes||"This template may not include every POB, lucky draw, fansign, or store-exclusive card. Add missing cards manually."}</p>
            </div>
          </div>

          {duplicateErr && (
            <div style={{ background:`${C.rose}10`,border:`1.5px solid ${C.rose}33`,borderRadius:14,padding:"10px 14px",marginBottom:14 }}>
              <p style={{ fontSize:11.5, color:C.rose }}>{duplicateErr}</p>
              <p style={{ fontSize:10.5, color:C.textMid, marginTop:3 }}>Find it in your Albums tab to open it.</p>
            </div>
          )}

          <Btn onClick={createFromTemplate} disabled={saving}>{saving?"Creating...":"Create Binder from Template ✦"}</Btn>
          <p style={{ textAlign:"center", fontSize:10.5, color:C.textDim, marginTop:10 }}>All cards will be set to Missing. Open the binder to mark what you own.</p>
        </Screen>
      </div>
    );
  }

  if (step === "slots" && selectedMock) return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"16px 20px 14px", flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={()=>setStep("search")} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div style={{ flex:1 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:16, lineHeight:1.2 }}>{selectedMock.group} — {selectedMock.album}</p>
          <p style={{ fontSize:11, color:C.textMid }}>{slots.filter(s=>s.status==="owned").length}/{slots.length} owned · tap cards to cycle status</p>
        </div>
      </div>
      <div style={{ padding:"0 6px 6px", display:"flex", gap:6, flexWrap:"wrap", flexShrink:0, justifyContent:"center" }}>
        {Object.entries(STATUS_LABELS).map(([s,l])=>(
          <div key={s} style={{ display:"flex", alignItems:"center", gap:4 }}>
            <div style={{ width:18,height:18,borderRadius:6,background:STATUS_COLORS[s],display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,color:C.bg,fontWeight:800 }}>{l}</div>
            <p style={{ fontSize:9, color:C.textMid }}>{s}</p>
          </div>
        ))}
      </div>
      <Screen style={{ padding:"8px 18px calc(120px + env(safe-area-inset-bottom))" }}>
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:9 }}>
          {slots.map(slot => (
            <button key={slot.id} onClick={()=>cycleStatus(slot.id)} className="tap" style={{
              padding:"12px 10px", borderRadius:18,
              background:`linear-gradient(150deg,${STATUS_COLORS[slot.status]}14,${STATUS_COLORS[slot.status]}06)`,
              border:`1.5px solid ${STATUS_COLORS[slot.status]}${slot.status==="missing"?"22":"44"}`,
              textAlign:"left", cursor:"pointer",
              boxShadow:`0 4px 12px ${STATUS_COLORS[slot.status]}08`,
              position:"relative", overflow:"hidden",
            }}>
              <div style={{ position:"absolute",top:-10,right:-10,width:40,height:40,borderRadius:"50%",background:`radial-gradient(circle,${STATUS_COLORS[slot.status]}18,transparent 65%)`,pointerEvents:"none" }} />
              <div style={{ display:"flex", alignItems:"center", gap:7, marginBottom:4 }}>
                <div style={{ width:22,height:22,borderRadius:7,background:STATUS_COLORS[slot.status],display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:slot.status==="missing"?C.textMid:C.bg,fontWeight:800,flexShrink:0 }}>{STATUS_LABELS[slot.status]}</div>
                <p style={{ fontSize:10.5, fontFamily:"'Epilogue',sans-serif", fontWeight:700, color:slot.status==="missing"?C.textMid:C.text, lineHeight:1.3 }}>{slot.name}</p>
              </div>
            </button>
          ))}
        </div>
        <div style={{ height:20 }} />
        <div style={{ background:`linear-gradient(140deg,${selectedMock.color}10,${selectedMock.color}04)`, border:`1.5px solid ${selectedMock.color}28`, borderRadius:22, padding:18, marginBottom:10, textAlign:"center" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:15,marginBottom:6 }}>Collection Summary</p>
          <div style={{ display:"flex", gap:14, justifyContent:"center", marginBottom:14 }}>
            {[["owned",C.mint],["wishlist",C.accent],["dupe",C.gold],["tradeable",C.rose],["missing",C.textDim]].map(([s,col])=>(
              <div key={s} style={{ textAlign:"center" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:col }}>{slots.filter(x=>x.status===s).length}</p>
                <p style={{ fontSize:9,color:C.textMid }}>{s}</p>
              </div>
            ))}
          </div>
          <ProgressBar value={(slots.filter(s=>s.status==="owned").length/slots.length)*100} color={selectedMock.color} />
        </div>
        <Btn onClick={saveBinder} disabled={saving}>{saving?"Saving...":"Save Binder ✦"}</Btn>
      </Screen>
    </div>
  );

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"16px 20px 14px", flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:19 }}>Start a Binder</h2>
      </div>
      <Screen style={{ padding:"0 18px calc(120px + env(safe-area-inset-bottom))" }}>
        <p style={{ fontSize:12, color:C.textMid, marginBottom:12, lineHeight:1.6 }}>Choose an album template to create a binder, or build a custom one for any group.</p>
        <Input value={groupSearch} onChange={e=>setGroupSearch(e.target.value)} placeholder="Search group or album..." style={{ marginBottom:14 }} />

        {/* Loading indicator */}
        {dbLoading && <p style={{ textAlign:"center", fontSize:12, color:C.textMid, padding:"12px 0" }}>Loading templates...</p>}

        {/* DB templates */}
        {!dbLoading && showingDb && (
          <>
            {!dbError && <p style={{ fontSize:9.5, color:C.textDim, marginBottom:10, fontFamily:"'Epilogue',sans-serif", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.08em" }}>Backstage Starter Templates</p>}
            <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:14 }}>
              {(filteredDb.length ? filteredDb : dbTemplates).map(t => {
                const col = t.cover_color || C.accent;
                return (
                  <button key={t.id} onClick={()=>openDbTemplate(t)} className="tap" style={{ padding:"14px 16px", borderRadius:22, textAlign:"left", cursor:"pointer", ...VS.glowCard(col) }}>
                    <div style={VS.shimmerLine(col)} />
                    <div style={VS.innerGlow(col)} />
                    <div style={{ display:"flex", alignItems:"center", gap:12, position:"relative" }}>
                      <div style={{ width:50,height:50,borderRadius:15,background:`${col}20`,border:`1.5px solid ${col}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0 }}>{t.cover_emoji||"🃏"}</div>
                      <div style={{ flex:1,minWidth:0 }}>
                        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14.5,color:C.text,marginBottom:2 }}>{t.group_name}</p>
                        <p style={{ fontSize:11.5,color:C.textMid,marginBottom:5 }}>{t.album_name}</p>
                        <div style={{ display:"flex",gap:5,flexWrap:"wrap",alignItems:"center" }}>
                          <div style={{ ...VS.activePill(col),fontSize:8 }}>{t.status_label||t.status}</div>
                          <div style={{ ...VS.activePill(C.gold),fontSize:8 }}>⚠ {t.completeness_label||"May include gaps"}</div>
                          <div style={{ ...VS.activePill(C.silver),fontSize:8 }}>{t.card_count} cards</div>
                        </div>
                      </div>
                      <span style={{ color:col,fontSize:18,flexShrink:0 }}>→</span>
                    </div>
                  </button>
                );
              })}
              {filteredDb.length===0 && groupSearch && <p style={{ fontSize:12,color:C.textMid,textAlign:"center",padding:"10px 0" }}>No templates match "{groupSearch}"</p>}
            </div>
          </>
        )}

        {/* Mock fallback (when DB unavailable) */}
        {!dbLoading && !showingDb && (
          <>
            <p style={{ fontSize:9.5, color:C.textDim, marginBottom:10, fontFamily:"'Epilogue',sans-serif", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.08em" }}>Starter Templates</p>
            <div style={{ display:"flex", flexDirection:"column", gap:10, marginBottom:14 }}>
              {filteredMock.map(t => (
                <button key={t.id} onClick={()=>openMockTemplate(t)} className="tap" style={{ padding:"14px 16px", borderRadius:22, textAlign:"left", cursor:"pointer", ...VS.glowCard(t.color) }}>
                  <div style={VS.shimmerLine(t.color)} />
                  <div style={VS.innerGlow(t.color)} />
                  <div style={{ display:"flex", alignItems:"center", gap:12, position:"relative" }}>
                    <div style={{ width:50,height:50,borderRadius:15,background:`${t.color}20`,border:`1.5px solid ${t.color}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:24,flexShrink:0 }}>{t.emoji}</div>
                    <div style={{ flex:1 }}>
                      <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14.5,color:C.text,marginBottom:2 }}>{t.group}</p>
                      <p style={{ fontSize:11.5,color:C.textMid,marginBottom:5 }}>{t.album}</p>
                      <div style={{ display:"flex",gap:5 }}>
                        <div style={{ ...VS.activePill(t.color),fontSize:8 }}>{t.total} cards</div>
                        <div style={{ ...VS.activePill(C.gold),fontSize:8 }}>⚠ May include gaps</div>
                      </div>
                    </div>
                    <span style={{ color:t.color,fontSize:18 }}>→</span>
                  </div>
                </button>
              ))}
            </div>
          </>
        )}

        {/* Custom binder CTA */}
        <div style={{ background:`${C.accent}0a`, border:`1.5px dashed ${C.border}`, borderRadius:22, padding:18, textAlign:"center" }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13, marginBottom:4 }}>Any other group?</p>
          <p style={{ fontSize:11, color:C.textMid, marginBottom:12 }}>Create a custom binder for any group, era, or set not listed above.</p>
          <Btn ghost color={C.accent} small onClick={onCustom}>+ Create Custom Binder</Btn>
        </div>
      </Screen>
    </div>
  );
}

// ─── CUSTOM BINDER FORM ───────────────────────────────────────────────────────
function CustomBinderForm({ onBack, onSaved }) {
  const [form, setForm] = useState({ name:"", group_name:"", emoji:"🃏", cover_color:C.accent });
  const [saving, setSaving] = useState(false);
  const EMOJI_OPTIONS = ["🃏","💜","🖤","⭐","💛","🌸","🎤","💙","🌟","🎭","✨","🔥"];
  const COLOR_OPTIONS = [C.accent, C.pink, C.mint, C.gold, C.rose, C.sky, C.silver, C.lavender];

  const save = async () => {
    if (!form.name.trim() || saving) return;
    setSaving(true);
    const d = await api.post('/api/binders', form);
    if (d?.binder) { ls.set('backstage_has_binder', true); onSaved(d.binder); }
    else setSaving(false);
  };

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 12px", flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:18 }}>Custom Binder</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>
        <div style={{ display:"flex", flexDirection:"column", gap:16 }}>
          <Input label="Binder Name *" value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="e.g. My SKZ Collection" />
          <Input label="Group (optional)" value={form.group_name} onChange={e=>setForm(f=>({...f,group_name:e.target.value}))} placeholder="e.g. Stray Kids" />

          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Icon</p>
            <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
              {EMOJI_OPTIONS.map(e=>(
                <button key={e} onClick={()=>setForm(f=>({...f,emoji:e}))} style={{ width:40,height:40,borderRadius:12,background:form.emoji===e?`${C.accent}22`:"transparent",border:`1.5px solid ${form.emoji===e?C.accent:C.border}`,fontSize:20,cursor:"pointer" }}>{e}</button>
              ))}
            </div>
          </div>

          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Color</p>
            <div style={{ display:"flex", gap:8 }}>
              {COLOR_OPTIONS.map(col=>(
                <button key={col} onClick={()=>setForm(f=>({...f,cover_color:col}))} style={{ width:30,height:30,borderRadius:"50%",background:col,border:`3px solid ${form.cover_color===col?"white":"transparent"}`,cursor:"pointer",transition:"border-color .15s" }} />
              ))}
            </div>
          </div>

          <div style={{ background:`linear-gradient(140deg,${form.cover_color}18,${form.cover_color}06)`,border:`1.5px solid ${form.cover_color}44`,borderRadius:18,padding:16,display:"flex",gap:12,alignItems:"center" }}>
            <div style={{ width:52,height:52,borderRadius:16,background:`${form.cover_color}22`,border:`1.5px solid ${form.cover_color}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26 }}>{form.emoji||"🃏"}</div>
            <div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14.5,color:C.text }}>{form.name||"Binder Name"}</p>
              <p style={{ fontSize:11,color:C.textMid }}>{form.group_name||"Custom collection"}</p>
            </div>
          </div>

          <Btn onClick={save} disabled={saving||!form.name.trim()}>{saving?"Creating...":"Create Binder ✦"}</Btn>
        </div>
      </Screen>
    </div>
  );
}

// ─── ADD CARD FORM ─────────────────────────────────────────────────────────────
function AddCardForm({ binder, onBack, onSaved }) {
  const STATUSES = ["owned","missing","iso","duplicate","for_trade"];
  const STATUS_LABELS = {owned:"✓ Owned",missing:"— Missing",iso:"♡ ISO",duplicate:"×2 Duplicate",for_trade:"⇄ For Trade"};
  const STATUS_COLORS = {owned:C.mint,missing:C.textDim,iso:C.accent,duplicate:C.gold,for_trade:C.rose};

  const [form, setForm] = useState({ group_name:binder?.group_name||"", member:"", album:binder?.name||"", era:"", version:"", condition:"mint", status:"owned", notes:"" });
  const [photoFile, setPhotoFile] = useState(null);
  const [photoPreview, setPhotoPreview] = useState(null);
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");
  const photoRef = useRef(null);

  const update = k => e => setForm(f=>({...f,[k]:e.target.value}));

  const handlePhoto = (e) => {
    const f = e.target.files[0]; if(!f) return;
    setPhotoFile(f);
    const r = new FileReader();
    r.onload = ev => setPhotoPreview(ev.target.result);
    r.readAsDataURL(f);
  };

  const save = async () => {
    if (!form.group_name.trim()||!form.member.trim()) { setErr("Group and member name are required."); return; }
    setSaving(true); setErr("");
    try {
      let image_url = null;
      if (photoFile) {
        const urlRes = await api.post('/api/cards/upload-url', { filename: photoFile.name, content_type: photoFile.type });
        if (urlRes?.signed_url) {
          await fetch(urlRes.signed_url, { method:'PUT', body:photoFile, headers:{'Content-Type':photoFile.type} });
          image_url = urlRes.public_url;
        }
      }
      const d = await api.post('/api/cards', { ...form, binder_id: binder?.id, image_url });
      if (d?.card) onSaved(d.card);
      else { setErr("Failed to save. Try again."); setSaving(false); }
    } catch { setErr("Failed to save. Try again."); setSaving(false); }
  };

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 12px",flexShrink:0,display:"flex",alignItems:"center",gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:18 }}>Add Card</h2>
      </div>
      <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>
        <div style={{ display:"flex",flexDirection:"column",gap:14 }}>
          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Photo (optional)</p>
            {photoPreview ? (
              <div style={{ display:"inline-block",position:"relative" }}>
                <img src={photoPreview} alt="card" style={{ width:80,height:110,objectFit:"cover",borderRadius:12,border:`2px solid ${C.accent}66` }} />
                <button onClick={()=>{setPhotoFile(null);setPhotoPreview(null);}} style={{ position:"absolute",top:-8,right:-8,width:20,height:20,borderRadius:"50%",background:C.rose,border:"none",color:C.bg,fontSize:10,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800 }}>×</button>
              </div>
            ) : (
              <button onClick={()=>photoRef.current?.click()} style={{ width:80,height:110,borderRadius:12,background:`${C.accent}10`,border:`2px dashed ${C.accent}44`,color:C.accent,fontSize:9,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4 }}>
                <span style={{ fontSize:22 }}>📸</span><span>Add Photo</span>
              </button>
            )}
            <input ref={photoRef} type="file" accept="image/*" onChange={handlePhoto} style={{ display:"none" }} />
          </div>

          <Input label="Group *" value={form.group_name} onChange={update("group_name")} placeholder="e.g. Stray Kids" />
          <Input label="Member / Card Name *" value={form.member} onChange={update("member")} placeholder="e.g. Felix (Standard)" />
          <Input label="Album / Era" value={form.album} onChange={update("album")} placeholder="e.g. 5-STAR" />
          <Input label="Version / Type" value={form.version} onChange={update("version")} placeholder="e.g. Weverse POB, Lucky Draw..." />

          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Status</p>
            <div style={{ display:"flex",gap:6,flexWrap:"wrap" }}>
              {STATUSES.map(s=>(
                <button key={s} onClick={()=>setForm(f=>({...f,status:s}))} style={{ padding:"7px 12px",borderRadius:99,fontSize:11,fontFamily:"'Epilogue',sans-serif",fontWeight:700,background:form.status===s?STATUS_COLORS[s]:"transparent",color:form.status===s?C.bg:STATUS_COLORS[s],border:`1.5px solid ${STATUS_COLORS[s]}${form.status===s?"":"55"}`,cursor:"pointer" }}>{STATUS_LABELS[s]}</button>
              ))}
            </div>
          </div>

          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Condition</p>
            <div style={{ display:"flex",gap:6 }}>
              {["mint","near_mint","good","played"].map(c=>(
                <button key={c} onClick={()=>setForm(f=>({...f,condition:c}))} style={{ flex:1,padding:"7px 4px",borderRadius:10,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,background:form.condition===c?C.accent:"transparent",color:form.condition===c?C.bg:C.textMid,border:`1.5px solid ${form.condition===c?C.accent:C.border}`,cursor:"pointer",textAlign:"center" }}>{c.replace("_"," ")}</button>
              ))}
            </div>
          </div>

          <Textarea label="Notes (optional)" value={form.notes} onChange={update("notes")} placeholder="e.g. Pulled from unsealed pack, concert freebie..." style={{ height:72 }} />
          {err&&<p style={{ fontSize:11.5,color:C.rose }}>{err}</p>}
          <Btn onClick={save} disabled={saving}>{saving?"Saving...":"Save Card ✦"}</Btn>
        </div>
      </Screen>
    </div>
  );
}

// ─── TRADE LISTING FORM ────────────────────────────────────────────────────────
function TradeListingForm({ card, onBack, onSaved }) {
  const [form, setForm] = useState({ wants_description:"", trade_type:"any", location:"", notes:"" });
  const [proofFile, setProofFile] = useState(null);
  const [proofPreview, setProofPreview] = useState(null);
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");
  const fileRef = useRef(null);

  const update = k => e => setForm(f=>({...f,[k]:e.target.value}));

  const handleFile = (e) => {
    const f = e.target.files[0]; if(!f) return;
    setProofFile(f);
    const r = new FileReader();
    r.onload = ev => setProofPreview(ev.target.result);
    r.readAsDataURL(f);
  };

  const save = async () => {
    if (!proofFile) { setErr("A proof photo is required to list a card for trade."); return; }
    setSaving(true); setErr("");
    try {
      const urlRes = await api.post('/api/cards/upload-url', { filename: proofFile.name, content_type: proofFile.type });
      if (!urlRes?.signed_url) throw new Error("Upload URL failed");
      const uploadResp = await fetch(urlRes.signed_url, { method:"PUT", body:proofFile, headers:{"Content-Type":proofFile.type} });
      if (!uploadResp.ok) throw new Error("Upload failed");
      const d = await api.post('/api/trade-listings', { card_id:card.id, proof_image_url:urlRes.public_url, ...form });
      if (d?.listing) onSaved(d.listing);
      else throw new Error("Listing failed");
    } catch {
      setErr("Something went wrong. Try again.");
      setSaving(false);
    }
  };

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 12px",flexShrink:0,display:"flex",alignItems:"center",gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:18 }}>List for Trade</h2>
          <p style={{ fontSize:10.5,color:C.textMid }}>{card.group_name} · {card.member}</p>
        </div>
      </div>
      <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>
        <div style={{ background:`linear-gradient(140deg,${C.rose}18,${C.rose}06)`,border:`1.5px solid ${C.rose}33`,borderRadius:18,padding:"12px 14px",marginBottom:16,display:"flex",gap:10,alignItems:"center" }}>
          <span style={{ fontSize:22 }}>🃏</span>
          <div>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5,color:C.text }}>{card.member}</p>
            <p style={{ fontSize:11,color:C.textMid }}>{card.group_name} · {card.album||card.era||""} · {card.condition}</p>
          </div>
        </div>
        <div style={{ display:"flex",flexDirection:"column",gap:14 }}>
          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:6,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Proof Photo <span style={{ color:C.rose }}>*</span></p>
            <p style={{ fontSize:11,color:C.textMid,marginBottom:10,lineHeight:1.55 }}>Real photo of your card. Write your @handle + today's date in the shot — not a template image.</p>
            {proofPreview?(
              <div style={{ display:"inline-block",position:"relative" }}>
                <img src={proofPreview} alt="proof" style={{ width:100,height:130,objectFit:"cover",borderRadius:14,border:`2px solid ${C.rose}66` }} />
                <button onClick={()=>{setProofFile(null);setProofPreview(null);}} style={{ position:"absolute",top:-8,right:-8,width:22,height:22,borderRadius:"50%",background:C.rose,border:"none",color:C.bg,fontSize:12,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",fontWeight:800 }}>×</button>
                <div style={{ ...VS.activePill(C.rose),fontSize:8,marginTop:6 }}>📷 Photo Added</div>
              </div>
            ):(
              <button onClick={()=>fileRef.current?.click()} style={{ width:100,height:130,borderRadius:14,background:`${C.rose}10`,border:`2px dashed ${C.rose}44`,color:C.rose,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:5 }}>
                <span style={{ fontSize:26 }}>📸</span>Add Photo
              </button>
            )}
            <input ref={fileRef} type="file" accept="image/*" onChange={handleFile} style={{ display:"none" }} />
          </div>

          <Textarea label="What you want (optional)" value={form.wants_description} onChange={update("wants_description")} placeholder="e.g. Jimin FACE, any aespa Karina, open offers..." style={{ height:72 }} />

          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Trade Type</p>
            <div style={{ display:"flex",gap:6 }}>
              {[["any","Any"],["mail","Mail"],["local","Local"],["concert","Concert"]].map(([v,l])=>(
                <button key={v} onClick={()=>setForm(f=>({...f,trade_type:v}))} style={{ flex:1,padding:"8px 4px",borderRadius:10,fontSize:10.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,background:form.trade_type===v?C.accent:"transparent",color:form.trade_type===v?C.bg:C.textMid,border:`1.5px solid ${form.trade_type===v?C.accent:C.border}`,cursor:"pointer",textAlign:"center" }}>{l}</button>
              ))}
            </div>
          </div>

          <Input label="Location (city, optional)" value={form.location} onChange={update("location")} placeholder="e.g. Dallas, TX" />
          <Textarea label="Notes (optional)" value={form.notes} onChange={update("notes")} placeholder="e.g. Ships Monday, PWG preferred..." style={{ height:60 }} />

          <div style={{ background:`${C.gold}0a`,border:`1px solid ${C.gold}22`,borderRadius:14,padding:"10px 14px",display:"flex",gap:8,alignItems:"flex-start" }}>
            <span style={{ fontSize:14,flexShrink:0 }}>🛡️</span>
            <p style={{ fontSize:10.5,color:C.textMid,lineHeight:1.6 }}>Never share your full address publicly. Exchange shipping info only after both sides agree.</p>
          </div>

          {err&&<p style={{ fontSize:11.5,color:C.rose }}>{err}</p>}
          <Btn onClick={save} disabled={saving}>{saving?"Uploading...":"Publish Listing ✦"}</Btn>
        </div>
      </Screen>
    </div>
  );
}

// ─── BINDER DETAIL ─────────────────────────────────────────────────────────────
function BinderDetail({ binder, onBack }) {
  const STATUS_ORDER = ["owned","missing","iso","duplicate","for_trade"];
  const STATUS_META  = {
    owned:     { label:"✓",  color:C.mint,    badge:"Owned"     },
    missing:   { label:"—",  color:C.textDim, badge:"Missing"   },
    iso:       { label:"♡",  color:C.accent,  badge:"ISO"       },
    duplicate: { label:"×2", color:C.gold,    badge:"Dupe"      },
    for_trade: { label:"⇄",  color:C.rose,    badge:"For Trade" },
  };

  const [cards, setCards]               = useState([]);
  const [loading, setLoading]           = useState(true);
  const [showAddCard, setShowAddCard]   = useState(false);
  const [tradingCard, setTradingCard]   = useState(null);

  useEffect(() => {
    api.get(`/api/cards?binder_id=${binder.id}`)
      .then(d => { setCards(d?.cards || []); setLoading(false); });
  }, [binder.id]);

  const cycleStatus = async (card) => {
    const next = STATUS_ORDER[(STATUS_ORDER.indexOf(card.status)+1) % STATUS_ORDER.length];
    setCards(cs => cs.map(c => c.id===card.id ? {...c,status:next} : c));
    api.patch(`/api/cards/${card.id}`, { status:next });
  };

  const deleteCard = (cardId) => {
    setCards(cs => cs.filter(c => c.id !== cardId));
    api.del(`/api/cards/${cardId}`).catch(()=>{});
  };

  if (showAddCard) return <AddCardForm binder={binder} onBack={()=>setShowAddCard(false)} onSaved={card=>{ setCards(cs=>[card,...cs]); setShowAddCard(false); }} />;
  if (tradingCard) return <TradeListingForm card={tradingCard} onBack={()=>setTradingCard(null)} onSaved={()=>{ setTradingCard(null); setCards(cs=>cs.map(c=>c.id===tradingCard.id?{...c,status:'for_trade'}:c)); }} />;

  const owned    = cards.filter(c=>c.status==='owned').length;
  const dupes    = cards.filter(c=>c.status==='duplicate').length;
  const missing  = cards.filter(c=>c.status==='missing').length;
  const forTrade = cards.filter(c=>c.status==='for_trade').length;
  const pct      = cards.length ? Math.round((owned/cards.length)*100) : 0;

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 10px",flexShrink:0,display:"flex",alignItems:"center",gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div style={{ flex:1,minWidth:0 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:15,lineHeight:1.2 }}>{binder.emoji||"🃏"} {binder.name}</p>
          <p style={{ fontSize:10,color:C.textMid }}>{owned}/{cards.length} owned · {dupes} dupes · {missing} missing</p>
        </div>
        <button onClick={()=>setShowAddCard(true)} style={{ background:`linear-gradient(140deg,${C.accent}cc,${C.accentDim})`,border:"none",borderRadius:11,padding:"8px 13px",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:10.5,cursor:"pointer",flexShrink:0 }}>+ Add</button>
      </div>

      {/* Legend */}
      <div style={{ padding:"0 20px 8px",display:"flex",gap:8,flexWrap:"wrap",flexShrink:0,alignItems:"center" }}>
        {Object.entries(STATUS_META).map(([s,m])=>(
          <div key={s} style={{ display:"flex",alignItems:"center",gap:3 }}>
            <div style={{ width:18,height:18,borderRadius:6,background:m.color,display:"flex",alignItems:"center",justifyContent:"center",fontSize:9,color:s==="missing"?C.textMid:C.bg,fontWeight:800 }}>{m.label}</div>
            <p style={{ fontSize:9,color:C.textMid }}>{m.badge}</p>
          </div>
        ))}
        <p style={{ fontSize:9,color:C.textDim,marginLeft:"auto" }}>tap to cycle</p>
      </div>

      <Screen style={{ padding:"0 18px calc(120px + env(safe-area-inset-bottom))" }}>
        {loading && <div style={{ textAlign:"center",padding:40,color:C.textMid,fontSize:13 }}>Loading...</div>}

        {!loading && cards.length===0 && (
          <div style={{ textAlign:"center",padding:"40px 20px" }}>
            <p style={{ fontSize:36,marginBottom:12 }}>🃏</p>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:15,marginBottom:6 }}>No cards yet</p>
            <p style={{ fontSize:12,color:C.textMid,marginBottom:20 }}>Tap + Add to start tracking your collection.</p>
            <Btn small onClick={()=>setShowAddCard(true)}>+ Add First Card</Btn>
          </div>
        )}

        {!loading && cards.length>0 && (
          <>
            <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,paddingTop:4 }}>
              {cards.map(card=>{
                const meta = STATUS_META[card.status]||STATUS_META.missing;
                return (
                  <div key={card.id} style={{ position:"relative" }}>
                    <button onClick={()=>cycleStatus(card)} style={{
                      width:"100%",padding:"12px 10px",borderRadius:18,textAlign:"left",cursor:"pointer",
                      background:`linear-gradient(150deg,${meta.color}14,${meta.color}06)`,
                      border:`1.5px solid ${meta.color}${card.status==="missing"?"22":"44"}`,
                      boxShadow:`0 4px 12px ${meta.color}08`,position:"relative",overflow:"hidden",
                    }}>
                      <div style={{ position:"absolute",top:-10,right:-10,width:40,height:40,borderRadius:"50%",background:`radial-gradient(circle,${meta.color}18,transparent 65%)`,pointerEvents:"none" }} />
                      <div style={{ display:"flex",alignItems:"center",gap:7,marginBottom:card.version?4:0 }}>
                        <div style={{ width:22,height:22,borderRadius:7,background:meta.color,display:"flex",alignItems:"center",justifyContent:"center",fontSize:10,color:card.status==="missing"?C.textMid:C.bg,fontWeight:800,flexShrink:0 }}>{meta.label}</div>
                        <p style={{ fontSize:10.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,color:card.status==="missing"?C.textMid:C.text,lineHeight:1.3 }}>{card.member}</p>
                      </div>
                      {card.version&&<p style={{ fontSize:9,color:C.textDim,marginLeft:29 }}>{card.version}</p>}
                    </button>
                    {card.status==="for_trade"&&(
                      <button onClick={()=>setTradingCard(card)} style={{ position:"absolute",bottom:6,right:6,background:C.rose,border:"none",borderRadius:7,padding:"3px 7px",color:C.bg,fontSize:8.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer" }}>List →</button>
                    )}
                    <button onClick={e=>{e.stopPropagation();deleteCard(card.id);}} style={{ position:"absolute",top:-5,right:-5,width:18,height:18,borderRadius:"50%",background:C.surfaceMid,border:`1.5px solid ${C.border}`,color:C.textDim,fontSize:9,cursor:"pointer",zIndex:5,display:"flex",alignItems:"center",justifyContent:"center",padding:0 }}>✕</button>
                  </div>
                );
              })}
            </div>

            {/* Summary */}
            <div style={{ marginTop:16,background:`linear-gradient(140deg,${binder.cover_color||C.accent}10,${binder.cover_color||C.accent}04)`,border:`1.5px solid ${binder.cover_color||C.accent}28`,borderRadius:22,padding:18,textAlign:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,marginBottom:10 }}>Collection Summary</p>
              <div style={{ display:"flex",gap:0 }}>
                {[{val:owned,label:"Owned",color:C.mint},{val:forTrade,label:"For Trade",color:C.rose},{val:dupes,label:"Dupes",color:C.gold},{val:missing,label:"Missing",color:C.textDim}].map((s,i)=>(
                  <div key={s.label} style={{ flex:1,textAlign:"center",borderRight:i<3?`1px solid ${C.border}`:"none" }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:20,color:s.color,lineHeight:1 }}>{s.val}</p>
                    <p style={{ fontSize:8.5,color:C.textMid,marginTop:2 }}>{s.label}</p>
                  </div>
                ))}
              </div>
              <div style={{ marginTop:12 }}>
                <ProgressBar value={pct} color={binder.cover_color||C.accent} />
                <p style={{ fontSize:9,color:binder.cover_color||C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,marginTop:5 }}>{pct}% complete</p>
              </div>
            </div>
          </>
        )}
      </Screen>
    </div>
  );
}

// ─── TRADE HUB ────────────────────────────────────────────────────────────────
// POST /api/trades/start | PATCH /api/trades/:id/status | POST /api/trades/:id/review | GET /api/trades/:userId
// localStorage: backstage_active_trades | backstage_trade_history | backstage_trade_reviews
// ─── TRADE STAGE BADGE ────────────────────────────────────────────────────────
const TRADE_STAGE_META = {
  match:    { label:"Match Found",   color:C.accent, icon:"✨" },
  offer:    { label:"Offer Sent",    color:C.sky,    icon:"📤" },
  waiting:  { label:"Waiting",       color:C.gold,   icon:"⏳" },
  accepted: { label:"Accepted",      color:C.mint,   icon:"✓"  },
  shipped:  { label:"Shipped",       color:C.pink,   icon:"📦" },
  confirm:  { label:"Confirming",    color:C.rose,   icon:"🔍" },
  done:     { label:"Complete",      color:C.gold,   icon:"🏅" },
  rate:     { label:"Rate Trader",   color:C.gold,   icon:"⭐" },
};

// ─── TRADE LISTING DETAIL ─────────────────────────────────────────────────────
// View a single public listing. Lister sees manage controls. Others see "Make Offer".
function TradeListingDetail({ listing, onBack, user, onOfferMade }) {
  const [showOffer, setShowOffer] = useState(false);
  const [showReport, setShowReport] = useState(false);
  const [reportReason, setReportReason] = useState("");
  const [reportNote, setReportNote] = useState("");
  const [reportSent, setReportSent] = useState(false);
  const [cancelling, setCancelling] = useState(false);
  const [cancelled, setCancelled] = useState(false);

  const uc  = listing.user_cards || {};
  const trader = listing.users || {};
  const isOwner = user?.id === listing.user_id;
  const col = C.rose;

  const cancelListing = async () => {
    setCancelling(true);
    await api.patch(`/api/trade-listings/${listing.id}`, { status:'cancelled' });
    setCancelled(true);
  };

  const submitReport = async () => {
    if (!reportReason) return;
    await api.post('/api/listing-reports', { listing_id: listing.id, reported_user_id: listing.user_id, reason: reportReason, notes: reportNote });
    setReportSent(true);
  };

  if (showOffer) return <MakeOfferForm listing={listing} user={user} onBack={()=>setShowOffer(false)} onSaved={(offer)=>{ setShowOffer(false); onOfferMade?.(offer); onBack(); }} />;

  const REPORT_REASONS = [
    ["wrong_card","Wrong card / not as described"],
    ["stolen_image","Stolen / stock image"],
    ["fake_listing","Fake listing"],
    ["damaged_not_disclosed","Damage not disclosed"],
    ["duplicate_listing","Duplicate listing"],
    ["suspicious_account","Suspicious account"],
  ];

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 12px", flexShrink:0, display:"flex", alignItems:"center", gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div style={{ flex:1 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:16 }}>Trade Listing</p>
          <p style={{ fontSize:10,color:C.textMid }}>@{trader.username||"fan"}</p>
        </div>
        {!isOwner && !showReport && (
          <button onClick={()=>setShowReport(r=>!r)} style={{ background:"none",border:`1px solid ${C.border}`,borderRadius:9,padding:"5px 10px",color:C.textMid,fontSize:10,cursor:"pointer" }}>⚑ Report</button>
        )}
      </div>

      <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>

        {/* Card info */}
        <div style={{ background:`linear-gradient(140deg,${col}18,${col}06)`, border:`1.5px solid ${col}33`, borderRadius:22, padding:18, marginBottom:16, display:"flex", gap:14, alignItems:"flex-start" }}>
          {listing.proof_image_url ? (
            <img src={listing.proof_image_url} alt="proof" style={{ width:72,height:96,objectFit:"cover",borderRadius:14,border:`2px solid ${col}44`,flexShrink:0 }} />
          ) : (
            <div style={{ width:72,height:96,borderRadius:14,background:`${col}12`,border:`2px dashed ${col}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,flexShrink:0 }}>🃏</div>
          )}
          <div style={{ flex:1,minWidth:0 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:C.text,marginBottom:3 }}>{uc.member||"Card"}</p>
            <p style={{ fontSize:12,color:C.textMid,marginBottom:8 }}>{uc.group_name||""} · {uc.album||uc.era||""}</p>
            <div style={{ display:"flex",gap:6,flexWrap:"wrap" }}>
              {uc.condition&&<div style={{ ...VS.activePill(C.mint),fontSize:9 }}>{uc.condition}</div>}
              <div style={{ ...VS.activePill(col),fontSize:9 }}>{listing.trade_type==="any"?"Any trade":listing.trade_type}</div>
              {listing.location&&<div style={{ ...VS.activePill(C.silver),fontSize:9 }}>📍 {listing.location}</div>}
              <div style={{ ...VS.activePill(C.accent),fontSize:9 }}>📷 Proof photo</div>
            </div>
          </div>
        </div>

        {/* Wants */}
        {listing.wants_description && (
          <div style={{ background:`${C.accent}0a`,border:`1px solid ${C.accent}22`,borderRadius:16,padding:"12px 14px",marginBottom:12 }}>
            <p style={{ fontSize:10,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,marginBottom:4 }}>Looking for</p>
            <p style={{ fontSize:13,color:C.text,lineHeight:1.6 }}>{listing.wants_description}</p>
          </div>
        )}

        {/* Notes */}
        {listing.notes && (
          <div style={{ background:`${C.surfaceHi}`,border:`1px solid ${C.border}`,borderRadius:16,padding:"12px 14px",marginBottom:12 }}>
            <p style={{ fontSize:10,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,marginBottom:4 }}>Seller notes</p>
            <p style={{ fontSize:12.5,color:C.text,lineHeight:1.6 }}>{listing.notes}</p>
          </div>
        )}

        {/* Safety reminder */}
        <div style={{ background:`${C.gold}0a`,border:`1px solid ${C.gold}22`,borderRadius:14,padding:"10px 14px",marginBottom:20,display:"flex",gap:8,alignItems:"flex-start" }}>
          <span style={{ fontSize:14,flexShrink:0 }}>🛡️</span>
          <p style={{ fontSize:10.5,color:C.textMid,lineHeight:1.6 }}>Never share your full address in public. Exchange shipping info only after you've agreed to trade in your offer thread.</p>
        </div>

        {/* Report form */}
        {showReport && !reportSent && (
          <div style={{ background:C.surfaceHi,border:`1.5px solid ${C.border}`,borderRadius:18,padding:16,marginBottom:16 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:10 }}>Report Listing</p>
            <div style={{ display:"flex",flexDirection:"column",gap:6,marginBottom:10 }}>
              {REPORT_REASONS.map(([v,l])=>(
                <button key={v} onClick={()=>setReportReason(v)} style={{ padding:"9px 12px",borderRadius:10,textAlign:"left",background:reportReason===v?`${C.rose}18`:"transparent",border:`1.5px solid ${reportReason===v?C.rose:C.border}`,color:reportReason===v?C.rose:C.text,fontSize:11.5,cursor:"pointer" }}>{l}</button>
              ))}
            </div>
            <textarea value={reportNote} onChange={e=>setReportNote(e.target.value)} placeholder="Additional context (optional)..." style={{ width:"100%",height:60,background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:10,color:C.text,fontSize:12,padding:"9px 12px",resize:"none",outline:"none",fontFamily:"'Instrument Sans',sans-serif",marginBottom:10 }} />
            <div style={{ display:"flex",gap:8 }}>
              <Btn ghost color={C.textMid} small onClick={()=>setShowReport(false)}>Cancel</Btn>
              <Btn color={C.rose} small disabled={!reportReason} onClick={submitReport}>Submit Report</Btn>
            </div>
          </div>
        )}
        {reportSent && <div style={{ background:`${C.mint}12`,border:`1px solid ${C.mint}33`,borderRadius:14,padding:"12px 14px",marginBottom:16,textAlign:"center" }}><p style={{ fontSize:12,color:C.mint }}>✓ Report submitted. We'll review it shortly.</p></div>}

        {/* Actions */}
        {!cancelled && isOwner && (
          <div style={{ display:"flex",flexDirection:"column",gap:10 }}>
            <p style={{ fontSize:11,color:C.textMid,textAlign:"center" }}>This is your listing.</p>
            <Btn ghost color={C.rose} disabled={cancelling} onClick={cancelListing}>{cancelling?"Cancelling...":"Cancel Listing"}</Btn>
          </div>
        )}
        {cancelled && <div style={{ textAlign:"center",padding:"12px 0",color:C.textMid,fontSize:12 }}>Listing cancelled.</div>}

        {!isOwner && !cancelled && listing.status==="active" && (
          <Btn color={C.rose} onClick={()=>setShowOffer(true)}>Make Offer ⇄</Btn>
        )}
        {listing.status==="pending" && !isOwner && (
          <p style={{ textAlign:"center",fontSize:12,color:C.textMid,marginTop:8 }}>This listing has a pending offer.</p>
        )}
        {listing.status!=="active" && listing.status!=="pending" && !isOwner && (
          <p style={{ textAlign:"center",fontSize:12,color:C.textMid,marginTop:8 }}>This listing is no longer available.</p>
        )}
      </Screen>
    </div>
  );
}

// ─── MAKE OFFER FORM ──────────────────────────────────────────────────────────
function MakeOfferForm({ listing, user, onBack, onSaved }) {
  const { tokenReady } = useAuth();
  const [myCards, setMyCards] = useState([]);
  const [selectedCard, setSelectedCard] = useState(null);
  const [message, setMessage] = useState("");
  const [saving, setSaving] = useState(false);
  const [err, setErr] = useState("");
  const uc = listing.user_cards || {};

  useEffect(()=>{
    if (!tokenReady) return;
    api.get('/api/cards?status=for_trade').then(d=>setMyCards(d?.cards||[]));
  },[tokenReady]);

  const submit = async () => {
    setSaving(true); setErr("");
    const d = await api.post('/api/listing-offers', { listing_id: listing.id, sender_card_id: selectedCard?.id || null, message: message.trim() || null });
    if (d?.offer) onSaved(d.offer);
    else { setErr(d?.error || "Failed to send offer. Try again."); setSaving(false); }
  };

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden" }}>
      <div style={{ padding:"14px 20px 12px",flexShrink:0,display:"flex",alignItems:"center",gap:10 }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:18 }}>Make Offer</h2>
          <p style={{ fontSize:10.5,color:C.textMid }}>{uc.group_name} · {uc.member}</p>
        </div>
      </div>
      <Screen style={{ padding:"0 20px calc(140px + env(safe-area-inset-bottom))" }}>

        {/* Their card */}
        <div style={{ background:`${C.rose}10`,border:`1.5px solid ${C.rose}33`,borderRadius:16,padding:"12px 14px",marginBottom:16,display:"flex",gap:10,alignItems:"center" }}>
          <span style={{ fontSize:22 }}>🃏</span>
          <div>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13 }}>You want: {uc.member||"this card"}</p>
            <p style={{ fontSize:10.5,color:C.textMid }}>{uc.group_name} · {uc.album||uc.era||""} · {uc.condition}</p>
          </div>
        </div>

        <div style={{ display:"flex",flexDirection:"column",gap:14 }}>
          {/* Select your card to offer (optional) */}
          <div>
            <p style={{ fontSize:10,color:C.textMid,marginBottom:8,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Your card to offer (optional)</p>
            {myCards.length===0 ? (
              <div style={{ background:`${C.accent}0a`,border:`1.5px dashed ${C.border}`,borderRadius:14,padding:"12px 14px",textAlign:"center" }}>
                <p style={{ fontSize:11.5,color:C.textMid }}>No cards marked "For Trade" yet.</p>
                <p style={{ fontSize:10.5,color:C.textDim,marginTop:3 }}>Go to your binder → tap a card → cycle to "For Trade" to add one here.</p>
              </div>
            ) : (
              <div style={{ display:"flex",flexDirection:"column",gap:7 }}>
                <button onClick={()=>setSelectedCard(null)} style={{ padding:"10px 14px",borderRadius:12,textAlign:"left",background:!selectedCard?`${C.accent}18`:"transparent",border:`1.5px solid ${!selectedCard?C.accent:C.border}`,color:C.text,fontSize:12,cursor:"pointer" }}>
                  Open offer — let them pick
                </button>
                {myCards.map(c=>(
                  <button key={c.id} onClick={()=>setSelectedCard(c)} style={{ padding:"10px 14px",borderRadius:12,textAlign:"left",background:selectedCard?.id===c.id?`${C.rose}18`:"transparent",border:`1.5px solid ${selectedCard?.id===c.id?C.rose:C.border}`,color:C.text,fontSize:12,cursor:"pointer",display:"flex",gap:10,alignItems:"center" }}>
                    <span style={{ fontSize:20 }}>🃏</span>
                    <div>
                      <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5 }}>{c.member}</p>
                      <p style={{ fontSize:10.5,color:C.textMid }}>{c.group_name} · {c.album||c.era||""} · {c.condition}</p>
                    </div>
                  </button>
                ))}
              </div>
            )}
          </div>

          <Textarea label="Message (optional)" value={message} onChange={e=>setMessage(e.target.value)} placeholder="Introduce yourself — e.g. I'm in Dallas, open to mail trade, I have matching condition card..." style={{ height:88 }} />

          <div style={{ background:`${C.gold}0a`,border:`1px solid ${C.gold}22`,borderRadius:14,padding:"10px 14px",display:"flex",gap:8,alignItems:"flex-start" }}>
            <span style={{ fontSize:14,flexShrink:0 }}>🛡️</span>
            <p style={{ fontSize:10.5,color:C.textMid,lineHeight:1.6 }}>Only send your card after both of you agree and confirm in your offer thread. Never share personal details outside Backstage.</p>
          </div>

          {err && <p style={{ fontSize:11.5,color:C.rose }}>{err}</p>}
          <Btn onClick={submit} disabled={saving}>{saving?"Sending...":"Send Offer ⇄"}</Btn>
        </div>
      </Screen>
    </div>
  );
}

// ─── OFFER THREAD ─────────────────────────────────────────────────────────────
// Full negotiation view. Works for both lister and sender.
function OfferThread({ offer: initialOffer, user, onBack, onComplete }) {
  const [offer, setOffer]       = useState(initialOffer);
  const [messages, setMessages] = useState([]);
  const [msgDraft, setMsgDraft] = useState("");
  const [sending, setSending]   = useState(false);
  const [actionLoading, setActionLoading] = useState(false);
  const [rating, setRating]     = useState(0);
  const [rateNote, setRateNote] = useState("");
  const [rateDone, setRateDone] = useState(false);
  const [showReport, setShowReport] = useState(false);
  const [reportReason, setReportReason] = useState("");
  const [reportSent, setReportSent] = useState(false);
  const proofRef = useRef(null);
  const msgBottom = useRef(null);

  const listing   = offer.trade_listings || {};
  const listerCard= listing.user_cards || {};
  const senderCard= offer.sender_card  || {};
  const isLister  = user?.id === listing.user_id;
  const isSender  = user?.id === offer.sender_id;
  const otherUser = offer.sender || {};

  const STATUS_META = {
    pending:     { label:"Offer Sent",    color:C.accent, icon:"📤" },
    accepted:    { label:"Accepted ✓",   color:C.mint,   icon:"✓"  },
    declined:    { label:"Declined",      color:C.textMid,icon:"✗"  },
    cancelled:   { label:"Cancelled",     color:C.textMid,icon:"✗"  },
    in_progress: { label:"In Progress",   color:C.sky,    icon:"📦" },
    completed:   { label:"Completed ✦",  color:C.gold,   icon:"🏅" },
    disputed:    { label:"Disputed",      color:C.rose,   icon:"⚑"  },
  };
  const meta = STATUS_META[offer.status] || STATUS_META.pending;

  const STAGE_STEPS = ["pending","accepted","in_progress","completed"];
  const stageIdx = STAGE_STEPS.indexOf(offer.status);

  useEffect(()=>{
    loadMessages();
  },[offer.id]);

  useEffect(()=>{
    msgBottom.current?.scrollIntoView({ behavior:"smooth" });
  },[messages]);

  const loadMessages = async () => {
    const d = await api.get(`/api/listing-offers/${offer.id}/messages`);
    setMessages(d?.messages || []);
  };

  const doAction = async (action, value) => {
    setActionLoading(true);
    const d = await api.patch(`/api/listing-offers/${offer.id}`, { action, value });
    if (d?.ok) {
      // Optimistically update local offer state
      const stateMap = { accept:"accepted", decline:"declined", cancel:"cancelled" };
      if (stateMap[action]) setOffer(o=>({...o, status:stateMap[action]}));
      if (action==="confirm") {
        const field = isSender ? "sender_confirmed" : "lister_confirmed";
        setOffer(o=>{
          const next = {...o, [field]:true};
          const bothConfirmed = next.sender_confirmed && next.lister_confirmed;
          if (bothConfirmed) { next.status = "completed"; onComplete?.(); }
          return next;
        });
      }
      if (action==="sender_tracking") setOffer(o=>({...o, sender_tracking:value}));
      if (action==="lister_tracking") setOffer(o=>({...o, lister_tracking:value}));
    }
    setActionLoading(false);
  };

  const handleProofUpload = async (e, who) => {
    const f = e.target.files[0]; if(!f) return;
    setActionLoading(true);
    const urlRes = await api.post('/api/cards/upload-url', { filename:f.name, content_type:f.type });
    if (!urlRes?.signed_url) { setActionLoading(false); return; }
    await fetch(urlRes.signed_url, { method:"PUT", body:f, headers:{"Content-Type":f.type} });
    await doAction(who==="sender"?"sender_proof":"lister_proof", urlRes.public_url);
    setOffer(o=>({...o, [who==="sender"?"sender_proof_url":"lister_proof_url"]:urlRes.public_url}));
    setActionLoading(false);
  };

  const sendMsg = async () => {
    if (!msgDraft.trim() || sending) return;
    setSending(true);
    const d = await api.post(`/api/listing-offers/${offer.id}/messages`, { body: msgDraft.trim() });
    if (d?.message) setMessages(m=>[...m, d.message]);
    setMsgDraft("");
    setSending(false);
  };

  const submitReview = async () => {
    if (!rating) return;
    const rateeId = isLister ? offer.sender_id : listing.user_id;
    await api.post('/api/trade-reviews', { listing_id: listing.id, ratee_id: rateeId, rating: rating>=4?1:-1, notes: rateNote });
    setRateDone(true);
  };

  const submitReport = async () => {
    if (!reportReason) return;
    await api.post('/api/listing-reports', { listing_id: listing.id, offer_id: offer.id, reported_user_id: isLister?offer.sender_id:listing.user_id, reason: reportReason });
    setReportSent(true); setShowReport(false);
  };

  const REPORT_REASONS = [["wrong_card","Wrong card"],["fake_listing","Fake listing"],["no_send","No-send after agreement"],["damaged_not_disclosed","Damage not disclosed"],["suspicious_account","Suspicious account"]];

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden",background:C.bg }}>
      {/* Header */}
      <div style={{ padding:"14px 20px 10px",display:"flex",gap:10,alignItems:"center",flexShrink:0,borderBottom:`1px solid ${C.border}` }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div style={{ flex:1,minWidth:0 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:15 }}>
            {isLister ? `Offer from @${otherUser.username||"fan"}` : `Your offer`}
          </p>
          <p style={{ fontSize:10,color:C.textMid }}>{listerCard.member} · {listerCard.group_name}</p>
        </div>
        <div style={{ ...VS.activePill(meta.color),fontSize:9 }}>{meta.icon} {meta.label}</div>
      </div>

      <Screen style={{ padding:"0 18px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* Stage stepper */}
        <div style={{ display:"flex",gap:3,alignItems:"center",marginTop:14,marginBottom:16,overflowX:"auto",scrollbarWidth:"none" }}>
          {["Offered","Accepted","In Progress","Complete"].map((label,i)=>(
            <div key={i} style={{ display:"flex",alignItems:"center",flexShrink:0 }}>
              <div style={{ width:i===stageIdx?28:22,height:i===stageIdx?28:22,borderRadius:"50%",background:i<stageIdx?C.mint:i===stageIdx?`linear-gradient(135deg,${C.accent},${C.pink})`:`${C.surfaceHi}`,border:i<stageIdx?`1.5px solid ${C.mint}`:i===stageIdx?"none":`1.5px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:i===stageIdx?10:9,fontFamily:"'Epilogue',sans-serif",fontWeight:800,color:i<=stageIdx?C.bg:C.textDim,boxShadow:i===stageIdx?`0 0 12px ${C.accent}55`:"none",flexShrink:0 }}>
                {i<stageIdx?"✓":i+1}
              </div>
              {i<3&&<div style={{ width:16,height:2,background:i<stageIdx?C.mint:C.border,borderRadius:99,margin:"0 2px" }} />}
            </div>
          ))}
        </div>

        {/* Card swap */}
        {["pending","accepted","in_progress"].includes(offer.status) && (
          <div style={{ display:"flex",gap:10,alignItems:"center",marginBottom:18 }}>
            {/* Lister's card */}
            <div style={{ flex:1,padding:"12px 10px",borderRadius:18,textAlign:"center",...VS.glowCard(C.rose) }}>
              <div style={VS.innerGlow(C.rose)} />
              <div style={{ position:"relative" }}>
                <p style={{ fontSize:8.5,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:4 }}>
                  {isLister?"Your Card":"Their Card"}
                </p>
                {listing.proof_image_url ? (
                  <img src={listing.proof_image_url} alt="card" style={{ width:54,height:72,objectFit:"cover",borderRadius:10,margin:"0 auto 6px",display:"block",border:`1.5px solid ${C.rose}44` }} />
                ) : <div style={{ fontSize:26,marginBottom:6 }}>🃏</div>}
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:12,color:C.text,marginBottom:1 }}>{listerCard.member||"Card"}</p>
                <p style={{ fontSize:9.5,color:C.textMid }}>{listerCard.group_name}</p>
                {isLister && (offer.status==="accepted"||offer.status==="in_progress") && (
                  <div style={{ marginTop:8 }}>
                    {offer.lister_proof_url ? (
                      <div style={{ ...VS.activePill(C.mint),fontSize:8,marginTop:4 }}>📷 Proof added</div>
                    ) : (
                      <button onClick={()=>proofRef.current?.click()} style={{ fontSize:9,background:`${C.rose}18`,border:`1.5px dashed ${C.rose}44`,borderRadius:8,padding:"4px 8px",color:C.rose,cursor:"pointer",fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>+ Proof</button>
                    )}
                    <input ref={proofRef} type="file" accept="image/*" onChange={e=>handleProofUpload(e,"lister")} style={{ display:"none" }} />
                  </div>
                )}
              </div>
            </div>

            <div style={{ flexShrink:0,width:32,height:32,borderRadius:"50%",background:`${C.accent}18`,border:`1.5px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,color:C.accent }}>⇄</div>

            {/* Sender's card / open offer */}
            <div style={{ flex:1,padding:"12px 10px",borderRadius:18,textAlign:"center",...VS.glowCard(senderCard.id?C.accent:C.border) }}>
              <div style={VS.innerGlow(senderCard.id?C.accent:C.border)} />
              <div style={{ position:"relative" }}>
                <p style={{ fontSize:8.5,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:4 }}>
                  {isSender?"Your Offer":"Their Offer"}
                </p>
                {senderCard.id ? (
                  <>
                    <div style={{ fontSize:26,marginBottom:6 }}>🃏</div>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:12,color:C.text,marginBottom:1 }}>{senderCard.member}</p>
                    <p style={{ fontSize:9.5,color:C.textMid }}>{senderCard.group_name}</p>
                    {isSender && (offer.status==="accepted"||offer.status==="in_progress") && (
                      <div style={{ marginTop:8 }}>
                        {offer.sender_proof_url ? (
                          <div style={{ ...VS.activePill(C.mint),fontSize:8,marginTop:4 }}>📷 Proof added</div>
                        ) : (
                          <button onClick={()=>proofRef.current?.click()} style={{ fontSize:9,background:`${C.accent}18`,border:`1.5px dashed ${C.accent}44`,borderRadius:8,padding:"4px 8px",color:C.accent,cursor:"pointer",fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>+ Proof</button>
                        )}
                        <input ref={proofRef} type="file" accept="image/*" onChange={e=>handleProofUpload(e,"sender")} style={{ display:"none" }} />
                      </div>
                    )}
                  </>
                ) : (
                  <>
                    <div style={{ fontSize:26,marginBottom:6 }}>✨</div>
                    <p style={{ fontSize:10,color:C.textMid,lineHeight:1.4 }}>Open offer — you choose what to send</p>
                  </>
                )}
              </div>
            </div>
          </div>
        )}

        {/* Action area */}
        <div style={{ marginBottom:16 }}>
          {/* Lister actions on pending offer */}
          {isLister && offer.status==="pending" && (
            <div style={{ display:"flex",gap:8 }}>
              <Btn color={C.mint} disabled={actionLoading} onClick={()=>doAction("accept")} style={{ flex:1 }}>Accept ✓</Btn>
              <Btn ghost color={C.textMid} disabled={actionLoading} onClick={()=>doAction("decline")} style={{ flex:1 }}>Decline</Btn>
            </div>
          )}

          {/* Sender actions on pending offer */}
          {isSender && offer.status==="pending" && (
            <Btn ghost color={C.textMid} disabled={actionLoading} onClick={()=>doAction("cancel")}>Cancel Offer</Btn>
          )}

          {/* Accepted / In Progress — tracking */}
          {["accepted","in_progress"].includes(offer.status) && (
            <div style={{ background:C.surfaceHi,border:`1.5px solid ${C.border}`,borderRadius:16,padding:"12px 14px",marginBottom:12 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,marginBottom:10 }}>📦 Shipping Details</p>
              <div style={{ display:"flex",flexDirection:"column",gap:8 }}>
                {isSender && (
                  <div>
                    <p style={{ fontSize:9.5,color:C.textMid,marginBottom:4 }}>Your tracking number</p>
                    <div style={{ display:"flex",gap:6 }}>
                      <input defaultValue={offer.sender_tracking||""} onBlur={e=>doAction("sender_tracking",e.target.value)} placeholder="e.g. 9400111899223372..." style={{ flex:1,padding:"8px 11px",borderRadius:9,background:C.surface,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12,outline:"none" }} />
                    </div>
                  </div>
                )}
                {isLister && (
                  <div>
                    <p style={{ fontSize:9.5,color:C.textMid,marginBottom:4 }}>Your tracking number</p>
                    <div style={{ display:"flex",gap:6 }}>
                      <input defaultValue={offer.lister_tracking||""} onBlur={e=>doAction("lister_tracking",e.target.value)} placeholder="e.g. 9400111899223372..." style={{ flex:1,padding:"8px 11px",borderRadius:9,background:C.surface,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12,outline:"none" }} />
                    </div>
                  </div>
                )}
                {/* Show other party's tracking (read-only) */}
                {isLister && offer.sender_tracking && <p style={{ fontSize:10.5,color:C.textMid }}>Their tracking: <span style={{ color:C.text,fontFamily:"monospace" }}>{offer.sender_tracking}</span></p>}
                {isSender && offer.lister_tracking  && <p style={{ fontSize:10.5,color:C.textMid }}>Their tracking: <span style={{ color:C.text,fontFamily:"monospace" }}>{offer.lister_tracking}</span></p>}
              </div>
            </div>
          )}

          {/* Confirm received */}
          {["accepted","in_progress"].includes(offer.status) && (
            <div style={{ marginBottom:12 }}>
              {isSender && !offer.sender_confirmed && (
                <Btn color={C.mint} disabled={actionLoading} onClick={()=>doAction("confirm")}>✓ I Received My Card</Btn>
              )}
              {isLister && !offer.lister_confirmed && (
                <Btn color={C.mint} disabled={actionLoading} onClick={()=>doAction("confirm")}>✓ I Received My Card</Btn>
              )}
              {isSender && offer.sender_confirmed && <p style={{ textAlign:"center",fontSize:11,color:C.mint,marginBottom:6 }}>✓ You confirmed receipt</p>}
              {isLister && offer.lister_confirmed && <p style={{ textAlign:"center",fontSize:11,color:C.mint,marginBottom:6 }}>✓ You confirmed receipt</p>}
            </div>
          )}

          {/* Cancel option */}
          {["accepted","in_progress"].includes(offer.status) && (
            <Btn ghost color={C.textMid} small disabled={actionLoading} onClick={()=>doAction("cancel")}>Cancel Trade</Btn>
          )}

          {/* Trade complete */}
          {offer.status==="completed" && !rateDone && (
            <div style={{ background:`linear-gradient(140deg,${C.gold}12,${C.gold}04)`,border:`1.5px solid ${C.gold}44`,borderRadius:18,padding:18,marginBottom:12,textAlign:"center" }}>
              <div style={{ fontSize:36,marginBottom:8 }}>🏅</div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:C.gold,marginBottom:6 }}>Trade Complete!</p>
              <p style={{ fontSize:11.5,color:C.textMid,marginBottom:16 }}>Rate your trade partner to help the community.</p>
              <div style={{ display:"flex",gap:10,justifyContent:"center",marginBottom:14 }}>
                {[1,2,3,4,5].map(s=>(
                  <button key={s} onClick={()=>setRating(s)} style={{ background:"none",border:"none",fontSize:28,cursor:"pointer",color:s<=rating?C.gold:C.border,transition:"all .15s" }}>★</button>
                ))}
              </div>
              <textarea value={rateNote} onChange={e=>setRateNote(e.target.value)} placeholder="Optional note for the community..." style={{ width:"100%",height:64,background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:11,color:C.text,fontSize:12,resize:"none",outline:"none",fontFamily:"'Instrument Sans',sans-serif",padding:"9px 12px",marginBottom:12 }} />
              <Btn color={C.gold} disabled={!rating} onClick={submitReview}>Submit Rating ✦</Btn>
            </div>
          )}
          {rateDone && <div style={{ textAlign:"center",padding:16,color:C.mint,fontSize:12 }}>✓ Rating submitted.</div>}

          {/* Declined / Cancelled */}
          {["declined","cancelled","disputed"].includes(offer.status) && (
            <div style={{ textAlign:"center",padding:"20px 0",color:C.textMid,fontSize:12 }}>
              <p style={{ fontSize:24,marginBottom:8 }}>{offer.status==="declined"?"✗":"⚑"}</p>
              <p>This offer was {offer.status}.</p>
            </div>
          )}
        </div>

        {/* Report */}
        {!["completed","declined","cancelled"].includes(offer.status) && !showReport && (
          <button onClick={()=>setShowReport(true)} style={{ background:"none",border:"none",color:C.textDim,fontSize:10.5,cursor:"pointer",display:"block",margin:"0 auto 12px",textDecoration:"underline" }}>⚑ Report an issue with this trade</button>
        )}
        {showReport && !reportSent && (
          <div style={{ background:C.surfaceHi,border:`1.5px solid ${C.border}`,borderRadius:16,padding:14,marginBottom:12 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,marginBottom:8 }}>Report Issue</p>
            {REPORT_REASONS.map(([v,l])=>(
              <button key={v} onClick={()=>setReportReason(v)} style={{ width:"100%",marginBottom:5,padding:"8px 11px",borderRadius:9,textAlign:"left",background:reportReason===v?`${C.rose}18`:"transparent",border:`1.5px solid ${reportReason===v?C.rose:C.border}`,color:reportReason===v?C.rose:C.text,fontSize:11.5,cursor:"pointer" }}>{l}</button>
            ))}
            <div style={{ display:"flex",gap:8,marginTop:6 }}>
              <Btn ghost color={C.textMid} small onClick={()=>setShowReport(false)}>Cancel</Btn>
              <Btn color={C.rose} small disabled={!reportReason} onClick={submitReport}>Submit</Btn>
            </div>
          </div>
        )}
        {reportSent && <p style={{ textAlign:"center",fontSize:11,color:C.mint,marginBottom:12 }}>✓ Report submitted.</p>}

        {/* Message thread */}
        {!["declined","cancelled"].includes(offer.status) && (
          <div>
            <p style={{ ...VS.softSectionHeader,marginBottom:10 }}>Messages</p>
            <div style={{ background:C.surfaceHi,borderRadius:18,padding:12,marginBottom:10,maxHeight:220,overflowY:"auto" }}>
              {messages.length===0&&<p style={{ fontSize:11,color:C.textDim,textAlign:"center",padding:"10px 0" }}>No messages yet. Say hi!</p>}
              {messages.map((msg,i)=>{
                const isMe = msg.sender_id === user?.id;
                return (
                  <div key={i} style={{ display:"flex",justifyContent:isMe?"flex-end":"flex-start",marginBottom:8 }}>
                    <div style={{ maxWidth:"78%",background:isMe?`linear-gradient(140deg,${C.accent},${C.accentDim})`:C.surface,borderRadius:isMe?"16px 16px 4px 16px":"16px 16px 16px 4px",padding:"9px 13px",border:isMe?"none":`1px solid ${C.border}` }}>
                      {!isMe&&<p style={{ fontSize:8.5,color:C.textDim,marginBottom:3 }}>@{msg.sender?.username||"fan"}</p>}
                      <p style={{ fontSize:12.5,lineHeight:1.55,color:isMe?C.white:C.text }}>{msg.body}</p>
                      <p style={{ fontSize:8.5,color:isMe?"rgba(255,255,255,0.5)":C.textDim,marginTop:3 }}>{new Date(msg.created_at).toLocaleTimeString([], {hour:"2-digit",minute:"2-digit"})}</p>
                    </div>
                  </div>
                );
              })}
              <div ref={msgBottom} />
            </div>
            <div style={{ display:"flex",gap:8 }}>
              <input value={msgDraft} onChange={e=>setMsgDraft(e.target.value)} onKeyDown={e=>e.key==="Enter"&&!e.shiftKey&&sendMsg()} placeholder="Message..." style={{ flex:1,padding:"10px 13px",borderRadius:12,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12.5,outline:"none" }} />
              <button onClick={sendMsg} disabled={!msgDraft.trim()||sending} style={{ width:42,height:42,borderRadius:12,background:msgDraft.trim()?C.accent:`${C.accent}33`,border:"none",color:C.bg,fontSize:16,cursor:"pointer" }}>→</button>
            </div>
          </div>
        )}
      </Screen>
    </div>
  );
}

// ─── TRADE PASSPORT — trust layer, shown in Trade Hub & Profile Preview ──────
const DEFAULT_TRADE_PASSPORT = { successfulTrades:37, yearsCollecting:4, verified:true, reports:0, rating:4.9, badges:["Fast Shipper","Careful Packaging","Venue Trader","Wishlist Matcher"], packagingNotes:"Always ships in top loaders with bubble mailers — zero damage reports." };
const DEFAULT_TRADE_HISTORY = { completed:34, cancelled:3 };
const TRADE_BADGE_ICONS = { "Fast Shipper":"🚀", "Careful Packaging":"📦", "Venue Trader":"🎤", "Wishlist Matcher":"🎯" };

function TradePassportCard({ passport, history, compact }) {
  const [expanded, setExpanded] = useState(false);
  const p = passport || DEFAULT_TRADE_PASSPORT;
  const h = history || DEFAULT_TRADE_HISTORY;
  const ratingDisplay = typeof p.rating === "number" ? p.rating.toFixed(1) : p.rating;
  return (
    <div style={{ ...VS.glowCard(C.gold), padding: compact ? "13px 15px" : "16px 18px", marginBottom:16 }}>
      <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.gold}44,transparent)` }} />
      <div style={{ display:"flex",alignItems:"center",gap:8,marginBottom:12,position:"relative" }}>
        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5,flex:1 }}>🛡️ Trade Passport</p>
        {p.verified && <Pill color={C.mint} small>✓ Verified Trader</Pill>}
      </div>
      <div style={{ display:"flex",gap:7,marginBottom:12,position:"relative" }}>
        {[[p.successfulTrades,"Trades",C.gold],[p.yearsCollecting,"Yrs Collecting",C.accent],[`★ ${ratingDisplay}`,"Rating",C.pink],[p.reports,"Reports",C.mint]].map(([val,label,color])=>(
          <div key={label} style={{ flex:1,textAlign:"center",padding:"8px 4px",borderRadius:12,background:`${color}10`,border:`1px solid ${color}28` }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:14.5,color }}>{val}</p>
            <p style={{ fontSize:8,color:C.textMid,marginTop:2,lineHeight:1.3 }}>{label}</p>
          </div>
        ))}
      </div>
      {p.badges?.length>0 && (
        <div style={{ display:"flex",gap:6,flexWrap:"wrap",marginBottom:10,position:"relative" }}>
          {p.badges.map(b=>(
            <span key={b} style={{ padding:"5px 11px",borderRadius:99,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:600,background:`${C.gold}14`,color:C.gold,border:`1px solid ${C.gold}30` }}>{TRADE_BADGE_ICONS[b]||"✦"} {b}</span>
          ))}
        </div>
      )}
      <div onClick={()=>setExpanded(e=>!e)} className="tap" style={{ display:"flex",justifyContent:"space-between",alignItems:"center",cursor:"pointer",position:"relative",paddingTop:2 }}>
        <p style={{ fontSize:10.5,color:C.accentDim,fontFamily:"'Epilogue',sans-serif",fontWeight:700 }}>Trust Details</p>
        <span style={{ fontSize:11,color:C.textMid }}>{expanded?"▾":"▸"}</span>
      </div>
      {expanded && (
        <div style={{ marginTop:10,paddingTop:10,borderTop:`1px solid ${C.border}`,display:"flex",flexDirection:"column",gap:7,position:"relative" }}>
          {[
            ["Completed Trades",h.completed],
            ["Cancelled Trades",h.cancelled],
            ["Reports",p.reports],
            ["Verification Status",p.verified?"Verified ✓":"Unverified"],
          ].map(([label,val])=>(
            <div key={label} style={{ display:"flex",justifyContent:"space-between" }}>
              <p style={{ fontSize:11,color:C.textMid }}>{label}</p>
              <p style={{ fontSize:11,fontWeight:700 }}>{val}</p>
            </div>
          ))}
          {p.packagingNotes && (
            <p style={{ fontSize:10.5,color:C.textDim,fontStyle:"italic",lineHeight:1.5,marginTop:2 }}>📦 "{p.packagingNotes}"</p>
          )}
        </div>
      )}
    </div>
  );
}

function TradeHub({ onBack, onNotif, user }) {
  const { tokenReady } = useAuth();
  const [hubTab, setHubTab]         = useState("mine");
  const [publicListings, setPublicListings] = useState([]);
  const [hubLoading, setHubLoading] = useState(false);
  const [myOffers, setMyOffers]     = useState([]);
  const [offersLoading, setOffersLoading] = useState(false);
  const [selectedListing, setSelectedListing] = useState(null); // for TradeListingDetail
  const [selectedOffer, setSelectedOffer]     = useState(null); // for OfferThread

  // Keep mock trades as fallback for the old "My Trades" flow (pre-real-data)
  const [trades] = useState(()=>ls.get("backstage_active_trades", MOCK_ACTIVE_TRADES_DEFAULT));
  const [tradePassport] = useState(()=>ls.get("backstage_trade_passport", DEFAULT_TRADE_PASSPORT));
  const [tradeHistory] = useState(()=>ls.get("backstage_trade_history", DEFAULT_TRADE_HISTORY));

  useEffect(()=>{
    if (hubTab !== "hub") return;
    setHubLoading(true);
    api.get('/api/trade-listings').then(d=>{ setPublicListings(d?.listings||[]); setHubLoading(false); });
  }, [hubTab]);

  useEffect(()=>{
    if (hubTab !== "mine" || !tokenReady) return;
    setOffersLoading(true);
    api.get('/api/listing-offers').then(d=>{ setMyOffers(d?.offers||[]); setOffersLoading(false); });
  }, [hubTab, tokenReady]);

  const refreshOffers = () => {
    api.get('/api/listing-offers').then(d=>setMyOffers(d?.offers||[]));
  };

  const sendMessage = (tradeId) => {
    if(!msgDraft.trim()) return;
    setTrades(ts=>ts.map(t=>t.id===tradeId?{...t,messages:[...t.messages,{from:"me",text:msgDraft,time:"now"}]}:t));
    setMsgDraft("");
    // TODO: POST /api/trades/:id/messages — real-time via Supabase Realtime
  };

  const handlePhotoProof = (e, tradeId) => {
    const f = e.target.files[0]; if(!f) return;
    const r = new FileReader();
    r.onload = ev => {
      setPhotoProof(p=>({...p,[tradeId]:ev.target.result}));
      setTrades(ts=>ts.map(t=>t.id===tradeId?{...t,myPhotoProof:ev.target.result}:t));
    };
    r.readAsDataURL(f);
  };

  // Route to sub-views
  if (selectedListing) return <TradeListingDetail listing={selectedListing} user={user} onBack={()=>setSelectedListing(null)} onOfferMade={()=>{ setSelectedListing(null); setHubTab("mine"); refreshOffers(); }} />;
  if (selectedOffer)   return <OfferThread offer={selectedOffer} user={user} onBack={()=>{ setSelectedOffer(null); refreshOffers(); }} onComplete={refreshOffers} />;

  const activeTrade = null; // legacy mock flow disabled — real offers used below

  const STAGE_FLOW = ["match","offer","waiting","accepted","shipped","confirm","done","rate"];
  const STAGE_LABELS = {
    match:    {headline:"Match Found! 👀",   sub:"A fan near you has your wishlist card. Review their profile before offering.",   cta:"Make Offer →",          next:"offer"    },
    offer:    {headline:"Offer Ready ✦",      sub:"Review the trade. Once you send, the other fan gets notified.",                   cta:"Send Offer",            next:"waiting"  },
    waiting:  {headline:"Offer Sent ⏳",      sub:"Waiting for their response. You'll be notified when they accept or decline.",     cta:"Withdraw Offer",        next:"match", ghost:true},
    accepted: {headline:"Accepted! 🎉",       sub:"Both sides agreed. Ship your card using tracked shipping and share the details.",  cta:"Mark as Shipped →",     next:"shipped"  },
    shipped:  {headline:"Card In Transit 📦", sub:"Your card is on its way. Waiting for confirmation from both sides.",              cta:"I Received Mine ✓",     next:"confirm"  },
    confirm:  {headline:"Confirm Receipt 🃏", sub:"Only confirm once you have the card physically in hand and it matches the deal.",  cta:"✓ Confirm Complete",    next:"done"     },
    done:     {headline:"Trade Complete! ✦",  sub:"Both sides confirmed. Proof scores updated. Rate your trade partner!",            cta:"Rate Trader →",         next:"rate"     },
    rate:     {headline:"Rate Your Trader",   sub:"Your rating keeps the community safe and trusted.",                               cta:null },
  };

  // Individual trade detail view
  if(activeTrade) {
    const meta = TRADE_STAGE_META[activeTrade.stage]||TRADE_STAGE_META.match;
    const flow = STAGE_LABELS[activeTrade.stage];
    const stageIdx = STAGE_FLOW.indexOf(activeTrade.stage);

    return (
      <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden",background:C.bg }}>
        {/* Header */}
        <div style={{ padding:"14px 20px 12px",display:"flex",gap:10,alignItems:"center",flexShrink:0,borderBottom:`1px solid ${C.border}` }}>
          <button onClick={()=>setSelected(null)} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
          <div style={{ flex:1 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:15 }}>Trade with {activeTrade.partner.name}</p>
            <p style={{ fontSize:10,color:C.textMid }}>★ {activeTrade.partner.trustScore} · {activeTrade.partner.trades} trades</p>
          </div>
          <div style={{ ...VS.activePill(meta.color),fontSize:9 }}>{meta.icon} {meta.label}</div>
        </div>

        <Screen style={{ padding:"0 18px calc(120px + env(safe-area-inset-bottom))" }}>
          {/* Progress stepper */}
          <div style={{ display:"flex",gap:3,alignItems:"center",marginBottom:20,marginTop:14,overflowX:"auto",scrollbarWidth:"none" }}>
            {["Match","Offer","Wait","Accept","Ship","Confirm","Done"].map((label,i)=>(
              <div key={i} style={{ display:"flex",alignItems:"center",flexShrink:0 }}>
                <div style={{ width:i===stageIdx?30:22,height:i===stageIdx?30:22,borderRadius:"50%",background:i<stageIdx?C.mint:i===stageIdx?`linear-gradient(135deg,${C.accent},${C.pink})`:C.surfaceHi,border:i<stageIdx?`1.5px solid ${C.mint}`:i===stageIdx?"none":`1.5px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:i===stageIdx?11:9,color:i<=stageIdx?C.bg:C.textDim,boxShadow:i===stageIdx?`0 0 14px ${C.accent}55`:"none",transition:"all .3s",flexShrink:0 }}>
                  {i<stageIdx?"✓":i+1}
                </div>
                {i<6&&<div style={{ width:18,height:2,background:i<stageIdx?C.mint:C.border,borderRadius:99,margin:"0 2px",transition:"background .4s" }} />}
              </div>
            ))}
          </div>

          {/* Stage headline */}
          <div style={{ textAlign:"center",marginBottom:18 }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:22,letterSpacing:"-0.02em",marginBottom:6,lineHeight:1.2 }}>{flow.headline}</p>
            <p style={{ fontSize:12.5,color:C.textMid,lineHeight:1.65,maxWidth:280,margin:"0 auto" }}>{flow.sub}</p>
          </div>

          {/* Card swap */}
          {activeTrade.stage!=="rate" && (
            <div style={{ display:"flex",gap:10,alignItems:"center",marginBottom:18 }}>
              {[{label:"You Offer",card:activeTrade.myCard},{label:"You Get",card:activeTrade.theirCard}].map((side,si)=>(
                <div key={si} style={{ flex:1,padding:"14px 10px",borderRadius:20,textAlign:"center",...VS.glowCard(side.card.color) }}>
                  <div style={VS.innerGlow(side.card.color)} />
                  <div style={{ position:"relative" }}>
                    {/* Photo proof section */}
                    {(activeTrade.stage==="offer"||activeTrade.stage==="accepted")&&si===0&&(
                      <div style={{ marginBottom:6 }}>
                        {photoProof[activeTrade.id] ? (
                          <img src={photoProof[activeTrade.id]} alt="proof" style={{ width:60,height:80,objectFit:"cover",borderRadius:10,margin:"0 auto",display:"block",border:`1.5px solid ${side.card.color}55` }} />
                        ) : (
                          <button onClick={()=>photoRef.current?.click()} style={{ width:60,height:80,borderRadius:10,background:`${side.card.color}12`,border:`2px dashed ${side.card.color}44`,color:side.card.color,fontSize:9.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:3,margin:"0 auto" }}>
                            <span style={{ fontSize:18 }}>📸</span>Add Photo Proof
                          </button>
                        )}
                        <input ref={photoRef} type="file" accept="image/*" onChange={e=>handlePhotoProof(e,activeTrade.id)} style={{ display:"none" }} />
                      </div>
                    )}
                    {!(activeTrade.stage==="offer"||activeTrade.stage==="accepted")||si!==0 ? <div style={{ fontSize:28,marginBottom:6 }}>{side.card.emoji}</div> : null}
                    <p style={{ fontSize:8.5,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.08em",marginBottom:3 }}>{side.label}</p>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13,color:C.text,marginBottom:1 }}>{side.card.name}</p>
                    <p style={{ fontSize:9.5,color:C.textMid }}>{side.card.group} · {side.card.era}</p>
                    <div style={{ marginTop:6,...VS.activePill(side.card.color),fontSize:8 }}>{side.card.rarity}</div>
                  </div>
                </div>
              ))}
              <div style={{ flexShrink:0,width:34,height:34,borderRadius:"50%",background:`${C.accent}18`,border:`1.5px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:14,color:C.accent }}>⇄</div>
            </div>
          )}

          {/* Safety tip for accepted stage */}
          {activeTrade.stage==="accepted"&&(
            <div style={{ background:`${C.gold}0a`,border:`1px solid ${C.gold}28`,borderRadius:14,padding:"11px 14px",marginBottom:16 }}>
              <p style={{ fontSize:11.5,color:C.gold,fontFamily:"'Epilogue',sans-serif",fontWeight:700,marginBottom:4 }}>🛡️ Safety Reminder</p>
              <p style={{ fontSize:11,color:C.textMid,lineHeight:1.6 }}>Use tracked shipping only. Screenshot your address exchange. Never send without written confirmation.</p>
              <input value={activeTrade.shippingInfo} onChange={e=>setTrades(ts=>ts.map(t=>t.id===activeTrade.id?{...t,shippingInfo:e.target.value}:t))} placeholder="Enter tracking number when shipped..." style={{ width:"100%",marginTop:10,padding:"9px 12px",borderRadius:10,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12,outline:"none" }} />
            </div>
          )}

          {/* Rating UI */}
          {activeTrade.stage==="rate"&&!rateDone[activeTrade.id]&&(
            <div style={{ animation:"up .3s ease" }}>
              <div style={{ display:"flex",gap:14,justifyContent:"center",marginBottom:18 }}>
                {[1,2,3,4,5].map(star=>(
                  <button key={star} onClick={()=>setRating(star)} style={{ background:"none",border:"none",fontSize:34,cursor:"pointer",color:star<=rating?C.gold:C.border,transition:"all .15s",transform:star===rating?"scale(1.2)":"scale(1)" }}>★</button>
                ))}
              </div>
              <textarea value={rateNote} onChange={e=>setRateNote(e.target.value)} placeholder="Leave a note for other traders... (optional)" style={{ width:"100%",height:72,background:C.surfaceHi,border:`1.5px solid ${C.border}`,borderRadius:13,color:C.text,fontSize:12.5,resize:"none",outline:"none",fontFamily:"'Instrument Sans',sans-serif",padding:"11px 13px",marginBottom:14 }} />
              <button disabled={!rating} onClick={()=>{ ls.set("backstage_trade_reviews",[...ls.get("backstage_trade_reviews",[]),{partner:activeTrade.partner.name,rating,note:rateNote,date:new Date().toISOString()}]); setRateDone(r=>({...r,[activeTrade.id]:true})); }} style={{ width:"100%",padding:"13px",borderRadius:14,background:rating?`linear-gradient(140deg,${C.gold}cc,${C.goldDim})`:`${C.gold}33`,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13,cursor:rating?"pointer":"default",opacity:rating?1:0.5 }}>Submit Rating ✦</button>
            </div>
          )}
          {rateDone[activeTrade.id]&&(
            <div style={{ textAlign:"center",padding:"28px 0",animation:"burst .4s ease" }}>
              <div style={{ fontSize:48,marginBottom:12 }}>🏅</div>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:20,color:C.gold,marginBottom:6 }}>Rated! Trade archived.</p>
              <p style={{ fontSize:12,color:C.textMid }}>Proof Score updated · Trusted Trader badge unlocked</p>
            </div>
          )}

          {/* CTA */}
          {activeTrade.stage!=="rate"&&flow.cta&&(
            <button onClick={()=>advanceStage(activeTrade.id,flow.next||activeTrade.stage)} className="tap" style={{ width:"100%",padding:"13px",borderRadius:16,background:flow.ghost?"transparent":`linear-gradient(140deg,${C.accent}ee,${C.pink}cc)`,border:flow.ghost?`1.5px solid ${C.border}`:"none",color:flow.ghost?C.textMid:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,cursor:"pointer",marginBottom:12 }}>{flow.cta}</button>
          )}

          {/* Messaging thread */}
          <div style={{ marginTop:8 }}>
            <p style={{ ...VS.softSectionHeader,marginBottom:12 }}>Messages</p>
            <div style={{ background:C.surfaceHi,borderRadius:18,padding:14,marginBottom:10,maxHeight:200,overflowY:"auto" }}>
              {activeTrade.messages.length===0&&<p style={{ fontSize:11.5,color:C.textDim,textAlign:"center",padding:"10px 0" }}>No messages yet. Start the conversation!</p>}
              {activeTrade.messages.map((msg,i)=>(
                <div key={i} style={{ display:"flex",justifyContent:msg.from==="me"?"flex-end":"flex-start",marginBottom:8 }}>
                  <div style={{ maxWidth:"78%",background:msg.from==="me"?`linear-gradient(140deg,${C.accent},${C.accentDim})`:C.surface,borderRadius:msg.from==="me"?"16px 16px 4px 16px":"16px 16px 16px 4px",padding:"9px 13px",border:msg.from==="me"?"none":`1px solid ${C.border}` }}>
                    <p style={{ fontSize:12.5,lineHeight:1.55,color:msg.from==="me"?C.white:C.text }}>{msg.text}</p>
                    <p style={{ fontSize:8.5,color:msg.from==="me"?"rgba(255,255,255,0.5)":C.textDim,marginTop:3 }}>{msg.time}</p>
                  </div>
                </div>
              ))}
            </div>
            <div style={{ display:"flex",gap:8 }}>
              <input value={msgDraft} onChange={e=>setMsgDraft(e.target.value)} onKeyDown={e=>e.key==="Enter"&&sendMessage(activeTrade.id)} placeholder="Message..." style={{ flex:1,padding:"10px 13px",borderRadius:12,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12.5,outline:"none" }} />
              <button onClick={()=>sendMessage(activeTrade.id)} disabled={!msgDraft.trim()} style={{ width:42,height:42,borderRadius:12,background:msgDraft.trim()?C.accent:`${C.accent}33`,border:"none",color:C.bg,fontSize:16,cursor:"pointer" }}>→</button>
            </div>
          </div>
        </Screen>
      </div>
    );
  }

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      {/* Header */}
      <div style={{ padding:"16px 20px 10px", display:"flex", alignItems:"center", gap:10, flexShrink:0 }}>
        <button onClick={onBack||undefined} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <div style={{ flex:1 }}>
          <h2 style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:19 }}>Trade Hub 🃏</h2>
          <p style={{ fontSize:10.5, color:C.textMid }}>{trades.filter(t=>t.stage!=="done").length} active trades</p>
        </div>
        {ls.get("backstage_is_vip")&&<div style={{ ...VS.activePill(C.gold),fontSize:9 }}>✦ Verified</div>}
      </div>

      {/* Tab switcher */}
      <div style={{ padding:"0 18px 12px", flexShrink:0 }}>
        <div style={{ display:"flex",gap:0,background:C.surfaceHi,borderRadius:13,padding:3 }}>
          {[["mine","My Trades"],["hub","Public Hub"]].map(([id,label])=>(
            <span key={id} onClick={()=>setHubTab(id)} style={{ flex:1,textAlign:"center",padding:"8px 4px",borderRadius:10,fontSize:11.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",background:hubTab===id?C.accent:"transparent",color:hubTab===id?C.bg:C.textMid,transition:"all .18s" }}>{label}</span>
          ))}
        </div>
      </div>

      <Screen style={{ padding:"0 18px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* TRADE PASSPORT — your trust signal to other traders */}
        <div style={{ paddingTop:14 }}>
          <p style={{ fontSize:9, color:C.textDim, fontFamily:"'Epilogue',sans-serif", fontWeight:700, textTransform:"uppercase", letterSpacing:"0.12em", marginBottom:8 }}>Your trust signal to other traders</p>
          <TradePassportCard passport={tradePassport} history={tradeHistory} compact />
        </div>

        {/* Public Hub — clickable listings */}
        {hubTab==="hub" && (
          hubLoading ? <div style={{ textAlign:"center",padding:40,color:C.textMid,fontSize:13 }}>Loading listings...</div> : (
            publicListings.filter(l=>l.status==="active"||l.status==="pending").length===0 ? (
              <div style={{ textAlign:"center",padding:"48px 20px" }}>
                <p style={{ fontSize:36,marginBottom:12 }}>⇄</p>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:15,marginBottom:6 }}>No active listings</p>
                <p style={{ fontSize:12,color:C.textMid }}>Mark a card as "For Trade" in your binder to list it here.</p>
              </div>
            ) : publicListings.filter(l=>l.status==="active"||l.status==="pending").map(listing=>{
              const uc = listing.user_cards || {};
              const trader = listing.users || {};
              return (
                <div key={listing.id} onClick={()=>setSelectedListing(listing)} className="tap" style={{ background:C.surface,border:`1.5px solid ${C.border}`,borderRadius:18,padding:14,marginBottom:12,cursor:"pointer" }}>
                  <div style={{ display:"flex",gap:10,alignItems:"flex-start" }}>
                    {listing.proof_image_url ? (
                      <img src={listing.proof_image_url} alt={uc.member} style={{ width:50,height:66,objectFit:"cover",borderRadius:10,border:`1.5px solid ${C.border}`,flexShrink:0 }} />
                    ) : (
                      <div style={{ width:50,height:66,borderRadius:10,background:`${C.accent}18`,border:`1.5px dashed ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0 }}>🃏</div>
                    )}
                    <div style={{ flex:1,minWidth:0 }}>
                      <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:13.5,color:C.text,marginBottom:2 }}>{uc.member}</p>
                      <p style={{ fontSize:11,color:C.textMid,marginBottom:4 }}>{uc.group_name} · {uc.album||uc.era||""}</p>
                      <div style={{ display:"flex",gap:5,flexWrap:"wrap" }}>
                        {uc.condition&&<div style={{ ...VS.activePill(C.mint),fontSize:8 }}>{uc.condition}</div>}
                        <div style={{ ...VS.activePill(C.accent),fontSize:8 }}>{listing.trade_type==="any"?"Any":listing.trade_type}</div>
                        {listing.location&&<div style={{ ...VS.activePill(C.silver),fontSize:8 }}>📍 {listing.location}</div>}
                        {listing.status==="pending"&&<div style={{ ...VS.activePill(C.gold),fontSize:8 }}>Offer pending</div>}
                      </div>
                      {listing.wants_description&&<p style={{ fontSize:10.5,color:C.textMid,marginTop:5,lineHeight:1.5 }}>Wants: {listing.wants_description}</p>}
                    </div>
                    <div style={{ ...VS.activePill(C.rose),fontSize:9,flexShrink:0 }}>📷</div>
                  </div>
                  <div style={{ marginTop:8,display:"flex",justifyContent:"space-between",alignItems:"center" }}>
                    <p style={{ fontSize:10,color:C.textDim }}>@{trader.username||"fan"}</p>
                    <p style={{ fontSize:10,color:C.accent }}>View →</p>
                  </div>
                </div>
              );
            })
          )
        )}

        {/* My Trades — real offers */}
        {hubTab==="mine" && (
          offersLoading ? <div style={{ textAlign:"center",padding:32,color:C.textMid,fontSize:13 }}>Loading...</div> :
          myOffers.length===0 ? (
            <div style={{ textAlign:"center",padding:"48px 20px" }}>
              <p style={{ fontSize:36,marginBottom:12 }}>⇄</p>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:15,marginBottom:6 }}>No active offers</p>
              <p style={{ fontSize:12,color:C.textMid }}>Browse the Public Hub and make an offer on a listing to get started.</p>
            </div>
          ) : myOffers.map(offer=>{
            const listing = offer.trade_listings || {};
            const uc = listing.user_cards || {};
            const STATUS_META_OFFER = {
              pending:    { label:"Pending",      color:C.accent  },
              accepted:   { label:"Accepted ✓",  color:C.mint    },
              in_progress:{ label:"In Progress",  color:C.sky     },
              completed:  { label:"Complete 🏅",  color:C.gold    },
              declined:   { label:"Declined",     color:C.textMid },
              cancelled:  { label:"Cancelled",    color:C.textMid },
            };
            const ometa = STATUS_META_OFFER[offer.status] || STATUS_META_OFFER.pending;
            const isLister = offer.role === "lister";
            return (
              <div key={offer.id} onClick={()=>setSelectedOffer(offer)} className="tap" style={{ ...VS.glowCard(ometa.color),padding:14,marginBottom:12,cursor:"pointer" }}>
                <div style={VS.shimmerLine(ometa.color)} />
                <div style={{ position:"relative",display:"flex",gap:11,alignItems:"center" }}>
                  <div style={{ width:46,height:62,borderRadius:10,background:`${ometa.color}14`,border:`1.5px solid ${ometa.color}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0 }}>🃏</div>
                  <div style={{ flex:1,minWidth:0 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:2 }}>{uc.member||"Card"}</p>
                    <p style={{ fontSize:10.5,color:C.textMid,marginBottom:4 }}>{uc.group_name} · {uc.album||uc.era||""}</p>
                    <p style={{ fontSize:10,color:C.textDim }}>{isLister?"Offer received":"Your offer"}</p>
                  </div>
                  <div style={{ display:"flex",flexDirection:"column",alignItems:"flex-end",gap:5 }}>
                    <div style={{ ...VS.activePill(ometa.color),fontSize:8.5 }}>{ometa.label}</div>
                    {isLister&&offer.status==="pending"&&<div style={{ ...VS.activePill(C.rose),fontSize:8 }}>Action needed</div>}
                  </div>
                </div>
              </div>
            );
          })
        )}

        {/* Completed trades section */}
        {hubTab==="mine"&&myOffers.filter(o=>o.status==="completed").length>0&&(
          <div style={{ marginTop:8 }}>
            <p style={{ ...VS.softSectionHeader,marginBottom:10 }}>Completed</p>
            {myOffers.filter(o=>o.status==="completed").map(offer=>{
              const uc = (offer.trade_listings||{}).user_cards || {};
              return (
                <div key={offer.id} onClick={()=>setSelectedOffer(offer)} className="tap" style={{ background:C.surface,border:`1px solid ${C.border}`,borderRadius:14,padding:12,marginBottom:8,display:"flex",gap:10,alignItems:"center",opacity:0.75,cursor:"pointer" }}>
                  <p style={{ fontSize:14 }}>🏅</p>
                  <div style={{ flex:1 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5 }}>{uc.member||"Card"}</p>
                    <p style={{ fontSize:10.5,color:C.textMid }}>{uc.group_name}</p>
                  </div>
                  <div style={{ ...VS.activePill(C.gold),fontSize:8 }}>✓ Done</div>
                </div>
              );
            })}
          </div>
        )}

{/* empty state handled inside the "mine" block above */}
      </Screen>
    </div>
  );
}

function CollectTab({ cards, setCards, isVip, onUpgrade, user }) {
  const [view, setView] = useState("shelf");
  const [filter, setFilter] = useState("all");
  const [selected, setSelected] = useState(null);
  const [wishlist, setWishlist] = useState([]);
  useEffect(()=>{ api.get('/api/cards?status=iso').then(d=>{ if(d?.cards) setWishlist(d.cards); }).catch(()=>{}); },[]);
  const [tradeable] = useState(MOCK_CARDS.filter(c=>c.tradeable));
  const [tracking, setTracking] = useState(null);
  const [trackNum, setTrackNum] = useState("");
  const [showBinderCreate, setShowBinderCreate] = useState(false);
  const [showCustomBinder, setShowCustomBinder] = useState(false);
  const [showTradeHub, setShowTradeHub] = useState(false);
  const [selectedBinder, setSelectedBinder] = useState(null);

  const { binders, loading: bindersLoading, refresh: refreshBinders } = useBinders();

  const filteredCards = cards.filter(c=>filter==="all"||(filter==="dupes"&&c.dupe)||(filter==="tradeable"&&c.tradeable));

  const mockTrack = () => {
    if(!trackNum.trim())return;
    setTracking({ status:"In Transit", statusDetail:"Package departed sorting facility", location:"Memphis, TN", estimatedDelivery:"Apr 29" });
  };

  if (showBinderCreate) return <BinderCreate onBack={()=>{ setShowBinderCreate(false); refreshBinders(); }} onCustom={()=>{ setShowBinderCreate(false); setShowCustomBinder(true); }} onCreatedBinder={b=>{ setShowBinderCreate(false); refreshBinders(); setSelectedBinder(b); }} />;
  if (showCustomBinder) return <CustomBinderForm onBack={()=>setShowCustomBinder(false)} onSaved={b=>{ setShowCustomBinder(false); refreshBinders(); setSelectedBinder(b); }} />;
  if (showTradeHub) return <TradeHub onBack={()=>setShowTradeHub(false)} user={user} />;
  if (selectedBinder) return <BinderDetail binder={selectedBinder} onBack={()=>setSelectedBinder(null)} />;

  return (
    <div style={{ height:"100%", display:"flex", flexDirection:"column", overflow:"hidden" }}>
      <div style={{ padding:"0 20px 0", flexShrink:0 }}>
        <div style={{ display:"flex", gap:0, background:C.surfaceHi, borderRadius:13, padding:3, marginBottom:14 }}>
          {[["shelf","Memories"],["wishlist","Wishlist"],["binders","Albums"],["trades","Trades"]].map(([id,label])=>(
            <span key={id} onClick={()=>setView(id)} style={{ flex:1, textAlign:"center", padding:"8px 4px", borderRadius:10, fontSize:11.5, fontFamily:"'Epilogue',sans-serif", fontWeight:700, cursor:"pointer", background:view===id?C.accent:"transparent", color:view===id?C.bg:C.textMid, transition:"all .18s" }}>{label}</span>
          ))}
        </div>
      </div>
      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {view==="shelf" && (
          <div>
            {/* Memory photo grid - matching mockup */}
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:12 }}>
              {[
                { title:"ATEEZ Dallas D1", sub:"May 22, 2025", color:`linear-gradient(160deg,${C.accent}40,${C.accentDim})`, emoji:"🎤" },
                { title:"Freebies Collection", sub:"May 22, 2025", color:`linear-gradient(160deg,${C.pink}40,${C.pinkDim})`, emoji:"🎁" },
                { title:"ATEEZ Soundcheck", sub:"May 22, 2025", color:`linear-gradient(160deg,${C.mint}30,${C.mintDim})`, emoji:"🎵" },
                { title:"New Friends Always", sub:"May 22, 2025", color:`linear-gradient(160deg,${C.gold}30,${C.goldDim})`, emoji:"💜" },
              ].map((mem,i)=>(
                <div key={i} className="tap" style={{ borderRadius:16, overflow:"hidden", cursor:"pointer", background:mem.color, aspectRatio:"1", position:"relative", display:"flex", flexDirection:"column", justifyContent:"flex-end", padding:10 }}>
                  <div style={{ position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center",fontSize:40,opacity:0.2 }}>{mem.emoji}</div>
                  <div style={{ position:"relative",zIndex:1 }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:10.5, color:"white", lineHeight:1.2 }}>{mem.title}</p>
                    <p style={{ fontSize:9, color:"rgba(255,255,255,0.7)", marginTop:2 }}>{mem.sub}</p>
                  </div>
                </div>
              ))}
              {/* Add memory card */}
              <div className="tap" style={{ borderRadius:16, border:`2px dashed ${C.border}`, cursor:"pointer", aspectRatio:"1", display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:6 }}>
                <div style={{ width:36,height:36,borderRadius:"50%",background:`${C.accent}18`,border:`1.5px solid ${C.accent}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,color:C.accent }}>+</div>
                <p style={{ fontSize:10, color:C.textDim, fontFamily:"'Epilogue',sans-serif", fontWeight:600, textAlign:"center" }}>Add Memory</p>
              </div>
            </div>
          </div>
        )}
        {view==="binders" && (
          <div>
            {/* Create Binder CTAs */}
            <div style={{ display:"flex", gap:10, marginBottom:16 }}>
              <button onClick={()=>setShowBinderCreate(true)} className="tap" style={{ flex:1, padding:"14px 14px", borderRadius:20, textAlign:"left", cursor:"pointer", background:`linear-gradient(145deg,${C.accent}18,${C.pink}10)`, border:`1.5px solid ${C.accent}38`, position:"relative", overflow:"hidden" }}>
                <div style={{ position:"absolute",top:-10,right:-10,width:60,height:60,borderRadius:"50%",background:`radial-gradient(circle,${C.accent}18,transparent 65%)`,pointerEvents:"none" }} />
                <div style={{ position:"relative", display:"flex", gap:10, alignItems:"center" }}>
                  <div style={{ width:38,height:38,borderRadius:12,background:`${C.accent}22`,border:`1.5px solid ${C.accent}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18 }}>🃏</div>
                  <div>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:12.5,color:C.text,marginBottom:1 }}>Use Template</p>
                    <p style={{ fontSize:10,color:C.textMid }}>BTS, SKZ, aespa + more</p>
                  </div>
                </div>
              </button>
              <button onClick={()=>setShowCustomBinder(true)} className="tap" style={{ flex:1, padding:"14px 14px", borderRadius:20, textAlign:"left", cursor:"pointer", background:`linear-gradient(145deg,${C.pink}14,${C.rose}08)`, border:`1.5px solid ${C.pink}38`, position:"relative", overflow:"hidden" }}>
                <div style={{ position:"relative", display:"flex", gap:10, alignItems:"center" }}>
                  <div style={{ width:38,height:38,borderRadius:12,background:`${C.pink}22`,border:`1.5px solid ${C.pink}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:18 }}>✨</div>
                  <div>
                    <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:12.5,color:C.text,marginBottom:1 }}>Custom</p>
                    <p style={{ fontSize:10,color:C.textMid }}>Any group / era</p>
                  </div>
                </div>
              </button>
            </div>

            {bindersLoading && <div style={{ textAlign:"center",padding:32,color:C.textMid,fontSize:12 }}>Loading binders...</div>}

            {!bindersLoading && binders.length===0 && (
              <div style={{ textAlign:"center",padding:"32px 16px",background:`${C.accent}08`,border:`1.5px dashed ${C.border}`,borderRadius:20 }}>
                <p style={{ fontSize:30,marginBottom:10 }}>🃏</p>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14,marginBottom:5 }}>No binders yet</p>
                <p style={{ fontSize:12,color:C.textMid }}>Create your first binder to start tracking your collection.</p>
              </div>
            )}

            {binders.map(b=>{
              const col = b.cover_color || C.accent;
              return (
                <div key={b.id} onClick={()=>setSelectedBinder(b)} className="tap" style={{ marginBottom:12, ...VS.glowCard(col), padding:16, cursor:"pointer" }}>
                  <div style={VS.shimmerLine(col)} />
                  <div style={VS.innerGlow(col)} />
                  <div style={{ position:"relative" }}>
                    <div style={{ display:"flex", gap:12, alignItems:"flex-start", marginBottom:10 }}>
                      <div style={{ width:52,height:52,borderRadius:16,background:`${col}22`,border:`1.5px solid ${col}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,flexShrink:0,boxShadow:`0 0 16px ${col}18` }}>{b.emoji||"🃏"}</div>
                      <div style={{ flex:1 }}>
                        <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14.5,color:C.text,marginBottom:3 }}>{b.name}</p>
                        {b.group_name&&<div style={VS.activePill(col)}>{b.group_name}</div>}
                      </div>
                      <span style={{ color:col,fontSize:18 }}>→</span>
                    </div>
                    <p style={{ fontSize:10.5,color:C.textMid }}>Tap to view cards</p>
                  </div>
                </div>
              );
            })}
          </div>
        )}
        {view==="trackers" && (
          <div>
            {MOCK_TRACKERS.map(t=>(
              <div key={t.id} style={{ background:C.surface, border:`1.5px solid ${C.border}`, borderRadius:18, padding:16, marginBottom:12 }}>
                <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:12 }}>
                  <div>
                    <Pill color={t.color} active small>{t.group}</Pill>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:14, marginTop:8 }}>{t.era} Set</p>
                  </div>
                  <div style={{ textAlign:"right" }}>
                    <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:20, color:t.color }}>{t.owned}<span style={{ fontSize:12, color:C.textMid }}>/{t.total}</span></p>
                    <p style={{ fontSize:9, color:C.textMid }}>collected</p>
                  </div>
                </div>
                <ProgressBar value={(t.owned/t.total)*100} color={t.color} style={{ marginBottom:8 }} />
                <div style={{ display:"flex", gap:12 }}>
                  <p style={{ fontSize:10.5, color:C.textMid }}>🔁 {t.dupes} dupes</p>
                  <p style={{ fontSize:10.5, color:C.textMid }}>❓ {t.missing} missing</p>
                </div>
              </div>
            ))}
          </div>
        )}
        {view==="wishlist" && (
          <div>
            <Card style={{ background:`${C.pink}0a`, border:`1px solid ${C.pink}22`, marginBottom:14 }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13, marginBottom:4 }}>💜 Wishlist Matching</p>
              <p style={{ fontSize:11.5, color:C.textMid }}>Cards marked ISO show up here. Mark them in your binders to track what you're looking for.</p>
            </Card>
            {wishlist.length===0 ? (
              <div style={{ textAlign:"center",padding:"24px 16px",color:C.textMid,fontSize:12 }}>No ISO cards yet — open a binder and mark cards as ♡ ISO.</div>
            ) : wishlist.map(card=>(
              <div key={card.id} style={{ background:C.surface, border:`1.5px solid ${C.border}`, borderRadius:16, padding:12, display:"flex", gap:10, alignItems:"center", marginBottom:10 }}>
                <div style={{ width:46,height:64,borderRadius:9,background:`${C.accent}18`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0,overflow:"hidden" }}>
                  {card.image_url ? <img src={card.image_url} alt="" style={{ width:"100%",height:"100%",objectFit:"cover" }} /> : "🃏"}
                </div>
                <div style={{ flex:1 }}>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13.5 }}>{card.member||card.name}</p>
                  <p style={{ fontSize:11, color:C.textMid }}>{card.group_name||card.group}{(card.album||card.era)&&` · ${card.album||card.era}`}</p>
                  <Pill color={C.accent} xs style={{ marginTop:5 }}>♡ ISO</Pill>
                </div>
              </div>
            ))}
          </div>
        )}
        {view==="trades" && (
          <div>
            {/* Open Trade Hub CTA */}
            <button onClick={()=>setShowTradeHub(true)} className="tap" style={{
              width:"100%", marginBottom:16, padding:"20px 18px", borderRadius:24,
              background:`linear-gradient(145deg,${C.pink}18,${C.accent}10)`,
              border:`1.5px solid ${C.pink}38`,
              boxShadow:`0 8px 28px ${C.pink}10`,
              textAlign:"center", cursor:"pointer", position:"relative", overflow:"hidden",
            }}>
              <div style={{ position:"absolute",top:-20,left:"50%",transform:"translateX(-50%)",width:120,height:60,borderRadius:"50%",background:`radial-gradient(ellipse,${C.pink}20,transparent 65%)`,pointerEvents:"none" }} />
              <div style={{ position:"relative" }}>
                <div style={{ fontSize:30, marginBottom:8 }}>⇄</div>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:900, fontSize:16, color:C.text, marginBottom:3 }}>Open Trade Hub</p>
                <p style={{ fontSize:11.5, color:C.textMid }}>You have 1 active match waiting</p>
              </div>
            </button>

            {/* Package tracking */}
            <div style={{ marginBottom:16 }}>
              <p style={VS.softSectionHeader}>Track Shipment</p>
              <div style={{ display:"flex", gap:10 }}>
                <input value={trackNum} onChange={e=>setTrackNum(e.target.value)} placeholder="Enter tracking number..." style={{ flex:1, padding:"10px 12px", borderRadius:11, background:C.surfaceHi, border:`1.5px solid ${C.border}`, color:C.text, fontSize:12, fontFamily:"'Instrument Sans',sans-serif" }} />
                <button onClick={mockTrack} style={{ background:C.accent, border:"none", borderRadius:10, padding:"0 14px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11, cursor:"pointer" }}>Track</button>
              </div>
              {tracking&&(
                <div style={{ marginTop:10, ...VS.elevatedCard(C.mint), padding:"12px 14px", animation:"up .2s ease" }}>
                  <div style={VS.innerGlow(C.mint)} />
                  <div style={{ position:"relative" }}>
                    <Pill color={C.mint} small>{tracking.status}</Pill>
                    <p style={{ fontSize:12, marginTop:8, marginBottom:4, color:C.text }}>{tracking.statusDetail}</p>
                    <p style={{ fontSize:10.5, color:C.textMid }}>📍 {tracking.location} · ETA {tracking.estimatedDelivery}</p>
                  </div>
                </div>
              )}
            </div>

            {/* Tradeable cards */}
            <p style={VS.softSectionHeader}>Your Tradeable Cards</p>
            {tradeable.length===0?(
              <Empty emoji="🃏" title="No tradeable cards" sub="Mark cards as tradeable from your shelf." />
            ):(
              <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
                {tradeable.map(card=>(
                  <div key={card.id} style={{ padding:12, ...VS.glowCard(card.color), display:"flex", gap:10, alignItems:"center" }}>
                    <div style={VS.innerGlow(card.color)} />
                    <div style={{ width:46,height:64,borderRadius:13,background:`${card.color}18`,border:`1.5px solid ${card.color}30`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0,boxShadow:`0 0 12px ${card.color}14` }}>🃏</div>
                    <div style={{ flex:1, position:"relative" }}>
                      <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13.5 }}>{card.name}</p>
                      <p style={{ fontSize:11, color:C.textMid }}>{card.group} · {card.era}</p>
                      <div style={{ marginTop:5, ...VS.activePill(card.color) }}>{card.rarity}</div>
                    </div>
                    <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
                      <Pill color={C.mint} small>Listed</Pill>
                      <Pill color={C.accent} small>1 match</Pill>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}
        {view==="inventory" && <InventoryTab isVip={isVip} onUpgrade={onUpgrade} />}
      </Screen>
    </div>
  );
}

// ─── INVENTORY SYSTEM ─────────────────────────────────────────────────────────
// GET /api/inventory/:userId | POST /api/inventory/item | POST /api/inventory/update | DELETE /api/inventory/item/:id | GET /api/inventory/analytics
function InventoryTab({ isVip, onUpgrade }) {
  const [items, setItems] = useState(ls.get("backstage_inventory_items", MOCK_INVENTORY));
  const [view, setView] = useState("dashboard");
  const [filterType, setFilterType] = useState("all");
  const [adding, setAdding] = useState(false);
  const [search, setSearch] = useState("");
  const [form, setForm] = useState({ type:"photocard", group:"", member:"", era:"", rarity:"SR", condition:"mint", source:"album pull", purchasePrice:0, estimatedValue:0, duplicateCount:1, tradeable:false, status:"have", notes:"", tags:[] });

  useEffect(()=>{ ls.set("backstage_inventory_items", items); }, [items]);

  const filtered = items.filter(i=>(filterType==="all"||i.type===filterType)&&(!search||i.group.toLowerCase().includes(search.toLowerCase())||i.member?.toLowerCase().includes(search.toLowerCase())));

  const totalValue = items.reduce((sum,i)=>sum+i.estimatedValue,0);
  const types = ["photocard","album","lightstick","merch","freebie","poster","ticket","vinyl"];
  const typeEmoji = { photocard:"🃏", album:"💿", lightstick:"💡", merch:"👕", freebie:"🎁", poster:"📜", ticket:"🎟️", vinyl:"🎵" };

  const saveItem = () => {
    const newItem = { ...form, id:`inv-${Date.now()}`, acquiredDate: new Date().toISOString().split("T")[0] };
    setItems([newItem, ...items]);
    setAdding(false);
    setForm({ type:"photocard", group:"", member:"", era:"", rarity:"SR", condition:"mint", source:"album pull", purchasePrice:0, estimatedValue:0, duplicateCount:1, tradeable:false, status:"have", notes:"", tags:[] });
  };

  return (
    <div>
      <div style={{ display:"flex", gap:8, marginBottom:14 }}>
        {[["dashboard","📊"],["list","📋"],].map(([id,icon])=>(
          <span key={id} onClick={()=>setView(id)} className="tap" style={{ padding:"6px 12px", borderRadius:99, fontSize:10.5, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer", background:view===id?C.mint:C.surfaceHi, color:view===id?C.bg:C.textMid, border:`1px solid ${view===id?C.mint:C.border}` }}>{icon} {id}</span>
        ))}
        <button onClick={()=>setAdding(true)} style={{ marginLeft:"auto", background:C.accent, border:"none", borderRadius:10, padding:"6px 14px", color:C.bg, fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11, cursor:"pointer" }}>+ Add</button>
      </div>

      {view==="dashboard" && (
        <div>
          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:14 }}>
            <div style={{ background:`${C.mint}12`, border:`1.5px solid ${C.mint}44`, borderRadius:16, padding:14, textAlign:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, color:C.mint }}>{items.length}</p>
              <p style={{ fontSize:10.5, color:C.textMid }}>Total Items</p>
            </div>
            <VipGate isVip={isVip} onUpgrade={onUpgrade} feature="collection value tracking">
              <div style={{ background:`${C.gold}12`, border:`1.5px solid ${C.gold}44`, borderRadius:16, padding:14, textAlign:"center" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, color:C.gold }}>${totalValue}</p>
                <p style={{ fontSize:10.5, color:C.textMid }}>Est. Value</p>
              </div>
            </VipGate>
            <div style={{ background:`${C.accent}12`, border:`1.5px solid ${C.accent}44`, borderRadius:16, padding:14, textAlign:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, color:C.accent }}>{items.filter(i=>i.tradeable).length}</p>
              <p style={{ fontSize:10.5, color:C.textMid }}>Tradeable</p>
            </div>
            <div style={{ background:`${C.pink}12`, border:`1.5px solid ${C.pink}44`, borderRadius:16, padding:14, textAlign:"center" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:24, color:C.pink }}>{items.filter(i=>i.duplicateCount>1).length}</p>
              <p style={{ fontSize:10.5, color:C.textMid }}>Duplicates</p>
            </div>
          </div>
          <SectionHeader title="By Type" />
          <div style={{ display:"flex", flexDirection:"column", gap:8 }}>
            {types.map(t=>{
              const count = items.filter(i=>i.type===t).length;
              if(!count) return null;
              return (
                <div key={t} style={{ background:C.surface, borderRadius:13, padding:"10px 14px", display:"flex", alignItems:"center", gap:10 }}>
                  <span style={{ fontSize:18 }}>{typeEmoji[t]}</span>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:600, fontSize:13, flex:1, textTransform:"capitalize" }}>{t}</p>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:14, color:C.accent }}>{count}</p>
                </div>
              );
            })}
          </div>
        </div>
      )}

      {view==="list" && (
        <div>
          <div style={{ position:"relative", marginBottom:12 }}>
            <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search inventory..." style={{ width:"100%", padding:"10px 14px 10px 36px", borderRadius:11, background:C.surfaceHi, border:`1.5px solid ${C.border}`, color:C.text, fontSize:12.5 }} />
            <span style={{ position:"absolute", left:13, top:"50%", transform:"translateY(-50%)", fontSize:12, color:C.textDim }}>🔍</span>
          </div>
          <div style={{ display:"flex", gap:6, overflowX:"auto", marginBottom:12, paddingBottom:4 }}>
            {["all",...types].map(t=>(
              <Pill key={t} color={filterType===t?C.mint:C.textMid} active={filterType===t} onClick={()=>setFilterType(t)} small style={{ cursor:"pointer", textTransform:"capitalize" }}>{t}</Pill>
            ))}
          </div>
          {filtered.map(item=>(
            <div key={item.id} style={{ background:C.surface, border:`1.5px solid ${C.border}`, borderRadius:16, padding:12, marginBottom:10, display:"flex", gap:10, alignItems:"flex-start" }}>
              <div style={{ width:42,height:42,borderRadius:11,background:C.surfaceHi,border:`1.5px solid ${C.border}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0 }}>{typeEmoji[item.type]||"📦"}</div>
              <div style={{ flex:1 }}>
                <div style={{ display:"flex", gap:6, alignItems:"center", marginBottom:3 }}>
                  <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13 }}>{item.member||item.group}</p>
                  {item.tradeable&&<Pill color={C.mint} xs>Trade</Pill>}
                </div>
                <p style={{ fontSize:11, color:C.textMid }}>{item.group} · {item.era} · {item.condition}</p>
                <div style={{ display:"flex", gap:6, marginTop:6 }}>
                  <Pill color={C.silver} xs>{item.source}</Pill>
                  {item.duplicateCount>1&&<Pill color={C.gold} xs>x{item.duplicateCount}</Pill>}
                </div>
              </div>
              <div style={{ textAlign:"right" }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:13, color:C.mint }}>${item.estimatedValue}</p>
                <button onClick={()=>setItems(items.filter(i=>i.id!==item.id))} style={{ background:"none",border:"none",color:C.textDim,cursor:"pointer",fontSize:12,marginTop:4 }}>🗑️</button>
              </div>
            </div>
          ))}
          {filtered.length===0&&<Empty emoji="📦" title="No items found" sub="Add your collection items." action="+ Add Item" onAction={()=>setAdding(true)} />}
        </div>
      )}

      {adding && (
        <div onClick={()=>setAdding(false)} style={{ position:"fixed",inset:0,zIndex:400,background:"rgba(6,6,15,0.92)",display:"flex",alignItems:"flex-end",animation:"in .2s ease" }}>
          <div onClick={e=>e.stopPropagation()} style={{ background:C.surfaceHi,borderRadius:"22px 22px 0 0",padding:22,width:"100%",animation:"slideUp .25s ease",maxHeight:"90vh",overflowY:"auto" }}>
            <div style={{ width:34,height:4,borderRadius:99,background:C.border,margin:"0 auto 18px" }} />
            <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:17, marginBottom:16 }}>Add to Inventory</p>
            <div style={{ marginBottom:12 }}>
              <p style={{ fontSize:9.5,color:C.textMid,marginBottom:7,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Item Type</p>
              <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                {types.map(t=><Pill key={t} color={form.type===t?C.mint:C.textMid} active={form.type===t} onClick={()=>setForm({...form,type:t})} small style={{ cursor:"pointer", textTransform:"capitalize" }}>{typeEmoji[t]} {t}</Pill>)}
              </div>
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
              <Input label="Group *" value={form.group} onChange={e=>setForm({...form,group:e.target.value})} placeholder="e.g. BTS" />
              {form.type==="photocard"&&<Input label="Member" value={form.member} onChange={e=>setForm({...form,member:e.target.value})} placeholder="e.g. Jimin" />}
              <Input label="Era / Album" value={form.era} onChange={e=>setForm({...form,era:e.target.value})} placeholder="e.g. FACE" />
              <Input label="Est. Value ($)" type="number" value={form.estimatedValue} onChange={e=>setForm({...form,estimatedValue:Number(e.target.value)})} />
            </div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
              <div>
                <p style={{ fontSize:9.5,color:C.textMid,marginBottom:5,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Condition</p>
                <select value={form.condition} onChange={e=>setForm({...form,condition:e.target.value})} style={{ width:"100%",padding:"10px 12px",borderRadius:11,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12 }}>
                  {["mint","good","worn","damaged","sealed","opened"].map(c=><option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div>
                <p style={{ fontSize:9.5,color:C.textMid,marginBottom:5,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textTransform:"uppercase",letterSpacing:"0.07em" }}>Source</p>
                <select value={form.source} onChange={e=>setForm({...form,source:e.target.value})} style={{ width:"100%",padding:"10px 12px",borderRadius:11,background:C.surfaceHi,border:`1.5px solid ${C.border}`,color:C.text,fontSize:12 }}>
                  {["album pull","concert merch","trade","gift","Mercari","eBay","Weverse","Target","local shop","fan event"].map(s=><option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            <div style={{ marginBottom:12 }}><Textarea label="Notes" value={form.notes} onChange={e=>setForm({...form,notes:e.target.value})} placeholder="Any details..." style={{ height:60 }} /></div>
            <div style={{ display:"flex", gap:8, alignItems:"center", marginBottom:18 }}>
              <Toggle on={form.tradeable} onChange={v=>setForm({...form,tradeable:v})} color={C.mint} />
              <p style={{ fontSize:12.5, color:C.textMid }}>Mark as tradeable</p>
            </div>
            <div style={{ display:"flex", gap:10 }}>
              <Btn onClick={saveItem} disabled={!form.group.trim()} style={{ flex:1 }} small>Save Item</Btn>
              <Btn ghost color={C.textMid} onClick={()=>setAdding(false)} style={{ width:82,flex:"none" }} small>Cancel</Btn>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

// ─── K-POP MEME REACTION SYSTEM ──────────────────────────────────────────────
const MOCK_MEMES = [
  { id:"m1", cat:"crying", emoji:"😭", title:"When the encore starts", reactions:2841, saved:false, color:C.pink },
  { id:"m2", cat:"chaotic", emoji:"🤡", title:"Bias wrecked again", reactions:5102, saved:false, color:C.rose },
  { id:"m3", cat:"delulu", emoji:"✨", title:"Manifesting hi-touch", reactions:3390, saved:false, color:C.accent },
  { id:"m4", cat:"concert", emoji:"🎤", title:"Front row energy", reactions:1820, saved:false, color:C.gold },
  { id:"m5", cat:"crying", emoji:"💜", title:"Post-concert depression real", reactions:7210, saved:false, color:C.silver },
  { id:"m6", cat:"chaotic", emoji:"😤", title:"When they skip your fave song", reactions:4480, saved:false, color:C.coral },
  { id:"m7", cat:"delulu", emoji:"🌸", title:"'He looked at me'", reactions:6320, saved:false, color:C.pink },
  { id:"m8", cat:"concert", emoji:"💃", title:"Making it to the barricade", reactions:2150, saved:false, color:C.mint },
];

function MemeSystem({ onSendMeme, compact=false }) {
  const [memes, setMemes] = useState(ls.get("backstage_memes", MOCK_MEMES));
  const [catFilter, setCatFilter] = useState("all");
  const [reacted, setReacted] = useState({});
  const [sent, setSent] = useState(null);

  const toggleSave = (id) => {
    const next = memes.map(m=>m.id===id?{...m,saved:!m.saved}:m);
    setMemes(next); ls.set("backstage_memes", next);
  };

  const react = (id) => {
    setReacted(r=>({...r,[id]:!r[id]}));
    setMemes(memes.map(m=>m.id===id?{...m,reactions:m.reactions+(reacted[id]?-1:1)}:m));
  };

  const filtered = catFilter==="all" ? memes : catFilter==="saved" ? memes.filter(m=>m.saved) : memes.filter(m=>m.cat===catFilter);

  return (
    <div>
      <div style={{ display:"flex", gap:6, overflowX:"auto", paddingBottom:8, marginBottom:12 }}>
        {[["all","All"],["crying","😭 Crying"],["chaotic","🤡 Chaotic"],["delulu","✨ Delulu"],["concert","🎤 Concert"],["saved","🔖 Saved"]].map(([id,label])=>(
          <span key={id} onClick={()=>setCatFilter(id)} className="tap" style={{ flexShrink:0, padding:"5px 11px", borderRadius:99, fontSize:10, fontFamily:"'Epilogue',sans-serif", fontWeight:600, cursor:"pointer", background:catFilter===id?C.pink:C.surfaceHi, color:catFilter===id?C.bg:C.textMid, border:`1px solid ${catFilter===id?C.pink:C.border}`, whiteSpace:"nowrap" }}>{label}</span>
        ))}
      </div>

      {sent&&(
        <div style={{ background:`${C.mint}18`, border:`1.5px solid ${C.mint}44`, borderRadius:13, padding:"9px 14px", marginBottom:12, animation:"pop .3s ease", display:"flex", alignItems:"center", gap:8 }}>
          <span style={{ fontSize:18 }}>{sent.emoji}</span>
          <p style={{ fontSize:12, color:C.mint, fontFamily:"'Epilogue',sans-serif", fontWeight:600 }}>Meme sent! 🎉</p>
          <button onClick={()=>setSent(null)} style={{ marginLeft:"auto", background:"none", border:"none", color:C.textMid, cursor:"pointer" }}>✕</button>
        </div>
      )}

      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10 }}>
        {filtered.map(meme=>(
          <div key={meme.id} style={{ background:`linear-gradient(160deg,${meme.color}18,${meme.color}06)`, border:`1.5px solid ${meme.color}30`, borderRadius:16, padding:12, position:"relative" }}>
            <div style={{ fontSize:36, textAlign:"center", marginBottom:8 }}>{meme.emoji}</div>
            <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:11.5, textAlign:"center", marginBottom:10, lineHeight:1.4 }}>{meme.title}</p>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <button onClick={()=>react(meme.id)} className="tap" style={{ background:"none", border:"none", color:reacted[meme.id]?C.rose:C.textMid, cursor:"pointer", fontSize:11, display:"flex", alignItems:"center", gap:3 }}>
                {reacted[meme.id]?"♥":"♡"} {meme.reactions.toLocaleString()}
              </button>
              <div style={{ display:"flex", gap:6 }}>
                <button onClick={()=>toggleSave(meme.id)} style={{ background:"none", border:"none", color:meme.saved?C.gold:C.textDim, cursor:"pointer", fontSize:13 }}>{meme.saved?"🔖":"🏷️"}</button>
                {onSendMeme&&<button onClick={()=>{onSendMeme(meme);setSent(meme);setTimeout(()=>setSent(null),2500);}} style={{ background:meme.color, border:"none", borderRadius:8, padding:"3px 8px", color:C.bg, fontSize:9.5, fontFamily:"'Epilogue',sans-serif", fontWeight:700, cursor:"pointer" }}>Send</button>}
              </div>
            </div>
          </div>
        ))}
        {filtered.length===0&&<div style={{ gridColumn:"1/-1" }}><Empty emoji="😭" title="No memes here" sub="Save some from the main feed!" /></div>}
      </div>
    </div>
  );
}

// ─── COMMUNITY ────────────────────────────────────────────────────────────────
// ─── FAN BUDDY MATCHER ────────────────────────────────────────────────────────
// TODO: POST /api/fans/match — real compatibility scoring via backend
// TODO: Real discovery requires opt-in + location/concert verification
function FanBuddyMatcher({ go }) {
  const [travelFilter, setTravelFilter] = useState("all");
  const [expFilter, setExpFilter]       = useState("all");
  const [lookingFor, setLookingFor]     = useState("all");
  const [sentRequests, setSentRequests] = useState(()=>ls.get("backstage_buddy_requests",{}));
  const [discoveryOn, setDiscoveryOn]   = useState(ls.get("backstage_discovery_on", false));

  // Compatibility scoring mock
  // TODO: Real algorithm via /api/fans/match?concertId=X&userId=Y
  const scoreCompatibility = (fan) => {
    let score = 60; // base
    if(fan.experience==="veteran") score += 10;
    if(fan.solo) score += 8;
    if(fan.travelStatus==="traveling") score += 7;
    if(fan.trust >= 4.8) score += 10;
    if(fan.bias && fan.bias === "Karina") score += 5; // mock user bias match
    return Math.min(score, 99);
  };

  const filtered = MOCK_NEARBY.filter(f=>{
    if(travelFilter!=="all"&&f.travelStatus!==travelFilter) return false;
    if(expFilter!=="all"&&f.experience!==expFilter) return false;
    if(lookingFor!=="all"&&f.lookingFor!==lookingFor) return false;
    return true;
  }).sort((a,b)=>scoreCompatibility(b)-scoreCompatibility(a));

  const sendRequest = (id) => {
    const next = {...sentRequests,[id]:true};
    setSentRequests(next);
    ls.set("backstage_buddy_requests", next);
    // TODO: POST /api/fans/buddy-request — notify fan via Supabase Realtime
    // TODO: In production: add to user's notification inbox on their end
  };

  const EXPERIENCE_COLORS = { "veteran":C.gold, "intermediate":C.accent, "first-time":C.mint };
  const TRAVEL_ICONS = { "local":"📍", "nearby":"🚗", "traveling":"✈️" };

  return (
    <div style={{ paddingTop:4 }}>
      {/* Discovery toggle */}
      <div style={{ background:discoveryOn?`${C.mint}12`:C.surface, border:`1.5px solid ${discoveryOn?C.mint:C.border}`, borderRadius:16, padding:"12px 14px", marginBottom:16, display:"flex", gap:12, alignItems:"center" }}>
        <span style={{ fontSize:20 }}>{discoveryOn?"🟢":"🔒"}</span>
        <div style={{ flex:1 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13 }}>{discoveryOn?"Discovery On — fans can find you":"Fan Discovery Off"}</p>
          <p style={{ fontSize:10.5,color:C.textMid }}>{discoveryOn?"Visible to fans at your confirmed concerts · opt-out anytime":"Turn on to let fans at the same shows connect with you"}</p>
        </div>
        <button onClick={()=>{ const next=!discoveryOn; setDiscoveryOn(next); ls.set("backstage_discovery_on",next); }} style={{ padding:"8px 14px",borderRadius:11,background:discoveryOn?`${C.mint}22`:`linear-gradient(140deg,${C.mint}cc,${C.mintDim})`,border:discoveryOn?`1.5px solid ${C.mint}`:"none",color:discoveryOn?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>
          {discoveryOn?"Turn Off":"Turn On"}
        </button>
      </div>

      {/* Live stats */}
      <div style={{ display:"flex",gap:8,marginBottom:14 }}>
        {[["👥","412","going nearby",C.mint],["🤝","23","buddy requests",C.pink],["🎉","8","meetups today",C.gold]].map(([icon,val,label,color])=>(
          <div key={label} style={{ flex:1,...VS.glowCard(color),padding:"10px 6px",textAlign:"center" }}>
            <p style={{ fontSize:16,marginBottom:2 }}>{icon}</p>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:17,color,lineHeight:1,position:"relative" }}>{val}</p>
            <p style={{ fontSize:8,color:C.textMid,marginTop:3,position:"relative" }}>{label}</p>
          </div>
        ))}
      </div>

      {/* Filters */}
      <div style={{ marginBottom:12 }}>
        <p style={{ ...VS.softSectionHeader,marginBottom:8 }}>Filter Fans</p>
        <div style={{ display:"flex",gap:6,marginBottom:7,overflowX:"auto",scrollbarWidth:"none" }}>
          {[["all","All Fans"],["local","📍 Local"],["nearby","🚗 Nearby"],["traveling","✈️ Traveling"]].map(([id,label])=>(
            <button key={id} onClick={()=>setTravelFilter(id)} style={{ flexShrink:0,padding:"5px 11px",borderRadius:99,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",background:travelFilter===id?C.accent:`${C.accent}10`,color:travelFilter===id?C.bg:C.textMid,border:`1px solid ${travelFilter===id?C.accent:C.border}` }}>{label}</button>
          ))}
        </div>
        <div style={{ display:"flex",gap:6,overflowX:"auto",scrollbarWidth:"none" }}>
          {[["all","Any Experience"],["first-time","First Show 🌟"],["intermediate","Regular"],["veteran","Veteran 👑"]].map(([id,label])=>(
            <button key={id} onClick={()=>setExpFilter(id)} style={{ flexShrink:0,padding:"5px 11px",borderRadius:99,fontSize:10,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer",background:expFilter===id?C.pink:`${C.pink}10`,color:expFilter===id?C.bg:C.textMid,border:`1px solid ${expFilter===id?C.pink:C.border}` }}>{label}</button>
          ))}
        </div>
      </div>

      {/* Fan cards with compatibility score */}
      <p style={{ ...VS.softSectionHeader,marginBottom:10 }}>{filtered.length} fans matched</p>
      {filtered.map(fan=>{
        const score = scoreCompatibility(fan);
        const scoreColor = score>=85?C.mint:score>=70?C.gold:C.accent;
        return (
          <div key={fan.id} style={{ ...VS.glowCard(fan.color),padding:"13px 14px",marginBottom:11 }}>
            <div style={{ position:"absolute",top:-8,right:-8,width:55,height:55,borderRadius:"50%",background:`radial-gradient(circle,${fan.color}18,transparent 65%)`,pointerEvents:"none" }} />
            <div style={{ display:"flex",gap:11,alignItems:"center",marginBottom:10,position:"relative" }}>
              {/* Avatar */}
              <div style={{ position:"relative",flexShrink:0 }}>
                <div style={{ width:50,height:50,borderRadius:"50%",background:`linear-gradient(135deg,${fan.color},${fan.color}66)`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19,color:C.bg,boxShadow:`0 0 14px ${fan.color}33` }}>{fan.avatar}</div>
                {/* Travel icon */}
                <div style={{ position:"absolute",bottom:-2,right:-2,width:18,height:18,borderRadius:"50%",background:C.bg,display:"flex",alignItems:"center",justifyContent:"center",fontSize:11 }}>{TRAVEL_ICONS[fan.travelStatus]||"📍"}</div>
              </div>
              <div style={{ flex:1,minWidth:0 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5 }}>{fan.name}</p>
                <p style={{ fontSize:10,color:C.textMid }}>📍 {fan.city} · ★ {fan.trust} · 🎤 {fan.concerts} shows</p>
                <div style={{ display:"flex",gap:5,marginTop:4,alignItems:"center",flexWrap:"wrap" }}>
                  <div style={{ ...VS.activePill(EXPERIENCE_COLORS[fan.experience]||C.accent),fontSize:8 }}>{fan.experience==="first-time"?"First Show 🌟":fan.experience==="veteran"?"Veteran 👑":"Regular"}</div>
                  {fan.section&&<div style={{ ...VS.mutedPill,fontSize:8 }}>Sec {fan.section}</div>}
                  {fan.bias&&<div style={{ ...VS.mutedPill,fontSize:8 }}>Bias: {fan.bias}</div>}
                </div>
              </div>
              {/* Compatibility score */}
              <div style={{ textAlign:"center",background:`${scoreColor}18`,border:`1.5px solid ${scoreColor}33`,borderRadius:12,padding:"6px 10px",flexShrink:0 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:scoreColor,lineHeight:1 }}>{score}%</p>
                <p style={{ fontSize:7.5,color:C.textMid }}>match</p>
              </div>
            </div>
            {/* Tags */}
            <div style={{ display:"flex",gap:5,flexWrap:"wrap",marginBottom:10,position:"relative" }}>
              {fan.groups.map(g=><Pill key={g} color={fan.color} xs>{g}</Pill>)}
              {fan.tags.map(t=><Pill key={t} color={C.silver} xs>{t}</Pill>)}
              <Pill color={C.textMid} xs>{fan.lookingFor==="group"?"Looking for group":fan.lookingFor==="buddy"?"Looking for buddy":"Looking for friend"}</Pill>
            </div>
            {/* Actions */}
            <div style={{ display:"flex",gap:8 }}>
              <button
                onClick={()=>sendRequest(fan.id)}
                disabled={sentRequests[fan.id]}
                style={{ flex:1,padding:"9px",borderRadius:12,background:sentRequests[fan.id]?`${C.mint}18`:`linear-gradient(140deg,${fan.color}cc,${fan.color}88)`,border:sentRequests[fan.id]?`1.5px solid ${C.mint}`:"none",color:sentRequests[fan.id]?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer" }}
              >
                {sentRequests[fan.id]?"✓ Request Sent":"🤝 Buddy Request"}
              </button>
              <button onClick={()=>go&&go("chats")} style={{ padding:"9px 13px",borderRadius:12,background:`${C.accent}18`,border:`1.5px solid ${C.accent}33`,color:C.accent,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,cursor:"pointer",flexShrink:0 }}>💬 DM</button>
            </div>
          </div>
        );
      })}
      {filtered.length===0&&<div style={{ textAlign:"center",padding:"32px 20px" }}><p style={{ fontSize:28,marginBottom:10 }}>👥</p><p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,marginBottom:6 }}>No fans match this filter</p><p style={{ fontSize:11,color:C.textMid }}>Try removing some filters</p></div>}
    </div>
  );
}

// ─── CONCERT BUDGET TRACKER ───────────────────────────────────────────────────
// TODO: Sync via Supabase for cross-device totals when signed in
function BudgetTracker({ onBack }) {
  const KEY = "backstage_concert_budget";
  const [entries, setEntries] = useState(()=>ls.get(KEY,[
    { id:"e1", category:"tickets",  label:"BTS Dallas Floor Tickets", amount:320,  icon:"🎟️" },
    { id:"e2", category:"flights",  label:"Round-trip DFW",           amount:280,  icon:"✈️" },
    { id:"e3", category:"hotel",    label:"2 nights downtown Dallas",  amount:180,  icon:"🏨" },
    { id:"e4", category:"merch",    label:"Official merch + lightstick",amount:95,  icon:"👕" },
    { id:"e5", category:"food",     label:"Pre/post concert food",     amount:65,   icon:"🍜" },
  ]));
  const [adding, setAdding]   = useState(false);
  const [form, setForm]       = useState({ category:"merch", label:"", amount:"" });
  const [shareMode, setShareMode] = useState(false);

  useEffect(()=>{ ls.set(KEY, entries); }, [entries]);

  const CATS = [
    { id:"tickets",  label:"Tickets",   icon:"🎟️", color:C.pink   },
    { id:"flights",  label:"Flights",   icon:"✈️", color:C.sky    },
    { id:"hotel",    label:"Hotel",     icon:"🏨", color:C.accent },
    { id:"merch",    label:"Merch",     icon:"👕", color:C.gold   },
    { id:"food",     label:"Food",      icon:"🍜", color:C.mint   },
    { id:"other",    label:"Other",     icon:"💸", color:C.silver },
  ];

  const total = entries.reduce((s,e)=>s+Number(e.amount||0),0);
  const byCat = CATS.map(c=>({...c, sum:entries.filter(e=>e.category===c.id).reduce((s,e)=>s+Number(e.amount||0),0)})).filter(c=>c.sum>0);

  const addEntry = () => {
    if(!form.label.trim()||!form.amount) return;
    const cat = CATS.find(c=>c.id===form.category);
    setEntries([...entries,{id:`e-${Date.now()}`,category:form.category,label:form.label,amount:Number(form.amount),icon:cat?.icon||"💸"}]);
    setForm({category:"merch",label:"",amount:""});
    setAdding(false);
  };

  const REACTIONS = ["🤡","😭","🙃","💸","✨","💜"];
  const reactionForTotal = total > 500 ? "🤡" : total > 300 ? "😭" : total > 150 ? "🙃" : "✨";

  return (
    <div style={{ height:"100%",display:"flex",flexDirection:"column",overflow:"hidden",background:C.bg }}>
      <div style={{ padding:"16px 20px 14px",display:"flex",alignItems:"center",gap:10,flexShrink:0,borderBottom:`1px solid ${C.border}` }}>
        <button onClick={onBack} style={{ background:"none",border:"none",color:C.textMid,fontSize:22,cursor:"pointer" }}>←</button>
        <h2 style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19,flex:1 }}>Concert Budget 💸</h2>
        <button onClick={()=>setAdding(v=>!v)} style={{ background:C.accent,border:"none",borderRadius:11,padding:"7px 14px",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11.5,cursor:"pointer" }}>+ Add</button>
      </div>

      <Screen style={{ padding:"0 20px calc(120px + env(safe-area-inset-bottom))" }}>
        {/* Total hero */}
        <div style={{ ...VS.glowCard(C.pink),padding:"20px 18px",marginBottom:18,textAlign:"center" }}>
          <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.pink}55,transparent)` }} />
          <div style={{ position:"relative" }}>
            <p style={{ fontSize:13,color:C.textMid,marginBottom:6 }}>This era cost me</p>
            <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:44,color:C.pink,letterSpacing:"-0.04em",lineHeight:1 }}>${total.toFixed(0)}</p>
            <p style={{ fontSize:28,marginTop:6 }}>{reactionForTotal}</p>
            <p style={{ fontSize:10.5,color:C.textMid,marginTop:4,fontStyle:"italic" }}>Worth every cent 💜</p>
            <button onClick={()=>setShareMode(v=>!v)} style={{ marginTop:12,padding:"8px 18px",borderRadius:12,background:`${C.pink}18`,border:`1.5px solid ${C.pink}33`,color:C.pink,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer" }}>📤 Share Breakdown</button>
          </div>
        </div>

        {/* Shareable summary */}
        {shareMode&&(
          <div style={{ ...VS.glowCard(C.accent),padding:"14px 16px",marginBottom:16,animation:"up .2s ease" }}>
            <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${C.accent}55,transparent)` }} />
            <div style={{ position:"relative" }}>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12,color:C.accent,marginBottom:8 }}>Share this breakdown</p>
              <div style={{ background:C.surface,borderRadius:12,padding:"12px 14px",fontFamily:"'Epilogue',sans-serif" }}>
                <p style={{ fontWeight:800,fontSize:14,marginBottom:6 }}>My concert era cost me ${total.toFixed(0)} {reactionForTotal}</p>
                {byCat.map(c=><p key={c.id} style={{ fontSize:12,color:C.textMid,marginBottom:3 }}>{c.icon} {c.label}: ${c.sum}</p>)}
                <p style={{ fontSize:10,color:C.textDim,marginTop:6 }}>tracked on Backstage · @backstage_app</p>
              </div>
              <p style={{ fontSize:9.5,color:C.textDim,marginTop:8,textAlign:"center" }}>Screenshot and post · no API required {/* TODO: native share API */}</p>
            </div>
          </div>
        )}

        {/* Add entry form */}
        {adding&&(
          <div style={{ background:C.surfaceHi,border:`1.5px solid ${C.borderHi}`,borderRadius:16,padding:14,marginBottom:14,animation:"up .2s ease" }}>
            <div style={{ display:"flex",gap:7,overflowX:"auto",scrollbarWidth:"none",marginBottom:11 }}>
              {CATS.map(c=>(
                <button key={c.id} onClick={()=>setForm(f=>({...f,category:c.id}))} style={{ flexShrink:0,padding:"6px 11px",borderRadius:99,background:form.category===c.id?c.color:`${c.color}12`,border:`1px solid ${form.category===c.id?c.color:C.border}`,color:form.category===c.id?C.bg:C.textMid,fontSize:10.5,fontFamily:"'Epilogue',sans-serif",fontWeight:700,cursor:"pointer" }}>{c.icon} {c.label}</button>
              ))}
            </div>
            <Input label="Description" value={form.label} onChange={e=>setForm(f=>({...f,label:e.target.value}))} placeholder="e.g. Official lightstick" style={{ marginBottom:9 }} />
            <Input label="Amount ($)" type="number" value={form.amount} onChange={e=>setForm(f=>({...f,amount:e.target.value}))} placeholder="0.00" style={{ marginBottom:12 }} />
            <div style={{ display:"flex",gap:9 }}>
              <button onClick={addEntry} disabled={!form.label.trim()||!form.amount} style={{ flex:1,padding:"10px",borderRadius:13,background:form.label.trim()&&form.amount?`linear-gradient(140deg,${C.accent}cc,${C.accentDim})`:`${C.accent}33`,border:"none",color:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:12.5,cursor:"pointer" }}>Add</button>
              <button onClick={()=>setAdding(false)} style={{ padding:"10px 16px",borderRadius:13,background:"transparent",border:`1px solid ${C.border}`,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12.5,cursor:"pointer" }}>Cancel</button>
            </div>
          </div>
        )}

        {/* Category breakdown */}
        {byCat.length>0&&(
          <div style={{ marginBottom:16 }}>
            <p style={VS.softSectionHeader}>Breakdown</p>
            <div style={{ display:"grid",gridTemplateColumns:"1fr 1fr",gap:9,marginTop:10 }}>
              {byCat.map(c=>(
                <div key={c.id} style={{ ...VS.glowCard(c.color),padding:"11px 12px" }}>
                  <div style={{ position:"absolute",top:0,left:0,right:0,height:1,background:`linear-gradient(90deg,transparent,${c.color}44,transparent)` }} />
                  <p style={{ fontSize:18,marginBottom:4,position:"relative" }}>{c.icon}</p>
                  <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:900,fontSize:18,color:c.color,lineHeight:1,position:"relative" }}>${c.sum}</p>
                  <p style={{ fontSize:9.5,color:C.textMid,marginTop:3,position:"relative" }}>{c.label}</p>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* All entries */}
        <p style={VS.softSectionHeader}>All Items</p>
        {entries.map(e=>{
          const cat = CATS.find(c=>c.id===e.category);
          return (
            <div key={e.id} style={{ background:C.surface,border:`1px solid ${C.border}`,borderRadius:13,padding:"11px 13px",marginBottom:8,display:"flex",alignItems:"center",gap:10 }}>
              <span style={{ fontSize:18,flexShrink:0 }}>{e.icon}</span>
              <p style={{ flex:1,fontFamily:"'Epilogue',sans-serif",fontWeight:600,fontSize:12.5 }}>{e.label}</p>
              <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:14,color:cat?.color||C.accent }}>${Number(e.amount).toFixed(0)}</p>
              <button onClick={()=>setEntries(es=>es.filter(x=>x.id!==e.id))} style={{ background:"none",border:"none",color:C.textDim,cursor:"pointer",fontSize:14 }}>✕</button>
            </div>
          );
        })}
        {entries.length===0&&<div style={{ textAlign:"center",padding:"32px 0" }}><p style={{ fontSize:24 }}>💸</p><p style={{ fontSize:13,color:C.textMid,marginTop:10 }}>Start tracking your concert spending</p></div>}
      </Screen>
    </div>
  );
}

// ─── FANVERSE LEADERS — full leaderboard with Collectors / Traders / Cities ──
function FanverseLeaders() {
  const [lbTab, setLbTab] = useState("cities");

  const rows = lbTab==="cities"
    ? MOCK_LEADERBOARD.cities.map((r,i)=>({ rank:i+1, name:r.city, sub:`${r.fans.toLocaleString()} fans active`, color:[C.gold,C.silver,C.accent][i]||C.border, icon:"🏙️" }))
    : lbTab==="collectors"
    ? MOCK_LEADERBOARD.collectors.map((r,i)=>({ rank:i+1, name:r.name, sub:`${r.count} cards collected`, color:[C.gold,C.silver,C.accent][i]||C.border, icon:"🃏" }))
    : MOCK_LEADERBOARD.traders.map((r,i)=>({ rank:i+1, name:r.name, sub:`${r.count} trades completed`, color:[C.gold,C.silver,C.accent][i]||C.border, icon:"⇄" }));

  return (
    <div style={{ flex:1, overflowY:"auto", padding:"14px 18px 100px" }}>
      {/* Sub-tab switcher */}
      <div style={{ display:"flex", gap:7, marginBottom:18 }}>
        {[["cities","🏙️ Cities"],["collectors","🃏 Collectors"],["traders","⇄ Traders"]].map(([id,label])=>(
          <button key={id} onClick={()=>setLbTab(id)} className="tap" style={{ flexShrink:0, padding:"8px 14px", borderRadius:99, fontSize:10.5, fontFamily:"'Epilogue',sans-serif", fontWeight:700, cursor:"pointer", background:lbTab===id?`linear-gradient(140deg,${C.gold}cc,${C.goldDim})`:C.surfaceHi, color:lbTab===id?C.bg:C.textMid, border:`1px solid ${lbTab===id?C.gold:C.border}`, boxShadow:lbTab===id?`0 4px 14px ${C.gold}28`:"none" }}>{label}</button>
        ))}
      </div>

      {/* Rows */}
      {rows.map((item,i)=>(
        <div key={i} style={{ ...VS.glowCard(item.color), padding:"14px 16px", marginBottom:10, display:"flex", gap:12, alignItems:"center" }}>
          <div style={VS.innerGlow(item.color)} />
          <div style={{ position:"relative", width:42, height:42, borderRadius:"50%", background:`${item.color}22`, border:`1.5px solid ${item.color}44`, display:"flex", alignItems:"center", justifyContent:"center", fontFamily:"'Epilogue',sans-serif", fontWeight:800, fontSize:14, color:item.color, flexShrink:0 }}>
            {i===0?"👑":`#${i+1}`}
          </div>
          <div style={{ flex:1, position:"relative" }}>
            <p style={{ fontFamily:"'Epilogue',sans-serif", fontWeight:700, fontSize:13.5 }}>{item.name}</p>
            <p style={{ fontSize:11, color:C.textMid }}>{item.sub}</p>
          </div>
          <div style={{ fontSize:20 }}>{i===0?"🏆":item.icon}</div>
        </div>
      ))}

      {/* This week badge */}
      <div style={{ background:`${C.accent}08`, border:`1px solid ${C.accent}22`, borderRadius:12, padding:"10px 14px", textAlign:"center", marginTop:8 }}>
        <p style={{ fontSize:11, color:C.textMid }}>Rankings update weekly · based on verified activity ✦</p>
      </div>
    </div>
  );
}

// ─── FAN DISCOVERY ────────────────────────────────────────────────────────────
// Horizontal strip shown at top of Feed view
function FansVibeStrip({ fans, onViewProfile }) {
  if (!fans || fans.length === 0) return null;
  const STRIP_COLORS = [C.accent, C.pink, C.mint, C.gold, C.rose, C.berry, C.lavender, C.teal];
  const fanCol = (fan) => { const s=(fan.id||'').split('').reduce((a,c)=>a+c.charCodeAt(0),0); return STRIP_COLORS[s%STRIP_COLORS.length]; };
  return (
    <div style={{ padding:"10px 18px 2px", flexShrink:0, borderBottom:`1px solid ${C.border}` }}>
      <p style={{ fontSize:9,color:C.textMid,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textTransform:"uppercase",letterSpacing:"0.12em",marginBottom:8 }}>Fans you might vibe with ✦</p>
      <div style={{ display:"flex",gap:14,overflowX:"auto",scrollbarWidth:"none",paddingBottom:10 }}>
        {fans.slice(0,6).map(fan=>{
          const col = fanCol(fan);
          return (
            <div key={fan.id} onClick={()=>onViewProfile&&onViewProfile(fan)} className="tap" style={{ flexShrink:0,display:"flex",flexDirection:"column",alignItems:"center",gap:4,cursor:"pointer",width:56 }}>
              <div style={{ width:44,height:44,borderRadius:"50%",background:`linear-gradient(135deg,${col},${col}88)`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:17,color:C.bg,boxShadow:`0 0 10px ${col}40`,border:`1.5px solid ${col}55` }}>{fan.avatar}</div>
              <p style={{ fontSize:8.5,color:C.text,fontFamily:"'Epilogue',sans-serif",fontWeight:700,textAlign:"center",maxWidth:54,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{fan.display_name||fan.handle}</p>
              {(fan.fandoms||[])[0]&&<p style={{ fontSize:7.5,color:col,fontFamily:"'Epilogue',sans-serif",fontWeight:600,textAlign:"center",maxWidth:54,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap" }}>{fan.fandoms[0]}</p>}
            </div>
          );
        })}
      </div>
    </div>
  );
}

// Full fan discovery tab — "Fans" view inside FanverseTab
function FanDiscoverySection({ user, fans, loading, onViewProfile }) {
  const DISC_KEY = "backstage_discovery_on";
  const AVATAR_COLORS = [C.accent, C.pink, C.mint, C.gold, C.rose, C.berry, C.lavender, C.teal];
  const fanCol = (fan) => { const s=(fan.id||'').split('').reduce((a,c)=>a+c.charCodeAt(0),0); return AVATAR_COLORS[s%AVATAR_COLORS.length]; };

  const [statuses,     setStatuses]     = useState(()=>ls.get("backstage_circle_statuses",{}));
  const [discoverable, setDiscoverable] = useState(()=>ls.get(DISC_KEY, true));
  const [togglingDisc, setTogglingDisc] = useState(false);

  const addToCircle = async (fan) => {
    const next = {...statuses, [fan.id]:"sent"};
    setStatuses(next);
    ls.set("backstage_circle_statuses", next);
    api.post('/api/friends/request', { targetUserId: fan.id }).catch(()=>{});
  };

  const toggleDiscoverable = async () => {
    if (togglingDisc) return;
    const next = !discoverable;
    setTogglingDisc(true);
    setDiscoverable(next);
    ls.set(DISC_KEY, next);
    await api.post('/api/profile/update', { discoverable: next }).catch(()=>{});
    setTogglingDisc(false);
  };

  const getReasons = (fan) => {
    const reasons = [];
    const myFandoms  = user?.favorite_groups || user?.fandoms || [];
    const myBias     = user?.bias || "";
    const myCity     = (user?.city || "").split(",")[0].trim().toLowerCase();
    const myNpArtist = (user?.now_playing || ls.get(`backstage_now_playing_${user?.id||'anon'}`) || {})?.artist || "";
    const shared = (fan.fandoms||[]).filter(f=>myFandoms.includes(f));
    if (shared.length)  reasons.push(`🎵 Both stan ${shared[0]}`);
    if (fan.city && myCity && fan.city.toLowerCase().includes(myCity)) reasons.push(`📍 ${fan.city}`);
    if (myBias && fan.bias && fan.bias === myBias)  reasons.push(`🎤 Same bias: ${fan.bias}`);
    if (myNpArtist && fan.now_playing?.artist === myNpArtist) reasons.push(`🎧 ${myNpArtist}`);
    return reasons.slice(0, 2);
  };

  return (
    <div style={{ flex:1, overflowY:"auto", overflowX:"hidden", padding:"14px 18px calc(120px + env(safe-area-inset-bottom))" }}>
      {/* Discoverable toggle */}
      <div style={{ background:discoverable?`${C.mint}12`:C.surface, border:`1.5px solid ${discoverable?C.mint:C.border}`, borderRadius:16, padding:"12px 14px", marginBottom:18, display:"flex", gap:12, alignItems:"center" }}>
        <span style={{ fontSize:20 }}>{discoverable?"🟢":"🔒"}</span>
        <div style={{ flex:1 }}>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13,color:C.text }}>{discoverable?"You're discoverable":"Hidden from discovery"}</p>
          <p style={{ fontSize:10.5,color:C.textMid,lineHeight:1.5 }}>{discoverable?"Fans with your vibe can find you · opt out anytime":"Turn on to let fans with similar taste find you"}</p>
        </div>
        <button onClick={toggleDiscoverable} disabled={togglingDisc} style={{ padding:"8px 14px",borderRadius:11,background:discoverable?`${C.mint}22`:`linear-gradient(140deg,${C.mint}cc,${C.mintDim})`,border:discoverable?`1.5px solid ${C.mint}`:"none",color:discoverable?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11,cursor:"pointer",flexShrink:0 }}>
          {discoverable?"Turn Off":"Turn On"}
        </button>
      </div>

      <p style={{ ...VS.softSectionHeader, marginBottom:14 }}>Fans you might vibe with ✦</p>

      {loading && <div style={{ textAlign:"center",padding:"32px 20px",color:C.textMid,fontSize:12 }}>Finding fans...</div>}

      {!loading && fans.length===0 && (
        <div style={{ textAlign:"center",padding:"32px 20px" }}>
          <p style={{ fontSize:32,marginBottom:12 }}>👥</p>
          <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:14,marginBottom:6 }}>No fan matches yet</p>
          <p style={{ fontSize:12,color:C.textMid,lineHeight:1.6 }}>As more fans join your fandoms, they'll appear here. Make sure your fandoms and bias are set in your profile.</p>
        </div>
      )}

      {!loading && fans.map(fan=>{
        const col = fanCol(fan);
        const status = statuses[fan.id];
        const reasons = getReasons(fan);
        return (
          <div key={fan.id} style={{ ...VS.glowCard(col), padding:"13px 14px", marginBottom:12 }}>
            <div style={{ position:"absolute",top:-8,right:-8,width:55,height:55,borderRadius:"50%",background:`radial-gradient(circle,${col}18,transparent 65%)`,pointerEvents:"none" }} />
            <div onClick={()=>onViewProfile&&onViewProfile(fan)} style={{ display:"flex",gap:12,alignItems:"flex-start",marginBottom:10,position:"relative",cursor:"pointer" }}>
              <div style={{ width:48,height:48,borderRadius:"50%",background:`linear-gradient(135deg,${col},${col}88)`,display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Epilogue',sans-serif",fontWeight:800,fontSize:19,color:C.bg,boxShadow:`0 0 14px ${col}40`,flexShrink:0 }}>
                {fan.avatar}
              </div>
              <div style={{ flex:1, minWidth:0 }}>
                <p style={{ fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:13.5,color:C.text,marginBottom:2 }}>{fan.display_name||fan.backstage_name}</p>
                <p style={{ fontSize:10,color:C.textMid,marginBottom:6 }}>@{fan.handle||fan.username}{fan.city?` · 📍 ${fan.city}`:""}</p>
                {fan.bio&&<p style={{ fontSize:11,color:C.textMid,lineHeight:1.5,marginBottom:6,overflow:"hidden",display:"-webkit-box",WebkitLineClamp:2,WebkitBoxOrient:"vertical" }}>{fan.bio}</p>}
                <div style={{ display:"flex",gap:4,flexWrap:"wrap",marginBottom:reasons.length?6:0 }}>
                  {(fan.fandoms||[]).slice(0,3).map(f=>(
                    <div key={f} style={{ ...VS.activePill(col),fontSize:8,padding:"3px 8px" }}>{f}</div>
                  ))}
                  {fan.is_vip&&<div style={{ ...VS.activePill(C.gold),fontSize:8,padding:"3px 8px" }}>✦ VIP</div>}
                </div>
                {reasons.length>0&&(
                  <div style={{ display:"flex",gap:4,flexWrap:"wrap" }}>
                    {reasons.map((r,i)=>(
                      <div key={i} style={{ display:"inline-flex",alignItems:"center",padding:"3px 9px",borderRadius:99,background:`${col}10`,border:`1px solid ${col}28`,color:C.textMid,fontSize:8.5,fontFamily:"'Epilogue',sans-serif",fontWeight:600 }}>{r}</div>
                    ))}
                  </div>
                )}
              </div>
            </div>
            <div style={{ position:"relative",display:"flex",gap:8 }}>
              <button
                onClick={()=>{ if(!status) addToCircle(fan); }}
                disabled={!!status}
                style={{ flex:1,padding:"9px 12px",borderRadius:12,background:status?`${C.mint}18`:`linear-gradient(140deg,${col}cc,${col}88)`,border:status?`1.5px solid ${C.mint}`:"none",color:status?C.mint:C.bg,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11.5,cursor:status?"default":"pointer" }}
              >
                {status==="sent"?"✓ Requested":status==="accepted"?"In Circle ✦":"Add to Circle"}
              </button>
              <button
                onClick={()=>onViewProfile&&onViewProfile(fan)}
                style={{ padding:"9px 14px",borderRadius:12,background:`${col}18`,border:`1.5px solid ${col}33`,color:col,fontFamily:"'Epilogue',sans-serif",fontWeight:700,fontSize:11.5,cursor:"pointer",flexShrink:0 }}
              >
                View →
              </button>
            </div>
          </div>
        );
      })}
    </div>
  );
}

