                  <div style={{ width:34,height:34,borderRadius:10,background:`${C.gold}18`,border:`1.5px solid ${C.gold}33`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:17,flexShrink:0 }}>{stop.emoji}</div>
