        <div style={{ width:42,height:42,borderRadius:12,background:`${C.gold}22`,border:`1.5px solid ${C.gold}55`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0 }}>✨</div>
